import * as React from "react"
import { Slider as SliderPrimitive } from "radix-ui"

import { cn } from "@/lib/internal"
import { sliderRangeVariants, sliderThumbVariants, sliderTrackVariants } from "./slider-variants"

export interface SliderProps extends Omit<
  React.ComponentPropsWithoutRef<typeof SliderPrimitive.Root>,
  "className"
> {
  className?: string
}

const Slider = React.forwardRef<React.ElementRef<typeof SliderPrimitive.Root>, SliderProps>(
  ({ className, ...props }, ref) => (
    <SliderPrimitive.Root
      ref={ref}
      data-slot="slider"
      className={cn("relative flex w-full touch-none select-none items-center", className)}
      {...props}
    >
      <SliderPrimitive.Track data-slot="slider-track" className={cn(sliderTrackVariants())}>
        <SliderPrimitive.Range data-slot="slider-range" className={cn(sliderRangeVariants())} />
      </SliderPrimitive.Track>
      {(props.defaultValue ?? props.value ?? [0]).map((_, i) => (
        <SliderPrimitive.Thumb
          key={i}
          data-slot="slider-thumb"
          className={cn(sliderThumbVariants())}
        />
      ))}
    </SliderPrimitive.Root>
  )
)

Slider.displayName = "Slider"

export { Slider }
