import * as React from "react"
import { Popover } from "radix-ui"
import { Calendar as CalendarIcon, CalendarClock, Clock } from "lucide-react"

import { cn } from "@/lib/internal"
import { inputVariants } from "./input-variants"
import { Calendar } from "./calendar"

export interface DatePickerProps {
  /** "date" shows calendar, "time" shows time columns, "datetime" shows both */
  mode?: "date" | "time" | "datetime"
  value?: Date | null
  defaultValue?: Date | null
  onValueChange?: (value: Date | null) => void
  placeholder?: string
  minDate?: Date
  maxDate?: Date
  disabledDates?: Date[] | ((date: Date) => boolean)
  disabled?: boolean
  size?: "xs" | "s" | "m" | "l" | "xl"
  variant?: "light" | "fill" | "dim" | "borderless"
  className?: string
}

const pad = (n: number) => String(n).padStart(2, "0")

const formatDate = (date: Date) =>
  `${pad(date.getDate())}/${pad(date.getMonth() + 1)}/${date.getFullYear()}`

const formatTime = (date: Date) => `${pad(date.getHours())}:${pad(date.getMinutes())}`

const normalizeDate = (d: Date) => new Date(d.getFullYear(), d.getMonth(), d.getDate())

const HOURS_LIST = Array.from({ length: 24 }, (_, i) => i)
const MINUTES_LIST = Array.from({ length: 12 }, (_, i) => i * 5)

interface TimeScrollColumnsProps {
  date: Date | null
  onHourChange: (hour: number) => void
  onMinuteChange: (minute: number) => void
}

const TimeScrollColumns = ({ date, onHourChange, onMinuteChange }: TimeScrollColumnsProps) => {
  const selectedHour = date?.getHours() ?? -1
  const selectedMinute = date?.getMinutes() ?? -1

  const hourColumnRef = React.useRef<HTMLDivElement>(null)
  const minuteColumnRef = React.useRef<HTMLDivElement>(null)

  React.useEffect(() => {
    const selectedElement =
      hourColumnRef.current?.querySelector<HTMLButtonElement>('[data-selected="true"]')
    selectedElement?.scrollIntoView({ block: "nearest", behavior: "instant" })
  }, [selectedHour])

  React.useEffect(() => {
    const selectedElement =
      minuteColumnRef.current?.querySelector<HTMLButtonElement>('[data-selected="true"]')
    selectedElement?.scrollIntoView({ block: "nearest", behavior: "instant" })
  }, [selectedMinute])

  return (
    <div className="flex h-[280px]">
      <div
        ref={hourColumnRef}
        className="flex w-14 flex-col gap-0.5 overflow-y-auto border-r border_secondary p-1"
      >
        {HOURS_LIST.map((hour) => {
          const isSelected = hour === selectedHour

          return (
            <button
              key={hour}
              type="button"
              data-selected={isSelected}
              onClick={() => onHourChange(hour)}
              className={cn(
                "h-8 w-full shrink-0 radius_6 text-center text-sm transition-colors cursor-pointer",
                isSelected
                  ? "bg_accent_secondary fg_on_accent_secondary font-medium"
                  : "text_secondary hover:state_bg_button_tertiary_soft"
              )}
            >
              {pad(hour)}
            </button>
          )
        })}
      </div>

      <div ref={minuteColumnRef} className="flex w-14 flex-col gap-0.5 overflow-y-auto p-1">
        {MINUTES_LIST.map((minute) => {
          const isSelected = minute === selectedMinute

          return (
            <button
              key={minute}
              type="button"
              data-selected={isSelected}
              onClick={() => onMinuteChange(minute)}
              className={cn(
                "h-8 w-full shrink-0 radius_6 text-center text-sm transition-colors cursor-pointer",
                isSelected
                  ? "bg_accent_secondary fg_on_accent_secondary font-medium"
                  : "text_secondary hover:state_bg_button_tertiary_soft"
              )}
            >
              {pad(minute)}
            </button>
          )
        })}
      </div>
    </div>
  )
}

const DatePicker = React.forwardRef<HTMLButtonElement, DatePickerProps>(
  (
    {
      mode = "date",
      value,
      defaultValue,
      onValueChange,
      placeholder,
      minDate,
      maxDate,
      disabledDates,
      disabled = false,
      size = "m",
      variant = "light",
      className,
    },
    ref
  ) => {
    const isControlled = value !== undefined
    const [internalValue, setInternalValue] = React.useState<Date | null>(defaultValue ?? null)
    const [open, setOpen] = React.useState(false)

    const currentValue = isControlled ? (value ?? null) : internalValue

    const setValue = React.useCallback(
      (next: Date | null) => {
        if (!isControlled) setInternalValue(next)
        onValueChange?.(next)
      },
      [isControlled, onValueChange]
    )

    const defaultPlaceholder =
      placeholder ??
      (mode === "date" ? "Select date" : mode === "time" ? "Select time" : "Select date & time")

    const displayText = currentValue
      ? mode === "date"
        ? formatDate(currentValue)
        : mode === "time"
          ? formatTime(currentValue)
          : `${formatDate(currentValue)} ${formatTime(currentValue)}`
      : null

    const handleHourChange = React.useCallback(
      (hour: number) => {
        const base = currentValue ? new Date(currentValue) : normalizeDate(new Date())
        base.setHours(hour)
        setValue(base)
      },
      [currentValue, setValue]
    )

    const handleMinuteChange = React.useCallback(
      (minute: number) => {
        const base = currentValue ? new Date(currentValue) : normalizeDate(new Date())
        base.setMinutes(minute)
        setValue(base)
      },
      [currentValue, setValue]
    )

    const handleDateSelect = React.useCallback(
      (date: Date) => {
        setValue(date)
        setOpen(false)
      },
      [setValue]
    )

    const handleDatetimeCalendarSelect = React.useCallback(
      (date: Date) => {
        const base = currentValue ? new Date(currentValue) : new Date(date)
        base.setFullYear(date.getFullYear(), date.getMonth(), date.getDate())
        setValue(base)
      },
      [currentValue, setValue]
    )

    const TriggerIcon = mode === "date" ? CalendarIcon : mode === "time" ? Clock : CalendarClock

    return (
      <Popover.Root open={open} onOpenChange={disabled ? undefined : setOpen}>
        <Popover.Trigger asChild>
          <button
            ref={ref}
            type="button"
            disabled={disabled}
            data-slot="date-picker-trigger"
            className={cn(
              inputVariants({ variant, size }),
              "flex items-center justify-between gap-2 cursor-pointer",
              !displayText && "text_tertiary",
              className
            )}
          >
            <span className="truncate">{displayText ?? defaultPlaceholder}</span>
            <TriggerIcon className="h-4 w-4 flex-shrink-0 icon_secondary" aria-hidden="true" />
          </button>
        </Popover.Trigger>

        <Popover.Portal>
          <Popover.Content
            align="start"
            sideOffset={8}
            onOpenAutoFocus={(e) => e.preventDefault()}
            className="z-50 bg_primary border border_secondary radius_8 shadow_md overflow-hidden"
          >
            {mode === "date" ? (
              <Calendar
                mode="single"
                value={currentValue ?? undefined}
                onValueChange={handleDateSelect}
                minDate={minDate}
                maxDate={maxDate}
                disabledDates={disabledDates}
              />
            ) : mode === "time" ? (
              <TimeScrollColumns
                date={currentValue}
                onHourChange={handleHourChange}
                onMinuteChange={handleMinuteChange}
              />
            ) : (
              <div className="flex">
                <Calendar
                  mode="single"
                  value={currentValue ?? undefined}
                  onValueChange={handleDatetimeCalendarSelect}
                  minDate={minDate}
                  maxDate={maxDate}
                  disabledDates={disabledDates}
                />
                <div className="border-l border_secondary">
                  <TimeScrollColumns
                    date={currentValue}
                    onHourChange={handleHourChange}
                    onMinuteChange={handleMinuteChange}
                  />
                </div>
              </div>
            )}
          </Popover.Content>
        </Popover.Portal>
      </Popover.Root>
    )
  }
)

DatePicker.displayName = "DatePicker"

export { DatePicker }
