import * as React from "react"

import { cn } from "@/lib/internal"
import { progressFillVariants, progressTrackVariants } from "./progress-variants"

export interface ProgressProps extends React.HTMLAttributes<HTMLDivElement> {
  value?: number
  max?: number
  indeterminate?: boolean
  size?: "sm" | "md" | "lg"
  variant?: "default" | "success" | "warning" | "error"
  showLabel?: boolean
  label?: string
}

const clamp = (value: number, min: number, max: number) => Math.min(Math.max(value, min), max)

const Progress = React.forwardRef<HTMLDivElement, ProgressProps>(
  (
    {
      className,
      value,
      max = 100,
      indeterminate = false,
      size = "md",
      variant = "default",
      showLabel = false,
      label,
      ...props
    },
    ref
  ) => {
    const safeMax = max <= 0 ? 100 : max
    const currentValue = indeterminate ? 0 : clamp(value ?? 0, 0, safeMax)
    const percentage = (currentValue / safeMax) * 100
    const resolvedLabel = label ?? `${Math.round(percentage)}%`

    return (
      <div
        ref={ref}
        data-slot="progress"
        className={cn("flex items-center gap-2", className)}
        {...props}
      >
        <div
          data-slot="progress-track"
          role="progressbar"
          aria-valuemin={0}
          aria-valuemax={safeMax}
          aria-valuenow={indeterminate ? undefined : currentValue}
          aria-label={showLabel ? resolvedLabel : "Progress"}
          className={cn(progressTrackVariants({ size }))}
        >
          <div
            data-slot="progress-fill"
            className={cn(progressFillVariants({ variant, indeterminate }))}
            style={indeterminate ? undefined : { width: `${percentage}%` }}
          />
        </div>
        {showLabel ? <span className="text-sm text_secondary">{resolvedLabel}</span> : null}
      </div>
    )
  }
)

Progress.displayName = "Progress"

export { Progress }
