import * as React from "react"
import { Dialog } from "radix-ui"

import { cn } from "@/lib/internal"
import { Button } from "./button"
import { modalVariants } from "./modal-variants"

export interface ModalProps {
  open?: boolean
  onOpenChange?: (open: boolean) => void
  trigger?: React.ReactNode
  title?: string
  description?: string
  children: React.ReactNode
  footer?: React.ReactNode
  size?: "sm" | "md" | "lg" | "xl" | "2xl" | "full"
  showCloseButton?: boolean
  closeOnOverlayClick?: boolean
  "aria-label"?: string
  className?: string
  bodyClassName?: string
  variant?: "default" | "spotlight"
}

const Modal = ({
  open,
  onOpenChange,
  trigger,
  title,
  description,
  children,
  footer,
  size = "md",
  showCloseButton = true,
  closeOnOverlayClick = true,
  "aria-label": ariaLabel,
  className,
  bodyClassName,
  variant = "default",
}: ModalProps) => {
  React.useEffect(() => {
    if (import.meta.env.DEV && !title && !ariaLabel) {
      console.warn("[ui-kit/Modal] Provide a title or aria-label for accessible dialogs.")
    }
  }, [title, ariaLabel])

  return (
    <Dialog.Root data-slot="modal" open={open} onOpenChange={onOpenChange}>
      {trigger ? <Dialog.Trigger asChild>{trigger}</Dialog.Trigger> : null}
      <Dialog.Portal>
        {variant !== "spotlight" && (
          <Dialog.Overlay data-slot="modal-overlay" className="fixed inset-0 z-50 bg_backdrop" />
        )}
        <Dialog.Content
          data-slot="modal-content"
          data-size={size}
          aria-label={ariaLabel}
          className={cn(modalVariants({ variant, size }), className)}
          onPointerDownOutside={(event) => {
            if (!closeOnOverlayClick) {
              event.preventDefault()
            }
          }}
        >
          {title || description || showCloseButton ? (
            <div className="mb-4 flex items-start justify-between gap-4">
              <div className="flex flex-col gap-1">
                <Dialog.Title
                  className={cn("text-base font-semibold text_primary", !title && "sr-only")}
                >
                  {title ?? "Modal"}
                </Dialog.Title>
                <Dialog.Description
                  className={cn("text-sm text_secondary", !description && "sr-only")}
                >
                  {description ?? "Dialog content"}
                </Dialog.Description>
              </div>
              {showCloseButton ? (
                <Dialog.Close asChild>
                  <Button type="button" variant="subtle" size="icon-s" aria-label="Close modal">
                    <svg
                      viewBox="0 0 16 16"
                      fill="none"
                      xmlns="http://www.w3.org/2000/svg"
                      aria-hidden="true"
                      className="h-4 w-4"
                    >
                      <path
                        d="M4 4L12 12M12 4L4 12"
                        stroke="currentColor"
                        strokeWidth="1.5"
                        strokeLinecap="round"
                      />
                    </svg>
                  </Button>
                </Dialog.Close>
              ) : null}
            </div>
          ) : (
            <div className="sr-only">
              <Dialog.Title>Modal</Dialog.Title>
              <Dialog.Description>Dialog content</Dialog.Description>
            </div>
          )}
          <div className={cn("text_primary", bodyClassName)}>{children}</div>
          {footer ? <div className="mt-4 flex items-center justify-end gap-2">{footer}</div> : null}
        </Dialog.Content>
      </Dialog.Portal>
    </Dialog.Root>
  )
}

Modal.displayName = "Modal"

const ModalTrigger = Dialog.Trigger
ModalTrigger.displayName = "ModalTrigger"

export { Modal, ModalTrigger }
