import * as React from "react"

import { cn } from "@/lib/internal"

type FieldControlProps = {
  id?: string
  disabled?: boolean
  required?: boolean
  "aria-describedby"?: string
  "aria-invalid"?: boolean | "true" | "false"
}

export interface FieldProps extends Omit<React.ComponentProps<"div">, "children"> {
  label?: React.ReactNode
  required?: boolean
  supportingText?: React.ReactNode
  error?: string
  disabled?: boolean
  htmlFor?: string
  children: React.ReactElement<FieldControlProps>
}

const mergeDescribedBy = (current: string | undefined, next: string | undefined) =>
  [current, next].filter(Boolean).join(" ") || undefined

const Field = React.forwardRef<HTMLDivElement, FieldProps>(
  (
    {
      className,
      label,
      required = false,
      supportingText,
      error,
      disabled = false,
      htmlFor,
      children,
      ...props
    },
    ref
  ) => {
    const generatedId = React.useId()
    const controlId = htmlFor ?? children.props.id ?? `${generatedId}-control`
    const messageId = error || supportingText ? `${generatedId}-message` : undefined
    const describedBy = mergeDescribedBy(children.props["aria-describedby"], messageId)

    const control = React.cloneElement(children, {
      id: controlId,
      disabled: disabled || children.props.disabled,
      required: required || children.props.required,
      "aria-describedby": describedBy,
      "aria-invalid": error ? true : children.props["aria-invalid"],
    })

    const focusControl = () => {
      document.getElementById(controlId)?.focus()
    }

    return (
      <div
        ref={ref}
        data-slot="field"
        data-disabled={disabled || undefined}
        data-invalid={error ? true : undefined}
        className={cn("flex w-full flex-col gap-1", className)}
        {...props}
      >
        {label ? (
          <label htmlFor={controlId} onClick={focusControl} className="text-sm text_primary">
            {label}
            {required ? (
              <span aria-hidden="true" className="fg_error">
                {" "}
                *
              </span>
            ) : null}
          </label>
        ) : null}
        {control}
        {error || supportingText ? (
          <p
            id={messageId}
            role={error ? "alert" : undefined}
            className={cn("text-sm", error ? "fg_error" : "text_tertiary")}
          >
            {error ?? supportingText}
          </p>
        ) : null}
      </div>
    )
  }
)

Field.displayName = "Field"

export { Field }
