import * as React from "react"
import {
  type Column,
  type ColumnDef,
  type ColumnPinningState,
  type ExpandedState,
  type RowSelectionState,
  type SortingState,
} from "@tanstack/react-table"
import { ChevronRight } from "lucide-react"

import { cn } from "@/lib/internal"
import { DataTableFilterDropdown } from "./data-table-filter"
import { SortIcon } from "./table-sort-icon"
import type {
  DataTableCellMeta,
  DataTableColumnDef,
  DataTableColumnMeta,
  DataTableProps,
  DataTableSortValue,
} from "./data-table-types"

export function toSortValue(sorting: SortingState): DataTableSortValue | null {
  const firstSort = sorting[0]
  if (!firstSort) {
    return null
  }

  return {
    key: firstSort.id,
    direction: firstSort.desc ? "desc" : "asc",
  }
}

export function toCssSize(value: number | string | undefined): number | string | undefined {
  if (typeof value === "number") {
    return `${value}px`
  }

  return value
}

export function toRowSelectionState(keys: string[] | undefined): RowSelectionState {
  const next: RowSelectionState = {}

  if (!keys?.length) {
    return next
  }

  for (const key of keys) {
    next[key] = true
  }

  return next
}

export function toExpandedState(keys: string[] | undefined): ExpandedState {
  if (!keys?.length) {
    return {}
  }

  return Object.fromEntries(keys.map((key) => [key, true]))
}

export function toExpandedKeys(expanded: ExpandedState, allRowIds: string[]): string[] {
  if (expanded === true) {
    return allRowIds
  }

  return Object.keys(expanded).filter((key) => expanded[key])
}

export function resolveRowId<T extends object>(
  row: T,
  index: number,
  parentId: string | undefined,
  getRowKey: DataTableProps<T>["getRowKey"]
): string {
  if (getRowKey) {
    return getRowKey(row, index)
  }

  if (parentId) {
    return `${parentId}.${index}`
  }

  return String(index)
}

export function buildRowLookup<T extends object>(
  rows: T[],
  getRowKey: DataTableProps<T>["getRowKey"],
  getSubRows: DataTableProps<T>["getSubRows"]
): Map<string, T> {
  const rowLookup = new Map<string, T>()

  const walk = (items: T[], parentId: string | undefined) => {
    for (let index = 0; index < items.length; index += 1) {
      const item = items[index]!
      const rowId = resolveRowId(item, index, parentId, getRowKey)
      rowLookup.set(rowId, item)

      if (!getSubRows) {
        continue
      }

      const children = getSubRows(item)
      if (!children?.length) {
        continue
      }

      walk(children, rowId)
    }
  }

  walk(rows, undefined)
  return rowLookup
}

export function renderHeaderContent<T>(
  header: DataTableColumnDef<T>["header"],
  column: Column<T, unknown>
): React.ReactNode {
  if (typeof header === "function") {
    return header({ column })
  }

  return header
}

export function getPinnedState(pinned: false | "left" | "right") {
  if (pinned === "left") {
    return "left" as const
  }

  if (pinned === "right") {
    return "right" as const
  }

  return false
}

export function collectColumnPinning<T>(columnDefs: DataTableColumnDef<T>[]): ColumnPinningState {
  const pinning: ColumnPinningState = {
    left: [],
    right: [],
  }

  const walk = (defs: DataTableColumnDef<T>[]) => {
    for (const columnDef of defs) {
      if (columnDef.columns?.length) {
        walk(columnDef.columns)
        continue
      }

      if (columnDef.pin === "left") {
        ;(pinning.left ??= []).push(columnDef.id)
      }

      if (columnDef.pin === "right") {
        ;(pinning.right ??= []).push(columnDef.id)
      }
    }
  }

  walk(columnDefs)
  return pinning
}

export function hasResizableColumn<T>(defs: DataTableColumnDef<T>[]): boolean {
  return defs.some((def) => {
    if (def.resizable === true) return true
    if (def.columns?.length) return hasResizableColumn(def.columns)
    return false
  })
}

export function toTanStackColumns<T extends object>(
  columnDefs: DataTableColumnDef<T>[]
): ColumnDef<T>[] {
  return columnDefs.map((columnDef): ColumnDef<T> => {
    if (columnDef.columns?.length) {
      return {
        id: columnDef.id,
        header: ({ column }) => renderHeaderContent(columnDef.header, column),
        columns: toTanStackColumns(columnDef.columns),
        meta: {
          align: "center",
          groupBorder: columnDef.groupBorder,
        } satisfies DataTableColumnMeta,
      }
    }

    const accessorKey = columnDef.accessorKey

    return {
      id: columnDef.id,
      accessorFn: accessorKey ? (row: T) => row[accessorKey] : undefined,
      size: columnDef.width,
      minSize: columnDef.minWidth,
      maxSize: columnDef.maxWidth,
      enableSorting: columnDef.sortable ?? false,
      enableColumnFilter: columnDef.filterable ?? false,
      enableResizing: columnDef.resizable ?? false,
      filterFn: (row, columnId, filterValue) => {
        const rawCellValue = row.getValue(columnId)

        if (columnDef.filterType === "select") {
          const selectedValues = Array.isArray(filterValue)
            ? filterValue.filter((valueItem): valueItem is string => typeof valueItem === "string")
            : []

          if (selectedValues.length === 0) {
            return true
          }

          return selectedValues.includes(String(rawCellValue ?? ""))
        }

        const textValue = typeof filterValue === "string" ? filterValue.trim().toLowerCase() : ""
        if (!textValue) {
          return true
        }

        return String(rawCellValue ?? "")
          .toLowerCase()
          .includes(textValue)
      },
      header: ({ column }) => {
        const headerContent = renderHeaderContent(columnDef.header, column)
        const canSort = columnDef.sortable ?? false
        const canFilter = columnDef.filterable ?? false

        const headerButton = canSort ? (
          <button
            type="button"
            onClick={column.getToggleSortingHandler()}
            className="inline-flex cursor-pointer items-center gap-1"
          >
            <span>{headerContent}</span>
            <SortIcon state={column.getIsSorted()} className="shrink-0" />
          </button>
        ) : (
          <span>{headerContent}</span>
        )

        if (!canFilter) {
          return headerButton
        }

        return (
          <div className="inline-flex items-center gap-2">
            {headerButton}
            <DataTableFilterDropdown
              columnId={column.id}
              filterType={columnDef.filterType}
              options={columnDef.filters}
              value={column.getFilterValue()}
              onApply={(nextFilterValue) => {
                if (
                  (typeof nextFilterValue === "string" && nextFilterValue.length === 0) ||
                  (Array.isArray(nextFilterValue) && nextFilterValue.length === 0)
                ) {
                  column.setFilterValue(undefined)
                  return
                }

                column.setFilterValue(nextFilterValue)
              }}
              onReset={() => {
                column.setFilterValue(undefined)
              }}
            />
          </div>
        )
      },
      cell: ({ row }) => {
        const value = accessorKey
          ? (row.original[accessorKey] as unknown)
          : row.getValue(columnDef.id)

        const cellMeta: DataTableCellMeta<T> = {
          value,
          row: row.original,
          depth: row.depth,
          isExpanded: row.getIsExpanded(),
          canExpand: row.getCanExpand(),
          toggleExpand: () => {
            row.toggleExpanded()
          },
          rowIndex: row.index,
        }

        const content = columnDef.cell
          ? columnDef.cell(row.original, cellMeta)
          : (value as React.ReactNode)

        if (!columnDef.expandTrigger) {
          return content
        }

        return (
          <div className="flex items-center gap-1.5" style={{ paddingLeft: `${row.depth * 20}px` }}>
            {row.getCanExpand() ? (
              <button
                type="button"
                className="inline-flex h-5 w-5 cursor-pointer items-center justify-center rounded-sm hover:bg_secondary"
                aria-label={row.getIsExpanded() ? "Collapse row" : "Expand row"}
                onClick={row.getToggleExpandedHandler()}
              >
                <ChevronRight
                  className={cn(
                    "h-3.5 w-3.5 icon_tertiary transition-transform duration-150",
                    row.getIsExpanded() && "rotate-90"
                  )}
                />
              </button>
            ) : (
              <span aria-hidden="true" className="inline-block h-5 w-5" />
            )}
            <span>{content}</span>
          </div>
        )
      },
      meta: {
        align: columnDef.align ?? "left",
        width: columnDef.width,
        minWidth: columnDef.minWidth,
        maxWidth: columnDef.maxWidth,
        pin: columnDef.pin,
        groupBorder: columnDef.groupBorder,
        resizable: columnDef.resizable,
      } satisfies DataTableColumnMeta,
    }
  })
}
