import * as React from "react"
import { Trash2, Upload, FileText } from "lucide-react"

import { cn } from "@/lib/internal"

export interface FileEntry {
  id: string
  name: string
  /** File size in bytes */
  size: number
  /** Upload progress 0-100; omit or set to 100 when complete */
  progress?: number
  status?: "uploading" | "error" | "done"
  /** Preview URL (data URL or object URL); auto-set for images when using internal state */
  preview?: string
  /** Error message shown when status="error" */
  error?: string
}

export interface FileUploadProps {
  /** Accepted MIME types e.g. "image/*" or ".pdf,.docx" */
  accept?: string
  multiple?: boolean
  /** Max file size in bytes */
  maxSize?: number
  /** Max number of files (only applied in uncontrolled mode) */
  maxFiles?: number
  /** Controlled file list */
  files?: FileEntry[]
  /** Fires when files list changes (uncontrolled mode) */
  onFilesChange?: (files: FileEntry[]) => void
  /** Fires when new valid File objects are added — use this to start uploads */
  onFileAdd?: (files: File[]) => void
  /** Fires when a file is removed */
  onFileRemove?: (id: string) => void
  /** Drop zone heading text */
  placeholder?: string
  /** Drop zone sub-text */
  description?: string
  disabled?: boolean
  className?: string
}

const formatSize = (bytes: number): string => {
  if (bytes < 1024) return `${bytes} B`
  if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(0)} KB`
  return `${(bytes / (1024 * 1024)).toFixed(1)} MB`
}

const acceptsFile = (file: File, accept?: string): boolean => {
  const acceptList = accept
    ?.split(",")
    .map((item) => item.trim().toLowerCase())
    .filter(Boolean)

  if (!acceptList?.length) {
    return true
  }

  const fileName = file.name.toLowerCase()
  const fileType = file.type.toLowerCase()

  return acceptList.some((acceptedType) => {
    if (acceptedType.startsWith(".")) {
      return fileName.endsWith(acceptedType)
    }

    if (acceptedType.endsWith("/*")) {
      return fileType.startsWith(acceptedType.slice(0, -1))
    }

    return fileType === acceptedType
  })
}

const FileUpload = React.forwardRef<HTMLDivElement, FileUploadProps>(
  (
    {
      accept,
      multiple = false,
      maxSize,
      maxFiles,
      files: controlledFiles,
      onFilesChange,
      onFileAdd,
      onFileRemove,
      placeholder = "Upload a file",
      description,
      disabled = false,
      className,
    },
    ref
  ) => {
    const isControlled = controlledFiles !== undefined
    const [internalFiles, setInternalFiles] = React.useState<FileEntry[]>([])
    const [isDragging, setIsDragging] = React.useState(false)
    const inputRef = React.useRef<HTMLInputElement>(null)
    const createdObjectUrlsRef = React.useRef<Set<string>>(new Set())

    React.useEffect(() => {
      const urls = createdObjectUrlsRef.current
      return () => {
        urls.forEach((url) => URL.revokeObjectURL(url))
        urls.clear()
      }
    }, [])

    const prevFilesRef = React.useRef<FileEntry[]>([])

    React.useEffect(() => {
      const currentFiles = controlledFiles ?? internalFiles
      const currentPreviews = new Set(currentFiles.map((f) => f.preview).filter(Boolean))
      for (const prev of prevFilesRef.current) {
        if (
          prev.preview &&
          !currentPreviews.has(prev.preview) &&
          createdObjectUrlsRef.current.has(prev.preview)
        ) {
          URL.revokeObjectURL(prev.preview)
          createdObjectUrlsRef.current.delete(prev.preview)
        }
      }
      prevFilesRef.current = currentFiles
    }, [controlledFiles, internalFiles])

    const files = isControlled ? controlledFiles : internalFiles
    const filesRef = React.useRef(files)
    React.useLayoutEffect(() => {
      filesRef.current = files
    }, [files])

    const updateFiles = React.useCallback(
      (next: FileEntry[]) => {
        filesRef.current = next
        if (!isControlled) setInternalFiles(next)
        onFilesChange?.(next)
      },
      [isControlled, onFilesChange]
    )

    const addFiles = React.useCallback(
      (rawFiles: FileList | File[]) => {
        if (disabled) return
        const fileArray = Array.from(rawFiles)
        const valid: File[] = []
        const errors: FileEntry[] = []

        for (const file of fileArray) {
          if (!acceptsFile(file, accept)) {
            errors.push({
              id: crypto.randomUUID(),
              name: file.name,
              size: file.size,
              status: "error",
              error: "File type is not accepted",
            })
            continue
          }

          if (maxSize && file.size > maxSize) {
            errors.push({
              id: crypto.randomUUID(),
              name: file.name,
              size: file.size,
              status: "error",
              error: `File exceeds ${formatSize(maxSize)} limit`,
            })
            continue
          }

          valid.push(file)
        }

        const previousFiles = filesRef.current
        const activeFileCount = previousFiles.filter((file) => file.status !== "error").length
        const availableFiles =
          !isControlled && maxFiles !== undefined ? Math.max(0, maxFiles - activeFileCount) : valid.length
        const filesToAdd = valid.slice(0, availableFiles)
        const truncatedCount = valid.length - filesToAdd.length
        const entries: FileEntry[] = []

        for (const file of filesToAdd) {
          const isImage = file.type.startsWith("image/")
          const preview = isImage ? URL.createObjectURL(file) : undefined
          if (preview) createdObjectUrlsRef.current.add(preview)
          const entry: FileEntry = {
            id: crypto.randomUUID(),
            name: file.name,
            size: file.size,
            status: "uploading",
            progress: 0,
            preview,
          }

          entries.push(entry)
        }

        if (truncatedCount > 0) {
          errors.push({
            id: crypto.randomUUID(),
            name: `${truncatedCount} file${truncatedCount === 1 ? "" : "s"} not added`,
            size: 0,
            status: "error",
            error: `Maximum ${maxFiles} file${maxFiles === 1 ? "" : "s"} allowed`,
          })
        }

        const nextFiles = [...previousFiles, ...entries, ...errors]
        filesRef.current = nextFiles
        if (!isControlled) {
          setInternalFiles(nextFiles)
        }
        onFilesChange?.(nextFiles)
        if (filesToAdd.length > 0) onFileAdd?.(filesToAdd)
      },
      [accept, disabled, isControlled, maxFiles, maxSize, onFileAdd, onFilesChange]
    )

    const removeFile = React.useCallback(
      (id: string) => {
        const entry = files.find((f) => f.id === id)
        if (entry?.preview && createdObjectUrlsRef.current.has(entry.preview)) {
          URL.revokeObjectURL(entry.preview)
          createdObjectUrlsRef.current.delete(entry.preview)
        }
        updateFiles(files.filter((f) => f.id !== id))
        onFileRemove?.(id)
      },
      [files, updateFiles, onFileRemove]
    )

    const handleDrop = React.useCallback(
      (e: React.DragEvent<HTMLDivElement>) => {
        e.preventDefault()
        setIsDragging(false)
        if (disabled) return
        addFiles(e.dataTransfer.files)
      },
      [addFiles, disabled]
    )

    const handleDragOver = (e: React.DragEvent<HTMLDivElement>) => {
      e.preventDefault()
      if (!disabled) setIsDragging(true)
    }

    const handleDragLeave = () => setIsDragging(false)

    const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
      if (e.target.files) addFiles(e.target.files)
      e.target.value = ""
    }

    const handleZoneClick = () => {
      if (!disabled) inputRef.current?.click()
    }

    return (
      <div ref={ref} data-slot="file-upload" className={cn("flex flex-col gap-3", className)}>
        {/* Drop zone */}
        <div
          role="button"
          tabIndex={disabled ? -1 : 0}
          aria-label="Upload area"
          onClick={handleZoneClick}
          onKeyDown={(e) => {
            if (e.key === "Enter" || e.key === " ") {
              e.preventDefault()
              handleZoneClick()
            }
          }}
          onDrop={handleDrop}
          onDragOver={handleDragOver}
          onDragLeave={handleDragLeave}
          className={cn(
            "flex flex-col items-center justify-center gap-2 p-8 border-2 border-dashed radius_8 transition-colors cursor-pointer select-none",
            isDragging
              ? "border_accent_primary bg_accent_primary/5"
              : "border_secondary hover:state_border_accent_primary_soft bg_secondary",
            disabled && "pointer-events-none opacity-60"
          )}
        >
          <div className="flex h-10 w-10 items-center justify-center radius_round bg_primary border border_secondary">
            <Upload className="h-5 w-5 icon_secondary" aria-hidden="true" />
          </div>
          <div className="text-center">
            <p className="text-sm font-medium text_primary">{placeholder}</p>
            {description ? <p className="text-xs text_tertiary mt-0.5">{description}</p> : null}
          </div>
        </div>

        <input
          ref={inputRef}
          type="file"
          accept={accept}
          multiple={multiple}
          className="sr-only"
          onChange={handleInputChange}
          aria-hidden="true"
          tabIndex={-1}
        />

        {/* File list */}
        {files.length > 0 ? (
          <div className="flex flex-col gap-2">
            {files.map((entry) => (
              <div
                key={entry.id}
                data-slot="file-upload-item"
                className="flex items-center gap-3 p-3 border border_secondary radius_8 bg_primary"
              >
                {/* Thumbnail or file icon */}
                <div className="h-10 w-10 flex-shrink-0 radius_6 overflow-hidden bg_secondary flex items-center justify-center">
                  {entry.preview ? (
                    <img
                      src={entry.preview}
                      alt={entry.name}
                      className="h-full w-full object-cover"
                    />
                  ) : (
                    <FileText className="h-5 w-5 icon_tertiary" aria-hidden="true" />
                  )}
                </div>

                {/* Name, size, progress */}
                <div className="flex-1 min-w-0">
                  <div className="flex items-center justify-between gap-2">
                    <p className="text-sm font-medium text_primary truncate">{entry.name}</p>
                    <p className="text-xs text_tertiary flex-shrink-0">{formatSize(entry.size)}</p>
                  </div>

                  {entry.status === "error" ? (
                    <p role="alert" className="text-xs fg_error mt-0.5">
                      {entry.error ?? "Upload failed"}
                    </p>
                  ) : entry.progress !== undefined && entry.progress < 100 ? (
                    <div className="mt-1.5 flex items-center gap-2">
                      <div
                        role="progressbar"
                        aria-valuenow={entry.progress}
                        aria-valuemin={0}
                        aria-valuemax={100}
                        aria-label={`Upload progress for ${entry.name}`}
                        className="flex-1 h-1.5 bg_secondary radius_round overflow-hidden"
                      >
                        <div
                          className="h-full bg_accent_primary radius_round transition-all duration-300"
                          style={{ width: `${entry.progress}%` }}
                        />
                      </div>
                      <span className="text-xs text_tertiary flex-shrink-0">{entry.progress}%</span>
                    </div>
                  ) : null}
                </div>

                {/* Remove button */}
                <button
                  type="button"
                  aria-label={`Remove ${entry.name}`}
                  onClick={() => removeFile(entry.id)}
                  className="flex-shrink-0 flex h-7 w-7 items-center justify-center radius_6 transition-colors hover:state_bg_button_tertiary_subtle text_tertiary hover:text_primary"
                >
                  <Trash2 className="h-4 w-4" aria-hidden="true" />
                </button>
              </div>
            ))}
          </div>
        ) : null}
      </div>
    )
  }
)

FileUpload.displayName = "FileUpload"

export { FileUpload }
