import * as React from "react"
import { type VariantProps } from "class-variance-authority"

import { cn } from "@/lib/internal"
import { inputVariants } from "./input-variants"

export type InputVariant = "light" | "fill" | "dim" | "borderless"

export interface InputProps
  extends Omit<React.ComponentProps<"input">, "size">, VariantProps<typeof inputVariants> {
  leftIcon?: React.ReactNode
  rightIcon?: React.ReactNode
  unit?: React.ReactNode
}

const isAriaInvalid = (value: InputProps["aria-invalid"]) => value === true || value === "true"

const Input = React.forwardRef<HTMLInputElement, InputProps>(
  (
    {
      className,
      variant = "light",
      size = "m",
      validation,
      type = "text",
      placeholder,
      leftIcon,
      rightIcon,
      unit,
      "aria-invalid": ariaInvalid,
      disabled,
      ...props
    },
    ref
  ) => {
    const resolvedValidation = isAriaInvalid(ariaInvalid) ? "error" : validation
    const inputClassName = cn(
      inputVariants({ variant, size, validation: resolvedValidation }),
      className
    )

    if (!leftIcon && !rightIcon && !unit) {
      return (
        <input
          ref={ref}
          data-slot="input"
          data-variant={variant}
          data-size={size}
          type={type}
          placeholder={placeholder}
          aria-invalid={validation === "error" ? true : ariaInvalid}
          disabled={disabled}
          className={inputClassName}
          {...props}
        />
      )
    }

    return (
      <div
        data-slot="input"
        data-variant={variant}
        data-size={size}
        data-disabled={disabled || undefined}
        className={cn(
          inputClassName,
          "flex items-center gap-2 focus-within:border-[var(--ds-border-accent-secondary-contrast)]",
          disabled && "pointer-events-none opacity-60"
        )}
      >
        {leftIcon ? (
          <span className="inline-flex h-4 w-4 shrink-0 items-center justify-center icon_secondary">
            {leftIcon}
          </span>
        ) : null}
        <input
          ref={ref}
          type={type}
          placeholder={placeholder}
          aria-invalid={validation === "error" ? true : ariaInvalid}
          disabled={disabled}
          className="min-w-0 flex-1 bg-transparent p-0 text_primary placeholder:text_tertiary outline-none"
          {...props}
        />
        {unit ? <span className="shrink-0 text_tertiary">{unit}</span> : null}
        {rightIcon ? (
          <span className="inline-flex h-4 w-4 shrink-0 items-center justify-center icon_secondary">
            {rightIcon}
          </span>
        ) : null}
      </div>
    )
  }
)

Input.displayName = "Input"

export { Input }
