import * as React from "react"
import { ChevronDown } from "lucide-react"

import { cn } from "@/lib/internal"
import { Button, type ButtonProps } from "./button"
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuTrigger,
} from "./dropdown-menu"

export type DropdownButtonVariant =
  | "primary1"
  | "primary2"
  | "secondary1"
  | "secondary2"
  | "outline"
  | "border"

const dropdownButtonVariantMap: Record<DropdownButtonVariant, ButtonProps["variant"]> = {
  primary1: "primary",
  primary2: "primary2",
  secondary1: "secondary",
  secondary2: "secondary2",
  outline: "border",
  border: "border",
}

const dropdownButtonClassNameMap: Partial<Record<DropdownButtonVariant, string>> = {
  outline:
    "border_accent_secondary fg_accent_secondary hover:state_bg_accent_secondary_subtle_subtle active:state_bg_accent_secondary_subtle_soft",
}

export interface DropdownButtonProps
  extends Omit<React.ComponentPropsWithoutRef<typeof DropdownMenu>, "children"> {
  label: React.ReactNode
  children: React.ReactNode
  variant?: DropdownButtonVariant
  size?: ButtonProps["size"]
  disabled?: boolean
  className?: string
  contentClassName?: string
  side?: "top" | "right" | "bottom" | "left"
  align?: "start" | "center" | "end"
  sideOffset?: number
}

const DropdownButton = React.forwardRef<HTMLButtonElement, DropdownButtonProps>(
  (
    {
      label,
      children,
      variant = "primary1",
      size = "m",
      disabled,
      className,
      contentClassName,
      side,
      align,
      sideOffset,
      open: openProp,
      onOpenChange,
      ...props
    },
    ref
  ) => {
    const [uncontrolledOpen, setUncontrolledOpen] = React.useState(false)
    const open = openProp ?? uncontrolledOpen

    const handleOpenChange = React.useCallback(
      (nextOpen: boolean) => {
        setUncontrolledOpen(nextOpen)
        onOpenChange?.(nextOpen)
      },
      [onOpenChange]
    )

    return (
      <DropdownMenu open={open} onOpenChange={handleOpenChange} {...props}>
        <DropdownMenuTrigger asChild disabled={disabled}>
          <Button
            ref={ref}
            variant={dropdownButtonVariantMap[variant]}
            size={size}
            disabled={disabled}
            data-dropdown-button-variant={variant}
            className={cn(dropdownButtonClassNameMap[variant], className)}
          >
            {label}
            <ChevronDown
              aria-hidden="true"
              className={cn("h-4 w-4 shrink-0 transition-transform duration-0", open && "rotate-180")}
            />
          </Button>
        </DropdownMenuTrigger>
        <DropdownMenuContent
          side={side}
          align={align}
          sideOffset={sideOffset}
          className={contentClassName}
        >
          {children}
        </DropdownMenuContent>
      </DropdownMenu>
    )
  }
)

DropdownButton.displayName = "DropdownButton"

export { DropdownButton }
