import * as React from "react"

type DarkModeOptions = {
  defaultValue?: boolean
  storageKey?: string
}

export function useDarkMode(options: DarkModeOptions = {}) {
  const { storageKey = "ui-kit-dark-mode", defaultValue } = options

  const [isDark, setIsDark] = React.useState<boolean>(() => {
    if (typeof window === "undefined") return defaultValue ?? false
    const stored = localStorage.getItem(storageKey)
    if (stored !== null) return stored === "true"
    if (defaultValue !== undefined) return defaultValue
    return window.matchMedia("(prefers-color-scheme: dark)").matches
  })

  React.useEffect(() => {
    const root = document.documentElement
    root.classList.remove(
      "theme-high-contrast-light",
      "theme-olive",
      "theme-deep-forest",
      "theme-sunset"
    )
    root.classList.toggle("dark", isDark)
    root.dataset.theme = isDark ? "dark" : "light"
    localStorage.setItem(storageKey, String(isDark))
  }, [isDark, storageKey])

  React.useEffect(() => {
    const mq = window.matchMedia("(prefers-color-scheme: dark)")
    const handler = (e: MediaQueryListEvent) => {
      const stored = localStorage.getItem(storageKey)
      if (stored === null) setIsDark(e.matches)
    }
    mq.addEventListener("change", handler)
    return () => mq.removeEventListener("change", handler)
  }, [storageKey])

  const toggle = React.useCallback(() => setIsDark((value) => !value), [])

  return { isDark, setIsDark, toggle }
}
