import * as React from "react"
import { AlertTriangle, CheckCircle, Info, X, XCircle } from "lucide-react"

import { cn } from "@/lib/internal"
import { alertIconVariants, alertVariants } from "./alert-variants"

export interface AlertProps extends React.HTMLAttributes<HTMLDivElement> {
  variant?: "default" | "success" | "warning" | "error" | "info"
  title?: string
  description?: string
  icon?: React.ReactNode
  onClose?: () => void
  action?: React.ReactNode
}

const defaultIconMap = {
  default: Info,
  success: CheckCircle,
  warning: AlertTriangle,
  error: XCircle,
  info: Info,
} as const

const Alert = React.forwardRef<HTMLDivElement, AlertProps>(
  (
    {
      className,
      variant = "default",
      title,
      description,
      icon,
      onClose,
      action,
      children,
      ...props
    },
    ref
  ) => {
    const Icon = defaultIconMap[variant]
    const resolvedIcon = icon ?? (
      <Icon aria-hidden="true" className={cn(alertIconVariants({ variant }))} />
    )

    return (
      <div
        ref={ref}
        role="status"
        data-slot="alert"
        data-variant={variant}
        className={cn(alertVariants({ variant }), className)}
        {...props}
      >
        <div data-slot="alert-icon" className="pt-0.5">
          {resolvedIcon}
        </div>
        <div className="flex flex-1 flex-col gap-1">
          {title ? <div className="font-semibold text-sm">{title}</div> : null}
          {description ? (
            <p className={cn("text-sm", variant === "default" ? "text_secondary" : "text-current")}>
              {description}
            </p>
          ) : null}
          {children}
          {action ? <div className="mt-2">{action}</div> : null}
        </div>
        {onClose ? (
          <button
            type="button"
            onClick={onClose}
            aria-label="Close alert"
            className="inline-flex h-6 w-6 items-center justify-center radius_4 text_secondary hover:state_bg_button_tertiary_soft"
          >
            <X className="h-4 w-4" aria-hidden="true" />
          </button>
        ) : null}
      </div>
    )
  }
)

Alert.displayName = "Alert"

export { Alert }
