import * as React from "react"
import { ScrollArea as ScrollAreaPrimitive } from "radix-ui"

import { cn } from "@/lib/internal"
import {
  scrollAreaRootVariants,
  scrollAreaScrollbarVariants,
  scrollAreaThumbVariants,
} from "./scroll-area-variants"

export interface ScrollAreaProps extends React.ComponentPropsWithoutRef<
  typeof ScrollAreaPrimitive.Root
> {
  orientation?: "vertical" | "horizontal" | "both"
  viewportClassName?: string
}

const ScrollArea = React.forwardRef<
  React.ElementRef<typeof ScrollAreaPrimitive.Root>,
  ScrollAreaProps
>(({ className, children, orientation = "vertical", viewportClassName, ...props }, ref) => (
  <ScrollAreaPrimitive.Root
    ref={ref}
    data-slot="scroll-area"
    className={cn(scrollAreaRootVariants(), className)}
    {...props}
  >
    <ScrollAreaPrimitive.Viewport
      data-slot="scroll-area-viewport"
      className={cn("h-full w-full rounded-[inherit]", viewportClassName)}
    >
      {children}
    </ScrollAreaPrimitive.Viewport>
    {(orientation === "vertical" || orientation === "both") && (
      <ScrollAreaPrimitive.Scrollbar
        orientation="vertical"
        className={scrollAreaScrollbarVariants({ orientation: "vertical" })}
      >
        <ScrollAreaPrimitive.Thumb className={scrollAreaThumbVariants()} />
      </ScrollAreaPrimitive.Scrollbar>
    )}
    {(orientation === "horizontal" || orientation === "both") && (
      <ScrollAreaPrimitive.Scrollbar
        orientation="horizontal"
        className={scrollAreaScrollbarVariants({ orientation: "horizontal" })}
      >
        <ScrollAreaPrimitive.Thumb className={scrollAreaThumbVariants()} />
      </ScrollAreaPrimitive.Scrollbar>
    )}
    <ScrollAreaPrimitive.Corner />
  </ScrollAreaPrimitive.Root>
))

ScrollArea.displayName = "ScrollArea"

export { ScrollArea }
