import * as React from "react"

import { cn } from "@/lib/internal"

export interface CommentInputProps
  extends Omit<
    React.ComponentProps<"textarea">,
    "value" | "defaultValue" | "onChange" | "onSubmit"
  > {
  value?: string
  defaultValue?: string
  onValueChange?: (value: string) => void
  onSubmit?: (value: string, event: React.KeyboardEvent<HTMLTextAreaElement>) => void
  actionIcons?: React.ReactNode
  avatar?: React.ReactNode
}

const COLLAPSED_TEXTAREA_HEIGHT = "22px"
const EXPANDED_TEXTAREA_MAX_HEIGHT = 68

const CommentInput = React.forwardRef<HTMLTextAreaElement, CommentInputProps>(
  (
    {
      className,
      value,
      defaultValue = "",
      onValueChange,
      onSubmit,
      actionIcons,
      avatar,
      placeholder = "Write a comment...",
      disabled,
      onFocus,
      onBlur,
      onKeyDown,
      ...props
    },
    ref
  ) => {
    const textareaRef = React.useRef<HTMLTextAreaElement | null>(null)
    const [focused, setFocused] = React.useState(false)
    const [uncontrolledValue, setUncontrolledValue] = React.useState(defaultValue)
    const currentValue = value ?? uncontrolledValue
    const expanded = focused || currentValue.length > 0
    const state = currentValue.length > 0 ? "typed" : focused ? "focus" : "default"

    const setRefs = React.useCallback(
      (node: HTMLTextAreaElement | null) => {
        textareaRef.current = node
        if (typeof ref === "function") {
          ref(node)
        } else if (ref) {
          ref.current = node
        }
      },
      [ref]
    )

    React.useLayoutEffect(() => {
      const textarea = textareaRef.current
      if (!textarea) return

      if (!expanded) {
        textarea.style.height = COLLAPSED_TEXTAREA_HEIGHT
        return
      }

      textarea.style.height = "auto"
      textarea.style.height = `${Math.min(textarea.scrollHeight, EXPANDED_TEXTAREA_MAX_HEIGHT)}px`
    }, [currentValue, expanded])

    const handleChange: React.ChangeEventHandler<HTMLTextAreaElement> = (event) => {
      const nextValue = event.target.value
      if (value === undefined) setUncontrolledValue(nextValue)
      onValueChange?.(nextValue)
    }

    const handleKeyDown: React.KeyboardEventHandler<HTMLTextAreaElement> = (event) => {
      onKeyDown?.(event)
      if (event.defaultPrevented) return

      if (event.key === "Enter" && (event.metaKey || event.ctrlKey)) {
        event.preventDefault()
        onSubmit?.(currentValue, event)
      }
    }

    return (
      <div
        data-slot="comment-input-root"
        data-state={state}
        data-expanded={expanded || undefined}
        data-disabled={disabled || undefined}
        className={cn("flex w-full items-start gap-2", disabled && "opacity-60")}
      >
        {avatar ? (
          <span data-slot="comment-input-avatar" className="shrink-0">
            {avatar}
          </span>
        ) : null}
        <div
          data-slot="comment-input"
          className={cn(
            "flex w-full items-start gap-2 overflow-hidden border bg_input_fill border_input_opacity radius_6 px-4 py-2 transition-[height] duration-0",
            expanded ? "h-[94px] py-3" : "h-10",
            disabled && "pointer-events-none",
            className
          )}
        >
          <textarea
            ref={setRefs}
            value={currentValue}
            placeholder={placeholder}
            disabled={disabled}
            rows={1}
            data-slot="comment-input-textarea"
            className="min-w-0 flex-1 resize-none bg-transparent p-0 text-sm leading-[22px] text_primary placeholder:text_tertiary outline-none disabled:pointer-events-none"
            onChange={handleChange}
            onFocus={(event) => {
              setFocused(true)
              onFocus?.(event)
            }}
            onBlur={(event) => {
              setFocused(false)
              onBlur?.(event)
            }}
            onKeyDown={handleKeyDown}
            {...props}
          />
          {actionIcons ? (
            <span
              data-slot="comment-input-actions"
              className="flex shrink-0 items-center gap-1 [&_[data-slot=button]]:h-[var(--ds-size-s-size-button)] [&_[data-slot=button]]:w-[var(--ds-size-s-size-button)] [&_svg]:size-4"
            >
              {actionIcons}
            </span>
          ) : null}
        </div>
      </div>
    )
  }
)

CommentInput.displayName = "CommentInput"

export { CommentInput }
