import * as React from "react"
import { type VariantProps } from "class-variance-authority"
import { Check, ChevronDown, X } from "lucide-react"

import { Avatar, type AvatarProps } from "@/components/ui/avatar"
import { Button } from "@/components/ui/button"
import { Popover } from "@/components/ui/popover"
import { cn } from "@/lib/internal"
import { chipVariants } from "./chip-variants"

type ChipVariantProps = VariantProps<typeof chipVariants>
type ChipSize = NonNullable<ChipVariantProps["size"]>
type ChipType = NonNullable<ChipVariantProps["chipType"]>

const ICON_CLASS = "size-5 flex-shrink-0"
const CHIP_INLINE_ICON_CLASS = "size-3.5 flex-shrink-0"
const CHIP_ICON_CLASS = "size-5 flex-shrink-0"
const CHIP_CONTROL_ICON_CLASS = "size-3"

const CHIP_SIZE_CLASS: Record<ChipSize, string> = {
  xs: "h_chip_xs px_chip_xs gap-1",
  s: "h_chip_s px_chip_s gap-1",
  m: "h_chip_m px_chip_m gap-1.5",
  l: "h_chip_l px_chip_l gap-1.5",
  xl: "h_chip_xl px_chip_xl gap-2",
}

const CHIP_ICON_ONLY_SIZE_CLASS: Record<ChipSize, string> = {
  xs: "w_chip_xs",
  s: "w_chip_s",
  m: "w_chip_m",
  l: "w_chip_l",
  xl: "w_chip_xl",
}

const CHIP_ICON_SIDE_PADDING_CLASS: Record<ChipSize, { left: string; right: string }> = {
  xs: {
    left: "pl_chip_icon_xs",
    right: "pr_chip_icon_xs",
  },
  s: {
    left: "pl_chip_icon_s",
    right: "pr_chip_icon_s",
  },
  m: {
    left: "pl_chip_icon_m",
    right: "pr_chip_icon_m",
  },
  l: {
    left: "pl_chip_icon_l",
    right: "pr_chip_icon_l",
  },
  xl: {
    left: "pl_chip_icon_xl",
    right: "pr_chip_icon_xl",
  },
}

const resolveChipType = (
  chipType: ChipType | null | undefined,
  bordered?: boolean | null
): ChipType =>
  chipType ?? (bordered === false ? "borderless" : "borderFill")

const CHIP_AVATAR_SIZE: Record<ChipSize, AvatarProps["size"]> = {
  xs: "xxs",
  s: "xxs",
  m: "xs",
  l: "xs",
  xl: "s",
}

const findNextEnabledIndex = (
  options: readonly FilterChipRadioOption[],
  currentIndex: number,
  step: 1 | -1
) => {
  if (options.length === 0) return -1

  for (let offset = 1; offset <= options.length; offset += 1) {
    const nextIndex = (currentIndex + offset * step + options.length) % options.length
    if (!options[nextIndex]?.disabled) return nextIndex
  }

  return -1
}

const findFirstEnabledIndex = (options: readonly FilterChipRadioOption[]) =>
  options.findIndex((option) => !option.disabled)

const findLastEnabledIndex = (options: readonly FilterChipRadioOption[]) => {
  for (let index = options.length - 1; index >= 0; index -= 1) {
    if (!options[index]?.disabled) return index
  }
  return -1
}

export interface ChipOption {
  label: string
  value: string
}

export interface ChipProps
  extends Omit<React.HTMLAttributes<HTMLSpanElement>, "color">,
    Omit<ChipVariantProps, "selected" | "pill"> {
  size?: ChipSize
  selected?: boolean
  pill?: boolean
  options?: ChipOption[]
  value?: string
  onValueChange?: (value: string) => void
  searchable?: boolean
  clearable?: boolean
  labelMode?: "replace" | "append"
  placeholder?: string
  icon?: React.ReactNode
  onRemove?: () => void
}

const Chip = React.forwardRef<HTMLSpanElement, ChipProps>(
  (
    {
      className,
      variant = "tag",
      size = "m",
      color,
      chipType,
      bordered,
      pill = false,
      selected = false,
      options,
      value,
      onValueChange,
      searchable = false,
      clearable = false,
      labelMode = "replace",
      placeholder = "Select...",
      icon,
      onRemove,
      children,
      ...props
    },
    ref
  ) => {
    const [selectorOpen, setSelectorOpen] = React.useState(false)
    const [searchQuery, setSearchQuery] = React.useState("")
    const [chipHovered, setChipHovered] = React.useState(false)

    const isSelected = variant === "selector" ? !!value : selected
    const showClearButton = clearable && variant === "selector" && !!value && chipHovered

    const selectedLabel = React.useMemo(
      () => options?.find((option) => option.value === value)?.label,
      [options, value]
    )

    const filteredOptions = React.useMemo(() => {
      if (!options) return []
      if (!searchable || !searchQuery) return options
      const q = searchQuery.toLowerCase()
      return options.filter((option) => option.label.toLowerCase().includes(q))
    }, [options, searchable, searchQuery])

    let leadingIcon = icon
    if (variant === "check" && selected) {
      leadingIcon = <Check className={ICON_CLASS} aria-hidden />
    }

    const resolvedChipType = resolveChipType(chipType, bordered)
    const hasLeftIcon = !!leadingIcon
    const hasRightIcon = variant === "selector" || !!onRemove

    const chipClassName = cn(
      chipVariants({
        variant,
        size,
        color,
        chipType: resolvedChipType,
        bordered,
        pill: variant === "check" || variant === "selector" ? true : pill,
        selected: isSelected,
      }),
      hasLeftIcon && CHIP_ICON_SIDE_PADDING_CLASS[size].left,
      hasRightIcon && CHIP_ICON_SIDE_PADDING_CLASS[size].right,
      className
    )

    const chipInner = (
      <>
        {leadingIcon && (
          <span className={cn(ICON_CLASS, "flex items-center justify-center [&>svg]:size-5")} aria-hidden>
            {leadingIcon}
          </span>
        )}
        <span>
          {variant === "selector"
            ? selectedLabel
              ? labelMode === "append"
                ? `${placeholder}: ${selectedLabel}`
                : selectedLabel
              : placeholder
            : children}
        </span>
        {variant === "selector" && (
          showClearButton ? (
            <button
              type="button"
              onPointerDown={(e) => {
                onValueChange?.("")
                e.preventDefault()
                e.stopPropagation()
              }}
              onKeyDown={(e) => {
                if (e.key !== "Enter" && e.key !== " ") return
                onValueChange?.("")
                e.preventDefault()
                e.stopPropagation()
              }}
              onClick={(e) => {
                e.preventDefault()
                e.stopPropagation()
              }}
              className={cn(ICON_CLASS, "flex items-center justify-center cursor-pointer")}
              aria-label="Clear"
            >
              <X className={CHIP_INLINE_ICON_CLASS} aria-hidden />
            </button>
          ) : (
            <span className={cn(ICON_CLASS, "flex items-center justify-center")} aria-hidden>
              <ChevronDown className={CHIP_INLINE_ICON_CLASS} aria-hidden />
            </span>
          )
        )}
        {onRemove && (
          <button
            type="button"
            onClick={(e) => {
              e.stopPropagation()
              onRemove()
            }}
            className="size-5 flex-shrink-0 flex items-center justify-center rounded-full opacity-60 hover:opacity-100 cursor-pointer"
            aria-label="Remove"
          >
            <X className={CHIP_INLINE_ICON_CLASS} aria-hidden />
          </button>
        )}
      </>
    )

    if (variant === "selector") {
      return (
        <Popover
          trigger={
            <span
              ref={ref}
              data-slot="chip"
              data-variant={variant}
              data-size={size}
              data-selected={isSelected || undefined}
              data-chip-type={resolvedChipType}
              className={chipClassName}
              onMouseEnter={() => setChipHovered(true)}
              onMouseLeave={() => setChipHovered(false)}
              {...props}
            >
              {chipInner}
            </span>
          }
          open={selectorOpen}
          onOpenChange={(open) => {
            setSelectorOpen(open)
            if (!open) setSearchQuery("")
          }}
          align="start"
          sideOffset={4}
        >
          <div className="flex flex-col gap-0.5">
            {searchable && (
              <input
                type="text"
                autoFocus
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                placeholder="Search..."
                className="w-full px-2 py-1.5 text-sm text_primary bg_primary border border_secondary radius_6 outline-none mb-1 focus:border_accent transition-colors duration-0"
              />
            )}
            <div className="max-h-[240px] overflow-y-auto flex flex-col gap-0.5">
              {filteredOptions.length === 0 ? (
                <p className="px-2 py-1.5 text-sm text_tertiary">No options</p>
              ) : (
                filteredOptions.map((option) => (
                  <button
                    key={option.value}
                    type="button"
                    onClick={() => {
                      onValueChange?.(option.value)
                      setSelectorOpen(false)
                      setSearchQuery("")
                    }}
                    className={cn(
                      "flex w-full items-center gap-2 px-2 py-1.5 text-sm radius_6 text-left cursor-pointer focus:outline-none hover:state_primary_subtle",
                      option.value === value ? "fg_accent_secondary" : "text_primary"
                    )}
                  >
                    {option.label}
                    {option.value === value && (
                      <Check className="w-3.5 h-3.5 flex-shrink-0 ml-auto" aria-hidden />
                    )}
                  </button>
                ))
              )}
            </div>
          </div>
        </Popover>
      )
    }

    return (
      <span
        ref={ref}
        data-slot="chip"
        data-variant={variant}
        data-size={size}
        data-selected={isSelected || undefined}
        data-chip-type={resolvedChipType}
        className={chipClassName}
        {...props}
      >
        {chipInner}
      </span>
    )
  }
)

Chip.displayName = "Chip"

export interface FilterChipRadioOption {
  label: React.ReactNode
  value: string
  icon?: React.ReactNode
  disabled?: boolean
}

export interface FilterChipRadioProps
  extends Omit<React.ComponentProps<"button">, "value" | "onChange"> {
  value: string
  selected?: boolean
  size?: ChipSize
  bordered?: boolean
  chipType?: ChipType
  icon?: React.ReactNode
}

const FilterChipRadio = React.forwardRef<HTMLButtonElement, FilterChipRadioProps>(
  (
    {
      className,
      value,
      selected = false,
      size = "m",
      bordered = true,
      chipType,
      icon,
      children,
      type,
      ...props
    },
    ref
  ) => (
    <button
      ref={ref}
      type={type ?? "button"}
      role="radio"
      aria-checked={selected}
      data-slot="filter-chip-radio"
      data-size={size}
      data-selected={selected || undefined}
      data-chip-type={resolveChipType(chipType, bordered)}
      value={value}
      className={cn(
        chipVariants({
          variant: "check",
          size,
          chipType: resolveChipType(chipType, bordered),
          bordered,
          pill: true,
          selected,
        }),
        icon && CHIP_ICON_SIDE_PADDING_CLASS[size].left,
        "outline-none focus-visible:shadow-[var(--ds-outline-blue-focus)] disabled:pointer-events-none disabled:opacity-60",
        className
      )}
      {...props}
    >
      {icon && (
        <span
          className={cn(CHIP_ICON_CLASS, "flex items-center justify-center [&>svg]:size-5")}
          aria-hidden
        >
          {icon}
        </span>
      )}
      <span>{children}</span>
    </button>
  )
)

export interface FilterChipRadioGroupProps
  extends Omit<React.ComponentProps<"div">, "onChange"> {
  options: readonly FilterChipRadioOption[]
  value?: string
  defaultValue?: string
  onValueChange?: (value: string) => void
  size?: ChipSize
  bordered?: boolean
  chipType?: ChipType
}

const FilterChipRadioGroup = React.forwardRef<HTMLDivElement, FilterChipRadioGroupProps>(
  (
    {
      className,
      options,
      value,
      defaultValue,
      onValueChange,
      size = "m",
      bordered = true,
      chipType,
      onKeyDown,
      ...props
    },
    ref
  ) => {
    const firstEnabledIndex = findFirstEnabledIndex(options)
    const firstEnabledValue = firstEnabledIndex >= 0 ? options[firstEnabledIndex]?.value : undefined
    const [uncontrolledValue, setUncontrolledValue] = React.useState(
      () => defaultValue ?? firstEnabledValue
    )
    const selectedValue = value ?? uncontrolledValue
    const [focusValue, setFocusValue] = React.useState(() => selectedValue ?? firstEnabledValue)
    const itemRefs = React.useRef(new Map<string, HTMLButtonElement>())

    React.useEffect(() => {
      if (selectedValue) setFocusValue(selectedValue)
    }, [selectedValue])

    const selectValue = React.useCallback(
      (nextValue: string) => {
        if (value === undefined) setUncontrolledValue(nextValue)
        onValueChange?.(nextValue)
      },
      [onValueChange, value]
    )

    const focusAndSelectIndex = React.useCallback(
      (nextIndex: number) => {
        const nextOption = options[nextIndex]
        if (!nextOption || nextOption.disabled) return

        setFocusValue(nextOption.value)
        selectValue(nextOption.value)
        itemRefs.current.get(nextOption.value)?.focus()
      },
      [options, selectValue]
    )

    const selectedIndex = options.findIndex((option) => option.value === selectedValue)
    const focusIndex = options.findIndex((option) => option.value === focusValue)
    const rovingIndex =
      focusIndex >= 0 && !options[focusIndex]?.disabled
        ? focusIndex
        : selectedIndex >= 0 && !options[selectedIndex]?.disabled
          ? selectedIndex
          : firstEnabledIndex

    const handleKeyDown: React.KeyboardEventHandler<HTMLDivElement> = (event) => {
      onKeyDown?.(event)
      if (event.defaultPrevented) return

      let nextIndex = -1
      if (event.key === "ArrowRight" || event.key === "ArrowDown") {
        nextIndex = findNextEnabledIndex(options, rovingIndex, 1)
      } else if (event.key === "ArrowLeft" || event.key === "ArrowUp") {
        nextIndex = findNextEnabledIndex(options, rovingIndex, -1)
      } else if (event.key === "Home") {
        nextIndex = findFirstEnabledIndex(options)
      } else if (event.key === "End") {
        nextIndex = findLastEnabledIndex(options)
      }

      if (nextIndex >= 0) {
        event.preventDefault()
        focusAndSelectIndex(nextIndex)
      }
    }

    return (
      <div
        ref={ref}
        role="radiogroup"
        data-slot="filter-chip-radio-group"
        className={cn("flex flex-wrap items-center gap-2", className)}
        onKeyDown={handleKeyDown}
        {...props}
      >
        {options.map((option, index) => (
          <FilterChipRadio
            key={option.value}
            ref={(node) => {
              if (node) {
                itemRefs.current.set(option.value, node)
              } else {
                itemRefs.current.delete(option.value)
              }
            }}
            value={option.value}
            size={size}
            bordered={bordered}
            chipType={chipType}
            selected={selectedValue === option.value}
            disabled={option.disabled}
            tabIndex={index === rovingIndex ? 0 : -1}
            icon={option.icon}
            onFocus={() => setFocusValue(option.value)}
            onClick={() => {
              if (option.disabled) return
              setFocusValue(option.value)
              selectValue(option.value)
            }}
          >
            {option.label}
          </FilterChipRadio>
        ))}
      </div>
    )
  }
)

export interface TabChipProps extends Omit<React.ComponentProps<"button">, "color"> {
  active?: boolean
  display?: "full" | "iconOnly"
  color?: "subtle" | "fill"
  size?: ChipSize
  pill?: boolean
  icon?: React.ReactNode
}

const TabChip = React.forwardRef<HTMLButtonElement, TabChipProps>(
  (
    {
      className,
      active = false,
      display = "full",
      color = "subtle",
      size = "m",
      pill = true,
      icon,
      children,
      type,
      ...props
    },
    ref
  ) => (
    <button
      ref={ref}
      type={type ?? "button"}
      aria-pressed={active}
      data-slot="tab-chip"
      data-size={size}
      data-active={active || undefined}
      data-display={display}
      data-color={color}
      className={cn(
        "inline-flex cursor-pointer items-center justify-center border font-normal text-sm transition-colors duration-0 outline-none focus-visible:shadow-[var(--ds-outline-blue-focus)] disabled:pointer-events-none disabled:opacity-60",
        CHIP_SIZE_CLASS[size],
        pill ? "radius_round" : "radius_4",
        display === "iconOnly" ? CHIP_ICON_ONLY_SIZE_CLASS[size] : "",
        active
          ? "bg_accent_secondary_subtle border_accent_secondary_contrast fg_accent_secondary hover:state_bg_accent_secondary_subtle_subtle active:state_bg_accent_secondary_subtle_soft"
          : color === "fill"
            ? "bg_interactive_secondary border_secondary text_primary hover:state_bg_interactive_secondary_subtle active:state_bg_interactive_secondary_soft"
            : "bg-transparent border_secondary text_primary hover:state_primary_subtle active:state_primary_soft",
        className
      )}
      {...props}
    >
      {icon && (
        <span
          className={cn(CHIP_ICON_CLASS, "flex items-center justify-center [&>svg]:size-5")}
          aria-hidden
        >
          {icon}
        </span>
      )}
      {display === "full" && <span>{children}</span>}
    </button>
  )
)

export interface InfoChipProps extends Omit<React.ComponentProps<"div">, "color"> {
  variant?: "fill" | "light"
  size?: ChipSize
  icon?: React.ReactNode
  showClose?: boolean
  closeAriaLabel?: string
  onClose?: () => void
}

const InfoChip = React.forwardRef<HTMLDivElement, InfoChipProps>(
  (
    {
      className,
      variant = "fill",
      size = "m",
      icon,
      showClose,
      closeAriaLabel = "Close",
      onClose,
      children,
      ...props
    },
    ref
  ) => {
    const closeVisible = showClose ?? !!onClose

    return (
      <div
        ref={ref}
        data-slot="info-chip"
        data-size={size}
        data-variant={variant}
        className={cn(
          "inline-flex items-center border select-none radius_4",
          CHIP_SIZE_CLASS[size],
          "font-normal text-sm text_secondary transition-colors duration-0",
          variant === "fill"
            ? "bg_interactive_secondary border_secondary hover:state_bg_interactive_secondary_subtle active:state_bg_interactive_secondary_soft"
            : "bg_interactive_primary border_secondary hover:state_bg_interactive_primary_subtle active:state_bg_interactive_primary_soft",
          icon && CHIP_ICON_SIDE_PADDING_CLASS[size].left,
          closeVisible && CHIP_ICON_SIDE_PADDING_CLASS[size].right,
          className
        )}
        {...props}
      >
        {icon && (
          <span
            className={cn(CHIP_ICON_CLASS, "flex items-center justify-center icon_secondary [&>svg]:size-5")}
            aria-hidden
          >
            {icon}
          </span>
        )}
        <span>{children}</span>
        {closeVisible && (
          <Button
            type="button"
            variant="borderlessSubtle"
            size="icon-mini-m"
            aria-label={closeAriaLabel}
            onClick={(event) => {
              event.stopPropagation()
              onClose?.()
            }}
          >
            <X className={CHIP_CONTROL_ICON_CLASS} aria-hidden />
          </Button>
        )}
      </div>
    )
  }
)

export interface InputChipProps extends Omit<React.ComponentProps<"div">, "color"> {
  type?: "value" | "avatar"
  size?: ChipSize
  icon?: React.ReactNode
  avatar?: React.ReactNode
  avatarProps?: AvatarProps
  showClose?: boolean
  closeAriaLabel?: string
  onRemove?: () => void
}

const InputChip = React.forwardRef<HTMLDivElement, InputChipProps>(
  (
    {
      className,
      type = "value",
      size = "m",
      icon,
      avatar,
      avatarProps,
      showClose,
      closeAriaLabel = "Remove",
      onRemove,
      children,
      ...props
    },
    ref
  ) => {
    const closeVisible = showClose ?? !!onRemove

    return (
      <div
        ref={ref}
        data-slot="input-chip"
        data-size={size}
        data-type={type}
        className={cn(
          "inline-flex items-center border select-none radius_4",
          CHIP_SIZE_CLASS[size],
          "bg_interactive_secondary border_secondary font-normal text-sm text_secondary transition-colors duration-0 hover:state_bg_interactive_secondary_subtle active:state_bg_interactive_secondary_soft",
          (type === "avatar" || icon) && CHIP_ICON_SIDE_PADDING_CLASS[size].left,
          closeVisible && CHIP_ICON_SIDE_PADDING_CLASS[size].right,
          className
        )}
        {...props}
      >
        {type === "avatar" ? (
          avatar ?? (
            <Avatar
              alt={typeof children === "string" ? children : "Input chip avatar"}
              size={avatarProps?.size ?? CHIP_AVATAR_SIZE[size]}
              {...avatarProps}
            />
          )
        ) : icon ? (
          <span
            className={cn(CHIP_ICON_CLASS, "flex items-center justify-center icon_secondary [&>svg]:size-5")}
            aria-hidden
          >
            {icon}
          </span>
        ) : null}
        <span>{children}</span>
        {closeVisible && (
          <Button
            type="button"
            variant="borderlessSubtle"
            size="icon-mini-m"
            aria-label={closeAriaLabel}
            onClick={(event) => {
              event.stopPropagation()
              onRemove?.()
            }}
          >
            <X className={CHIP_CONTROL_ICON_CLASS} aria-hidden />
          </Button>
        )}
      </div>
    )
  }
)

FilterChipRadio.displayName = "FilterChipRadio"
FilterChipRadioGroup.displayName = "FilterChipRadioGroup"
TabChip.displayName = "TabChip"
InfoChip.displayName = "InfoChip"
InputChip.displayName = "InputChip"

export { Chip, FilterChipRadio, FilterChipRadioGroup, InfoChip, InputChip, TabChip }
