import * as React from "react"

import { cn } from "@/lib/internal"
import { simpleSidebarItemVariants } from "./simple-sidebar-variants"

export interface SimpleSidebarItem {
  id: string
  label: string
  icon: React.ReactNode
  activeIcon?: React.ReactNode
  href?: string
  disabled?: boolean
}

export interface SimpleSidebarGroup {
  id: string
  items: SimpleSidebarItem[]
}

export interface SimpleSidebarProps extends React.ComponentProps<"aside"> {
  groups: SimpleSidebarGroup[]
  activeId?: string
  onNavigate?: (id: string, href?: string) => void
  header?: React.ReactNode
  footer?: React.ReactNode
  alwaysExpanded?: boolean
  expandedWidth?: number
  collapsedWidth?: number
}

const SimpleSidebar = React.forwardRef<HTMLElement, SimpleSidebarProps>(
  (
    {
      groups,
      activeId,
      onNavigate,
      header,
      footer,
      alwaysExpanded = false,
      expandedWidth = 200,
      collapsedWidth = 56,
      className,
      style,
      onMouseEnter,
      onMouseLeave,
      "aria-label": ariaLabel = "Simple sidebar",
      ...props
    },
    ref
  ) => {
    const [hovered, setHovered] = React.useState(false)
    const leaveTimerRef = React.useRef<ReturnType<typeof setTimeout> | null>(null)
    const isExpanded = alwaysExpanded || hovered

    React.useEffect(() => {
      return () => {
        if (leaveTimerRef.current) clearTimeout(leaveTimerRef.current)
      }
    }, [])

    React.useEffect(() => {
      if (!alwaysExpanded) return

      if (leaveTimerRef.current) {
        clearTimeout(leaveTimerRef.current)
        leaveTimerRef.current = null
      }

      setHovered(false)
    }, [alwaysExpanded])

    return (
      <aside
        ref={ref}
        data-slot="simple-sidebar"
        data-expanded={isExpanded}
        aria-label={ariaLabel}
        onMouseEnter={(event) => {
          if (leaveTimerRef.current) {
            clearTimeout(leaveTimerRef.current)
            leaveTimerRef.current = null
          }
          onMouseEnter?.(event)
          if (alwaysExpanded) return
          setHovered(true)
        }}
        onMouseLeave={(event) => {
          onMouseLeave?.(event)
          if (leaveTimerRef.current) {
            clearTimeout(leaveTimerRef.current)
            leaveTimerRef.current = null
          }
          if (alwaysExpanded) return
          leaveTimerRef.current = setTimeout(() => {
            setHovered(false)
            leaveTimerRef.current = null
          }, 100)
        }}
        style={{
          ...style,
          width: isExpanded ? expandedWidth : collapsedWidth,
        }}
        className={cn(
          "absolute left-0 top-0 h-full flex flex-col z-40",
          "bg-transparent",
          "transition-all duration-200 overflow-hidden",
          className
        )}
        {...props}
      >
        {header ? (
          <div
            data-slot="simple-sidebar-header"
            className="shrink-0 flex items-center justify-center overflow-hidden p-2"
            style={{ width: collapsedWidth }}
          >
            {header}
          </div>
        ) : null}

        <div data-slot="simple-sidebar-content" className="flex-1 overflow-y-auto flex flex-col">
          <div className="px-2 space-y-1 my-auto">
            {groups.map((group, index) => (
              <div key={group.id} data-slot="simple-sidebar-group" className="space-y-1">
                {index > 0 ? (
                  <hr
                    data-slot="simple-sidebar-separator"
                    className="border_secondary my-1 mx-2"
                  />
                ) : null}

                {group.items.map((item) => {
                  const isActive = activeId === item.id

                  return (
                    <button
                      key={item.id}
                      type="button"
                      data-slot="simple-sidebar-item"
                      data-active={isActive}
                      aria-label={!isExpanded ? item.label : undefined}
                      aria-current={isActive ? "page" : undefined}
                      disabled={item.disabled}
                      title={!isExpanded ? item.label : undefined}
                      onClick={() => onNavigate?.(item.id, item.href)}
                      className={cn(
                        simpleSidebarItemVariants({ active: isActive }),
                        "h-10 px-2",
                        "disabled:opacity-50 disabled:cursor-not-allowed"
                      )}
                    >
                      <span
                        data-slot="simple-sidebar-item-icon"
                        className="shrink-0 flex items-center justify-center w-6 h-6"
                        aria-hidden="true"
                      >
                        {isActive && item.activeIcon ? item.activeIcon : item.icon}
                      </span>

                      <span
                        data-slot="simple-sidebar-item-label"
                        aria-hidden={!isExpanded}
                        className={cn(
                          "text-left truncate overflow-hidden whitespace-nowrap transition-all duration-200 min-w-0 pl-2",
                          isExpanded ? "opacity-100 w-auto flex-1" : "opacity-0 w-0"
                        )}
                      >
                        {item.label}
                      </span>
                    </button>
                  )
                })}
              </div>
            ))}
          </div>
        </div>

        {footer ? (
          <div
            data-slot="simple-sidebar-footer"
            className="shrink-0 flex items-center justify-center overflow-hidden p-2"
            style={{ width: collapsedWidth }}
          >
            {footer}
          </div>
        ) : null}
      </aside>
    )
  }
)

SimpleSidebar.displayName = "SimpleSidebar"

export { SimpleSidebar }
