import * as React from "react"
import { Checkbox as CheckboxPrimitive } from "radix-ui"

import { cn } from "@/lib/internal"
import { checkboxIndicatorVariants, checkboxVariants } from "./checkbox-variants"

export interface CheckboxProps extends Omit<
  React.ComponentPropsWithoutRef<typeof CheckboxPrimitive.Root>,
  "asChild"
> {
  label?: string
  description?: string
  size?: "sm" | "md" | "lg"
}

const Checkbox = React.forwardRef<React.ElementRef<typeof CheckboxPrimitive.Root>, CheckboxProps>(
  ({ label, description, size = "md", className, id, onFocus, onBlur, ...props }, ref) => {
    const generatedId = React.useId()
    const innerId = id ?? generatedId
    const [isFocused, setIsFocused] = React.useState(false)

    return (
      <div className={cn("flex items-start gap-2", className)}>
        <CheckboxPrimitive.Root
          ref={ref}
          id={innerId}
          data-slot="checkbox"
          data-size={size}
          className={cn(checkboxVariants({ size }), isFocused && "outline_blue_focus")}
          onFocus={(event) => {
            setIsFocused(true)
            onFocus?.(event)
          }}
          onBlur={(event) => {
            setIsFocused(false)
            onBlur?.(event)
          }}
          {...props}
        >
          <CheckboxPrimitive.Indicator
            data-slot="checkbox-indicator"
            className={cn(checkboxIndicatorVariants({ size }))}
          >
            <svg
              viewBox="0 0 16 16"
              fill="none"
              xmlns="http://www.w3.org/2000/svg"
              aria-hidden="true"
              className="h-full w-full"
            >
              <path
                d="M12.5 4.5L6.5 10.5L3.5 7.5"
                stroke="currentColor"
                strokeWidth="2"
                strokeLinecap="round"
                strokeLinejoin="round"
              />
            </svg>
          </CheckboxPrimitive.Indicator>
        </CheckboxPrimitive.Root>
        {(label || description) && (
          <div className="flex flex-col">
            {label && (
              <label htmlFor={innerId} className="cursor-pointer text_primary text-sm">
                {label}
              </label>
            )}
            {description && <span className="text_tertiary text-sm">{description}</span>}
          </div>
        )}
      </div>
    )
  }
)

Checkbox.displayName = "Checkbox"

export { Checkbox }
