import * as React from "react"
import { Tabs as TabsPrimitive } from "radix-ui"

import { cn } from "@/lib/internal"
import {
  tabsContentVariants,
  tabsListVariants,
  tabsTriggerVariants,
  type TabsColor,
  type TabsVariant,
} from "./tabs-variants"

type TabsCssProperties = React.CSSProperties & {
  "--ui-tabs-trigger-height"?: string
}

const toTabHeight = (tabHeight?: number | string) => {
  if (tabHeight === undefined) return undefined
  return typeof tabHeight === "number" ? `${tabHeight}px` : tabHeight
}

const withTabHeightStyle = (
  style: React.CSSProperties | undefined,
  tabHeight?: number | string
) => {
  const value = toTabHeight(tabHeight)
  if (!value) return style

  const nextStyle: TabsCssProperties = { ...(style ?? {}) }
  nextStyle["--ui-tabs-trigger-height"] = value
  return nextStyle
}

export interface TabsItem {
  value: string
  label: React.ReactNode
  content?: React.ReactNode
  disabled?: boolean
  triggerClassName?: string
  contentClassName?: string
}

export interface TabsProps extends Omit<
  React.ComponentPropsWithoutRef<typeof TabsPrimitive.Root>,
  "children"
> {
  items: readonly TabsItem[]
  variant?: TabsVariant
  color?: TabsColor
  tabHeight?: number | string
  tabsListClassName?: string
  triggerClassName?: string
  contentClassName?: string
}

const Tabs = React.forwardRef<React.ElementRef<typeof TabsPrimitive.Root>, TabsProps>(
  (
    {
      items,
      variant = "default",
      color = "orange",
      tabHeight,
      tabsListClassName,
      triggerClassName,
      contentClassName,
      value,
      defaultValue,
      style,
      ...props
    },
    ref
  ) => {
    const firstEnabledItem = React.useMemo(
      () => items?.find((item) => !item.disabled)?.value,
      [items]
    )

    const resolvedDefaultValue =
      value === undefined ? (defaultValue ?? firstEnabledItem) : undefined

    return (
      <TabsPrimitive.Root
        ref={ref}
        data-slot="tabs"
        value={value}
        defaultValue={resolvedDefaultValue}
        style={withTabHeightStyle(style, tabHeight)}
        {...props}
      >
        <TabsPrimitive.List
          data-slot="tabs-list"
          data-variant={variant}
          data-color={color}
          className={cn(tabsListVariants({ variant }), tabsListClassName)}
        >
          {items.map((item) => (
            <TabsPrimitive.Trigger
              key={item.value}
              data-slot="tabs-trigger"
              data-variant={variant}
              data-color={color}
              value={item.value}
              disabled={item.disabled}
              className={cn(
                tabsTriggerVariants({ variant, color }),
                triggerClassName,
                item.triggerClassName
              )}
            >
              {item.label}
            </TabsPrimitive.Trigger>
          ))}
        </TabsPrimitive.List>

        {items.map((item) =>
          item.content === undefined ? null : (
            <TabsPrimitive.Content
              key={item.value}
              data-slot="tabs-content"
              value={item.value}
              className={cn(tabsContentVariants(), contentClassName, item.contentClassName)}
            >
              {item.content}
            </TabsPrimitive.Content>
          )
        )}
      </TabsPrimitive.Root>
    )
  }
)

Tabs.displayName = TabsPrimitive.Root.displayName

export { Tabs }
