import * as React from "react"
import { RadioGroup as RadioGroupPrimitive } from "radix-ui"

import { cn } from "@/lib/internal"
import { radioGroupItemVariants, radioGroupVariants } from "./radio-group-variants"

export interface RadioGroupProps extends React.ComponentPropsWithoutRef<
  typeof RadioGroupPrimitive.Root
> {
  orientation?: "horizontal" | "vertical"
}

export interface RadioGroupItemProps extends React.ComponentPropsWithoutRef<
  typeof RadioGroupPrimitive.Item
> {
  label?: string
  description?: string
  size?: "sm" | "md" | "lg"
}

const RadioGroup = React.forwardRef<
  React.ElementRef<typeof RadioGroupPrimitive.Root>,
  RadioGroupProps
>(({ className, orientation = "vertical", ...props }, ref) => (
  <RadioGroupPrimitive.Root
    ref={ref}
    orientation={orientation}
    data-slot="radio-group"
    data-orientation={orientation}
    className={cn(radioGroupVariants({ orientation }), className)}
    {...props}
  />
))

const RadioGroupItem = React.forwardRef<
  React.ElementRef<typeof RadioGroupPrimitive.Item>,
  RadioGroupItemProps
>(({ className, label, description, size = "md", id, ...props }, ref) => {
  const generatedId = React.useId()
  const innerId = id ?? generatedId

  return (
    <div className="flex items-start gap-2">
      <RadioGroupPrimitive.Item
        ref={ref}
        id={innerId}
        data-slot="radio-group-item"
        data-size={size}
        className={cn(radioGroupItemVariants({ size }), className)}
        {...props}
      />
      {(label || description) && (
        <div className="flex flex-col">
          {label && (
            <label htmlFor={innerId} className="cursor-pointer text_primary text-sm">
              {label}
            </label>
          )}
          {description && <span className="text_tertiary text-sm">{description}</span>}
        </div>
      )}
    </div>
  )
})

RadioGroup.displayName = "RadioGroup"
RadioGroupItem.displayName = "RadioGroupItem"

export { RadioGroup, RadioGroupItem }
