import * as React from "react"
import { Tooltip as TooltipPrimitive } from "radix-ui"

import { cn } from "@/lib/internal"

export interface TooltipProps {
  title?: React.ReactNode
  content: React.ReactNode
  children: React.ReactElement
  side?: "top" | "right" | "bottom" | "left"
  align?: "start" | "center" | "end"
  delayDuration?: number
  avoidCollisions?: boolean
  open?: boolean
  onOpenChange?: (open: boolean) => void
  disabled?: boolean
  className?: string
}

const Tooltip = ({
  title,
  content,
  children,
  side = "top",
  align = "center",
  delayDuration = 400,
  avoidCollisions = false,
  open,
  onOpenChange,
  disabled = false,
  className,
}: TooltipProps) => {
  if (disabled) {
    return <>{children}</>
  }

  return (
    <TooltipPrimitive.Root open={open} onOpenChange={onOpenChange} delayDuration={delayDuration}>
      <TooltipPrimitive.Trigger asChild>{children}</TooltipPrimitive.Trigger>
      <TooltipPrimitive.Portal>
        <TooltipPrimitive.Content
          data-slot="tooltip-content"
          side={side}
          align={align}
          avoidCollisions={avoidCollisions}
          className={cn(
            "z-50 bg_primary border border_primary radius_12 shadow_xs px-3 py-2 max-w-[240px]",
            className
          )}
        >
          {title ? (
            <p className="text-sm font-semibold text_primary leading-snug">{title}</p>
          ) : null}
          <div className={cn("text-xs font-normal text_tertiary leading-snug", title && "mt-0.5")}>
            {content}
          </div>
        </TooltipPrimitive.Content>
      </TooltipPrimitive.Portal>
    </TooltipPrimitive.Root>
  )
}

Tooltip.displayName = "Tooltip"

const TooltipProvider = TooltipPrimitive.Provider
TooltipProvider.displayName = "TooltipProvider"

export { Tooltip, TooltipProvider }
