import * as React from "react"

import { cn } from "@/lib/internal"

interface CardProps extends React.HTMLAttributes<HTMLDivElement> {
  shadow?: "none" | "xs" | "sm" | "md" | "lg" | "xl"
  hoverable?: boolean
}

const shadowClassMap: Record<NonNullable<CardProps["shadow"]>, string> = {
  none: "shadow-none",
  xs: "shadow_xs",
  sm: "shadow_xxs",
  md: "shadow_m",
  lg: "shadow_l",
  xl: "shadow_xl",
}

const Card = React.forwardRef<HTMLDivElement, CardProps>(
  ({ className, shadow = "xs", hoverable = false, ...props }, ref) => (
    <div
      ref={ref}
      data-slot="card"
      data-shadow={shadow}
      data-hoverable={hoverable}
      className={cn(
        "flex flex-col border border_secondary bg_primary radius_12",
        shadowClassMap[shadow],
        hoverable && "transition-shadow hover:shadow-[var(--ds-shadow-l)]",
        className
      )}
      {...props}
    />
  )
)

const CardHeader = React.forwardRef<HTMLDivElement, React.HTMLAttributes<HTMLDivElement>>(
  ({ className, ...props }, ref) => (
    <div
      ref={ref}
      data-slot="card-header"
      className={cn("flex flex-col gap-1.5 p-6 border-b border_secondary", className)}
      {...props}
    />
  )
)

const CardTitle = React.forwardRef<HTMLHeadingElement, React.HTMLAttributes<HTMLHeadingElement>>(
  ({ className, ...props }, ref) => (
    <h3
      ref={ref}
      data-slot="card-title"
      className={cn("text-base font-semibold text_primary", className)}
      {...props}
    />
  )
)

const CardDescription = React.forwardRef<
  HTMLParagraphElement,
  React.HTMLAttributes<HTMLParagraphElement>
>(({ className, ...props }, ref) => (
  <p
    ref={ref}
    data-slot="card-description"
    className={cn("text-sm text_secondary", className)}
    {...props}
  />
))

const CardContent = React.forwardRef<HTMLDivElement, React.HTMLAttributes<HTMLDivElement>>(
  ({ className, ...props }, ref) => (
    <div ref={ref} data-slot="card-content" className={cn("flex-1 p-6", className)} {...props} />
  )
)

const CardFooter = React.forwardRef<HTMLDivElement, React.HTMLAttributes<HTMLDivElement>>(
  ({ className, ...props }, ref) => (
    <div
      ref={ref}
      data-slot="card-footer"
      className={cn("flex items-center gap-2 border-t border_secondary p-6", className)}
      {...props}
    />
  )
)

Card.displayName = "Card"
CardHeader.displayName = "CardHeader"
CardTitle.displayName = "CardTitle"
CardDescription.displayName = "CardDescription"
CardContent.displayName = "CardContent"
CardFooter.displayName = "CardFooter"

export { Card, CardHeader, CardTitle, CardDescription, CardContent, CardFooter }
