import * as React from "react"
import { type VariantProps } from "class-variance-authority"

import { cn } from "@/lib/internal"
import { iconToggleVariants } from "./icon-toggle-variants"

type IconToggleVariantProps = VariantProps<typeof iconToggleVariants>

export interface IconToggleProps
  extends Omit<React.ComponentProps<"button">, "onChange">,
    Omit<IconToggleVariantProps, "active"> {
  pressed?: boolean
  defaultPressed?: boolean
  onPressedChange?: (pressed: boolean) => void
}

const IconToggle = React.forwardRef<HTMLButtonElement, IconToggleProps>(
  (
    {
      className,
      variant = "dim",
      size = "m",
      pressed,
      defaultPressed = false,
      onPressedChange,
      disabled,
      type,
      onClick,
      ...props
    },
    ref
  ) => {
    const [uncontrolledPressed, setUncontrolledPressed] = React.useState(defaultPressed)
    const isPressed = pressed ?? uncontrolledPressed

    const handleClick: React.MouseEventHandler<HTMLButtonElement> = (event) => {
      onClick?.(event)
      if (event.defaultPrevented || disabled) return

      const nextPressed = !isPressed
      if (pressed === undefined) setUncontrolledPressed(nextPressed)
      onPressedChange?.(nextPressed)
    }

    return (
      <button
        ref={ref}
        type={type ?? "button"}
        data-slot="icon-toggle"
        data-variant={variant}
        data-size={size}
        data-pressed={isPressed || undefined}
        aria-pressed={isPressed}
        disabled={disabled}
        className={cn(
          iconToggleVariants({ variant, size, active: isPressed }),
          disabled && variant === "dim" && "bg_button_tertiary",
          className
        )}
        onClick={handleClick}
        {...props}
      />
    )
  }
)

IconToggle.displayName = "IconToggle"

export { IconToggle }
