import * as React from "react"
import { Slot as SlotPrimitive } from "radix-ui"
import { type VariantProps } from "class-variance-authority"

import { cn } from "@/lib/internal"
import { buttonVariants } from "./button-variants"
import { Spinner } from "./spinner"

type ButtonVariantProps = VariantProps<typeof buttonVariants>
type ButtonSize = NonNullable<ButtonVariantProps["size"]>
type LegacyButtonSize = "sm" | "default" | "lg" | "icon-sm" | "icon-md" | "icon-lg"

const legacyButtonSizeMap: Record<LegacyButtonSize, ButtonSize> = {
  sm: "s",
  default: "m",
  lg: "l",
  "icon-sm": "icon-s",
  "icon-md": "icon-m",
  "icon-lg": "icon-l",
}

const normalizeButtonSize = (size?: ButtonSize | LegacyButtonSize): ButtonSize | undefined => {
  if (!size) return undefined
  return legacyButtonSizeMap[size as LegacyButtonSize] ?? (size as ButtonSize)
}

export interface ButtonProps
  extends React.ComponentProps<"button">, Omit<ButtonVariantProps, "size"> {
  size?: ButtonSize | LegacyButtonSize
  asChild?: boolean
  loading?: boolean
}

const Button = React.forwardRef<HTMLButtonElement, ButtonProps>(
  (
    {
      className,
      variant = "primary",
      size = "m",
      asChild = false,
      loading = false,
      disabled,
      children,
      type,
      ...props
    },
    ref
  ) => {
    const Comp = asChild ? SlotPrimitive.Root : "button"
    const normalizedSize = normalizeButtonSize(size)
    const isIconOnly = normalizedSize?.startsWith("icon-") ?? false
    const ariaLabel = props["aria-label"]

    // Accessibility warning for icon-only buttons (fires only when relevant props change)
    React.useEffect(() => {
      if (import.meta.env.DEV && isIconOnly && !ariaLabel) {
        console.warn("[ui-kit/Button] Icon-only buttons should set aria-label for accessibility.")
      }
    }, [isIconOnly, ariaLabel])

    // Preserve button width during loading; hide text from screen readers (aria-busy already signals state)
    const content = loading ? (
      <>
        <span className="absolute inset-0 flex items-center justify-center">
          <Spinner variant="inherit" size="sm" />
        </span>
        {!isIconOnly && (
          <span className="opacity-0" aria-hidden="true">
            {children}
          </span>
        )}
      </>
    ) : (
      children
    )

    return (
      <Comp
        ref={ref}
        data-slot="button"
        data-variant={variant}
        data-size={normalizedSize}
        data-loading={loading || undefined}
        type={type ?? (asChild ? undefined : "button")}
        disabled={disabled || loading}
        className={cn(
          buttonVariants({ variant, size: normalizedSize }),
          loading && "relative",
          className
        )}
        aria-busy={loading}
        {...props}
      >
        {content}
      </Comp>
    )
  }
)

Button.displayName = "Button"

export { Button }
