import { cn } from "@/lib/internal"
import { Button } from "./button"
import { Select } from "./select"
import {
  paginationControlsVariants,
  paginationEllipsisVariants,
  paginationTotalVariants,
  paginationVariants,
} from "./pagination-variants"

export interface PaginationProps {
  total: number
  pageSize: number
  pageIndex: number
  onPageChange: (index: number) => void
  onPageSizeChange?: (size: number) => void
  pageSizeSuffix?: string
  pageSizeOptions?: number[]
  showSizeSelector?: boolean
  showTotal?: boolean
  siblingCount?: number
  renderTotal?: (start: number, end: number, total: number) => React.ReactNode
  className?: string
}

const getPageItems = (totalPages: number, currentPage: number, siblingCount: number) => {
  const range: Array<number | "ellipsis"> = []

  if (totalPages <= 0) return range

  const firstPage = 0
  const lastPage = totalPages - 1
  const leftSibling = Math.max(currentPage - siblingCount, firstPage)
  const rightSibling = Math.min(currentPage + siblingCount, lastPage)

  range.push(firstPage)

  if (leftSibling > firstPage + 1) {
    range.push("ellipsis")
  }

  for (let page = leftSibling; page <= rightSibling; page += 1) {
    if (page !== firstPage && page !== lastPage) {
      range.push(page)
    }
  }

  if (rightSibling < lastPage - 1) {
    range.push("ellipsis")
  }

  if (lastPage !== firstPage) {
    range.push(lastPage)
  }

  return range
}

const ChevronLeftIcon = () => (
  <svg
    viewBox="0 0 16 16"
    fill="none"
    xmlns="http://www.w3.org/2000/svg"
    aria-hidden="true"
    className="h-4 w-4"
  >
    <path
      d="M10 4L6 8L10 12"
      stroke="currentColor"
      strokeWidth="1.5"
      strokeLinecap="round"
      strokeLinejoin="round"
    />
  </svg>
)

const ChevronRightIcon = () => (
  <svg
    viewBox="0 0 16 16"
    fill="none"
    xmlns="http://www.w3.org/2000/svg"
    aria-hidden="true"
    className="h-4 w-4"
  >
    <path
      d="M6 4L10 8L6 12"
      stroke="currentColor"
      strokeWidth="1.5"
      strokeLinecap="round"
      strokeLinejoin="round"
    />
  </svg>
)

const Pagination = ({
  total,
  pageSize,
  pageIndex,
  onPageChange,
  onPageSizeChange,
  pageSizeSuffix = "",
  pageSizeOptions = [10, 20, 50, 100],
  showSizeSelector,
  showTotal = true,
  siblingCount = 1,
  renderTotal,
  className,
}: PaginationProps) => {
  const totalPages = Math.max(1, Math.ceil(total / pageSize))
  const currentPage = Math.min(Math.max(pageIndex, 0), totalPages - 1)
  const shouldShowSizeSelector = showSizeSelector ?? !!onPageSizeChange
  const pageItems = getPageItems(totalPages, currentPage, siblingCount)

  const start = total === 0 ? 0 : currentPage * pageSize + 1
  const end = total === 0 ? 0 : Math.min(total, (currentPage + 1) * pageSize)

  return (
    <div data-slot="pagination" className={cn(paginationVariants(), className)}>
      {showTotal ? (
        <span className={cn(paginationTotalVariants())}>
          {renderTotal ? renderTotal(start, end, total) : `Showing ${start}-${end} of ${total}`}
        </span>
      ) : null}

      <div className={cn(paginationControlsVariants())}>
        <Button
          variant="subtle"
          size="s"
          aria-label="Previous page"
          disabled={currentPage === 0}
          onClick={() => onPageChange(currentPage - 1)}
        >
          <ChevronLeftIcon />
        </Button>

        {pageItems.map((item, index) =>
          item === "ellipsis" ? (
            <span key={`ellipsis-${index}`} className={cn(paginationEllipsisVariants())}>
              ...
            </span>
          ) : (
            <Button
              key={item}
              variant="subtle"
              size="s"
              aria-label={`Page ${item + 1}`}
              aria-current={item === currentPage ? "page" : undefined}
              onClick={() => onPageChange(item)}
              className={cn(item === currentPage && "bg_quaternary text_primary font-semibold")}
            >
              {item + 1}
            </Button>
          )
        )}

        <Button
          variant="subtle"
          size="s"
          aria-label="Next page"
          disabled={currentPage === totalPages - 1}
          onClick={() => onPageChange(currentPage + 1)}
        >
          <ChevronRightIcon />
        </Button>
      </div>

      {shouldShowSizeSelector && onPageSizeChange ? (
        <Select
          options={pageSizeOptions.map((size) => ({
            value: String(size),
            label: pageSizeSuffix ? `${size} ${pageSizeSuffix}` : String(size),
          }))}
          value={String(pageSize)}
          onValueChange={(next) => {
            if (Array.isArray(next)) return
            const parsed = Number(next)
            if (!Number.isNaN(parsed)) {
              onPageSizeChange(parsed)
            }
          }}
          placeholder="Size"
          size="s"
          className="w-auto min-w-[72px]"
        />
      ) : null}
    </div>
  )
}

Pagination.displayName = "Pagination"

export { Pagination }
