import * as React from "react"
import { Popover } from "radix-ui"
import { useVirtualizer } from "@tanstack/react-virtual"

import { cn } from "@/lib/internal"
import { inputVariants } from "./input-variants"
import { Spinner } from "./spinner"
import {
  selectContentVariants,
  selectOptionVariants,
  selectTagVariants,
  selectTriggerVariants,
} from "./select-variants"

export interface SelectOption {
  value: string
  label: string
  description?: string
  icon?: React.ReactNode
  disabled?: boolean
  group?: string
}

export interface SelectGroup {
  label: string
  key: string
}

export interface SelectProps {
  options: SelectOption[]
  groups?: SelectGroup[]
  value?: string | string[]
  defaultValue?: string | string[]
  onValueChange?: (value: string | string[]) => void
  multiple?: boolean
  searchable?: boolean
  clearable?: boolean
  disabled?: boolean
  required?: boolean
  name?: string
  placeholder?: string
  searchPlaceholder?: string
  emptyMessage?: string
  loadingMessage?: string
  preparingMessage?: string
  onSearch?: (query: string) => Promise<SelectOption[]>
  maxDisplayedTags?: number
  loading?: boolean
  overflowLabel?: (count: number) => string
  size?: "xs" | "s" | "m" | "l" | "xl"
  variant?: "light" | "fill" | "dim" | "borderless"
  validation?: "error"
  portalContainer?: HTMLElement | null
  id?: string
  "aria-describedby"?: string
  "aria-invalid"?: React.AriaAttributes["aria-invalid"]
  className?: string
}

const getFirstEnabledIndex = (items: SelectOption[]) => items.findIndex((item) => !item.disabled)
const getLastEnabledIndex = (items: SelectOption[]) => {
  for (let index = items.length - 1; index >= 0; index -= 1) {
    if (!items[index]?.disabled) return index
  }
  return -1
}

const ChevronDownIcon = ({ open }: { open: boolean }) => (
  <svg
    viewBox="0 0 16 16"
    fill="none"
    xmlns="http://www.w3.org/2000/svg"
    aria-hidden="true"
    className={cn("h-4 w-4 icon_secondary transition-transform", open && "rotate-180")}
  >
    <path
      d="M4 6L8 10L12 6"
      stroke="currentColor"
      strokeWidth="1.5"
      strokeLinecap="round"
      strokeLinejoin="round"
    />
  </svg>
)

const CheckIcon = () => (
  <svg
    viewBox="0 0 16 16"
    fill="none"
    xmlns="http://www.w3.org/2000/svg"
    aria-hidden="true"
    className="h-4 w-4"
  >
    <path
      d="M12.5 4.5L6.5 10.5L3.5 7.5"
      stroke="currentColor"
      strokeWidth="1.5"
      strokeLinecap="round"
      strokeLinejoin="round"
    />
  </svg>
)

const sizeMinHeightMap: Record<NonNullable<SelectProps["size"]>, string> = {
  xs: "min-h-8",
  s: "min-h-9",
  m: "min-h-10",
  l: "min-h-12",
  xl: "min-h-14",
}

const isAriaInvalid = (value: SelectProps["aria-invalid"]) => value === true || value === "true"

const Select = React.forwardRef<HTMLDivElement, SelectProps>(
  (
    {
      options,
      groups,
      value,
      defaultValue,
      onValueChange,
      multiple = false,
      searchable,
      clearable = false,
      disabled = false,
      required = false,
      name,
      placeholder = "Select...",
      searchPlaceholder = "Search...",
      emptyMessage = "No options found",
      loadingMessage = "Loading...",
      preparingMessage = "Preparing options...",
      onSearch,
      maxDisplayedTags,
      loading = false,
      overflowLabel = (count) => `+${count} more`,
      size = "m",
      variant = "light",
      validation,
      portalContainer = null,
      id,
      "aria-describedby": ariaDescribedBy,
      "aria-invalid": ariaInvalid,
      className,
    },
    ref
  ) => {
    const isControlled = value !== undefined
    const [open, setOpen] = React.useState(false)
    const [searchQuery, setSearchQuery] = React.useState("")
    const [focusedIndex, setFocusedIndex] = React.useState(-1)
    const [internalValue, setInternalValue] = React.useState<string | string[]>(
      defaultValue ?? (multiple ? [] : "")
    )
    const [contentWidth, setContentWidth] = React.useState<number>()
    const [asyncOptions, setAsyncOptions] = React.useState<SelectOption[]>([])
    const [asyncLoading, setAsyncLoading] = React.useState(false)
    const debounceTimerRef = React.useRef<ReturnType<typeof setTimeout> | null>(null)
    const triggerRef = React.useRef<HTMLDivElement | null>(null)
    const searchInputRef = React.useRef<HTMLInputElement | null>(null)
    const listRef = React.useRef<HTMLDivElement | null>(null)
    const optionIdPrefix = React.useId()

    const mergedRef = React.useCallback(
      (node: HTMLDivElement | null) => {
        triggerRef.current = node
        if (typeof ref === "function") {
          ref(node)
        } else if (ref) {
          ref.current = node
        }
      },
      [ref]
    )

    const isSearchEnabled = onSearch != null || (searchable ?? options.length > 10)
    const selectedValue = isControlled ? value : internalValue
    const normalizedMultiValue = React.useMemo(
      () =>
        multiple
          ? Array.isArray(selectedValue)
            ? selectedValue
            : selectedValue
              ? [selectedValue]
              : []
          : [],
      [multiple, selectedValue]
    )
    const normalizedSingleValue = React.useMemo(
      () =>
        multiple
          ? ""
          : Array.isArray(selectedValue)
            ? (selectedValue[0] ?? "")
            : (selectedValue ?? ""),
      [multiple, selectedValue]
    )
    const hasValue = multiple ? normalizedMultiValue.length > 0 : !!normalizedSingleValue

    const optionsByValue = React.useMemo(
      () => new Map(options.map((option) => [option.value, option])),
      [options]
    )

    const selectedOptions = multiple
      ? normalizedMultiValue
          .map((item) => optionsByValue.get(item))
          .filter((option): option is SelectOption => !!option)
      : []
    const selectedOption = multiple ? undefined : optionsByValue.get(normalizedSingleValue)
    const tagsToShow =
      maxDisplayedTags !== undefined ? selectedOptions.slice(0, maxDisplayedTags) : selectedOptions
    const hiddenCount =
      maxDisplayedTags !== undefined ? Math.max(0, selectedOptions.length - maxDisplayedTags) : 0

    const filteredOptions = React.useMemo(() => {
      if (onSearch) {
        return searchQuery.trim() ? asyncOptions : options
      }
      const query = searchQuery.trim().toLowerCase()
      if (!query) return options
      return options.filter((option) => option.label.toLowerCase().includes(query))
    }, [onSearch, searchQuery, asyncOptions, options])

    const displayOptions = React.useMemo(() => {
      if (!groups || groups.length === 0) {
        return filteredOptions
      }

      const declaredGroupKeys = new Set(groups.map((group) => group.key))
      const groupedOptions = groups.flatMap((group) =>
        filteredOptions.filter((option) => option.group === group.key)
      )
      const ungroupedOptions = filteredOptions.filter(
        (option) => !option.group || !declaredGroupKeys.has(option.group)
      )

      return [...groupedOptions, ...ungroupedOptions]
    }, [filteredOptions, groups])

    const displayOptionIndexes = React.useMemo(
      () => new Map(displayOptions.map((option, index) => [option.value, index])),
      [displayOptions]
    )

    const shouldVirtualize = displayOptions.length > 100 && !(groups && groups.length > 0)

    const rowVirtualizer = useVirtualizer({
      count: shouldVirtualize ? displayOptions.length : 0,
      getScrollElement: () => listRef.current,
      estimateSize: (index) => (displayOptions[index]?.description ? 64 : 48),
      overscan: 8,
    })

    const setValue = React.useCallback(
      (next: string | string[]) => {
        if (!isControlled) {
          setInternalValue(next)
        }
        onValueChange?.(next)
      },
      [isControlled, onValueChange]
    )

    const clearValue = React.useCallback(() => {
      setValue(multiple ? [] : "")
      setSearchQuery("")
    }, [multiple, setValue])

    const selectOption = React.useCallback(
      (option: SelectOption) => {
        if (option.disabled) return

        if (multiple) {
          const next = normalizedMultiValue.includes(option.value)
            ? normalizedMultiValue.filter((item) => item !== option.value)
            : [...normalizedMultiValue, option.value]
          setValue(next)
          return
        }

        setValue(option.value)
        setOpen(false)
      },
      [multiple, normalizedMultiValue, setValue]
    )

    const moveFocusedIndex = React.useCallback(
      (direction: 1 | -1) => {
        if (!displayOptions.length) return

        let next = focusedIndex
        for (let i = 0; i < displayOptions.length; i += 1) {
          next = (next + direction + displayOptions.length) % displayOptions.length
          if (!displayOptions[next]?.disabled) {
            setFocusedIndex(next)
            break
          }
        }
      },
      [displayOptions, focusedIndex]
    )

    const focusFirstOption = React.useCallback(() => {
      setFocusedIndex(getFirstEnabledIndex(displayOptions))
    }, [displayOptions])

    const focusLastOption = React.useCallback(() => {
      setFocusedIndex(getLastEnabledIndex(displayOptions))
    }, [displayOptions])

    const removeLastSelected = React.useCallback(() => {
      if (!multiple || normalizedMultiValue.length === 0) return
      setValue(normalizedMultiValue.slice(0, -1))
    }, [multiple, normalizedMultiValue, setValue])

    const removeOption = React.useCallback(
      (optionValue: string) => {
        setValue(normalizedMultiValue.filter((item) => item !== optionValue))
      },
      [normalizedMultiValue, setValue]
    )

    React.useEffect(() => {
      if (!open) {
        setSearchQuery("")
        return
      }

      setContentWidth(triggerRef.current?.getBoundingClientRect().width)
      setFocusedIndex(getFirstEnabledIndex(displayOptions))
      if (isSearchEnabled) {
        requestAnimationFrame(() => {
          searchInputRef.current?.focus()
        })
      }
    }, [displayOptions, isSearchEnabled, open])

    React.useEffect(() => {
      if (!open || !shouldVirtualize) return

      // Run a double measure on open to stabilize the first paint
      // when popover/list container dimensions settle across frames.
      let frameA = 0
      let frameB = 0

      frameA = requestAnimationFrame(() => {
        rowVirtualizer.measure()
        frameB = requestAnimationFrame(() => {
          rowVirtualizer.measure()
        })
      })

      return () => {
        cancelAnimationFrame(frameA)
        cancelAnimationFrame(frameB)
      }
    }, [open, rowVirtualizer, shouldVirtualize, displayOptions.length])

    React.useEffect(() => {
      if (!onSearch) return

      if (debounceTimerRef.current) {
        clearTimeout(debounceTimerRef.current)
      }

      if (!searchQuery.trim()) {
        setAsyncOptions([])
        setAsyncLoading(false)
        return
      }

      setAsyncLoading(true)
      let cancelled = false
      debounceTimerRef.current = setTimeout(() => {
        onSearch(searchQuery)
          .then((results) => {
            if (!cancelled) setAsyncOptions(results)
          })
          .catch(() => {
            if (!cancelled) setAsyncOptions([])
          })
          .finally(() => {
            if (!cancelled) setAsyncLoading(false)
          })
      }, 300)

      return () => {
        cancelled = true
        if (debounceTimerRef.current) {
          clearTimeout(debounceTimerRef.current)
        }
      }
    }, [searchQuery, onSearch])

    const onTriggerKeyDown: React.KeyboardEventHandler<HTMLDivElement> = (event) => {
      if (disabled) return

      if ((event.key === "Tab" || event.key === "Enter" || event.key === " ") && !open) {
        if (event.key !== "Tab") {
          event.preventDefault()
        }
        setOpen(true)
        return
      }

      if (event.key === "ArrowDown") {
        event.preventDefault()
        if (!open) {
          setOpen(true)
          return
        }
        moveFocusedIndex(1)
        return
      }

      if (event.key === "ArrowUp") {
        event.preventDefault()
        if (!open) {
          setOpen(true)
          return
        }
        moveFocusedIndex(-1)
        return
      }

      if (event.key === "Home" && open) {
        event.preventDefault()
        focusFirstOption()
        return
      }

      if (event.key === "End" && open) {
        event.preventDefault()
        focusLastOption()
        return
      }

      if (event.key === "Enter" && open && focusedIndex >= 0) {
        event.preventDefault()
        const option = displayOptions[focusedIndex]
        if (option) {
          selectOption(option)
        }
        return
      }

      if (event.key === "Escape" && open) {
        event.preventDefault()
        setOpen(false)
        return
      }

      if (event.key === "Backspace" && multiple && searchQuery.length === 0) {
        removeLastSelected()
      }
    }

    const onListKeyDown: React.KeyboardEventHandler<HTMLDivElement> = (event) => {
      if (event.key === "ArrowDown") {
        event.preventDefault()
        moveFocusedIndex(1)
        return
      }

      if (event.key === "Home") {
        event.preventDefault()
        focusFirstOption()
        return
      }

      if (event.key === "End") {
        event.preventDefault()
        focusLastOption()
        return
      }

      if (event.key === "ArrowUp") {
        event.preventDefault()
        moveFocusedIndex(-1)
        return
      }

      if (event.key === "Enter" && focusedIndex >= 0) {
        event.preventDefault()
        const option = displayOptions[focusedIndex]
        if (option) {
          selectOption(option)
        }
        return
      }

      if (event.key === "Escape") {
        event.preventDefault()
        setOpen(false)
      }
    }

    const renderOption = (option: SelectOption, index: number) => {
      const isSelected = multiple
        ? normalizedMultiValue.includes(option.value)
        : normalizedSingleValue === option.value
      const isFocused = index === focusedIndex
      const id = `${optionIdPrefix}-${option.value}`

      return (
        <div
          key={option.value}
          id={id}
          role="option"
          aria-selected={isSelected}
          data-focused={isFocused}
          data-disabled={option.disabled}
          onMouseEnter={() => setFocusedIndex(index)}
          onMouseDown={(event) => {
            event.preventDefault()
            selectOption(option)
          }}
          className={cn(
            selectOptionVariants({
              selected: isSelected,
              focused: isFocused,
              disabled: !!option.disabled,
            })
          )}
        >
          {option.icon}
          <span className="flex flex-col">
            <span>{option.label}</span>
            {option.description ? (
              <span className="text-xs text_tertiary">{option.description}</span>
            ) : null}
          </span>
          {isSelected ? (
            <span className="ml-auto icon_secondary" aria-hidden="true">
              <CheckIcon />
            </span>
          ) : null}
        </div>
      )
    }

    const renderOptionList = () => {
      if (loading || asyncLoading) {
        return (
          <div className="flex items-center gap-2 px-3 py-2 text-sm text_secondary">
            <Spinner size="sm" />
            <span>{loadingMessage}</span>
          </div>
        )
      }

      if (!displayOptions.length) {
        return <div className="px-3 py-2 text-sm text_secondary">{emptyMessage}</div>
      }

      if (shouldVirtualize) {
        const virtualItems = rowVirtualizer.getVirtualItems()
        if (virtualItems.length === 0 && displayOptions.length > 0) {
          return (
            <div className="flex items-center gap-2 px-3 py-2 text-sm text_secondary">
              <Spinner size="sm" />
              <span>{preparingMessage}</span>
            </div>
          )
        }

        return (
          <div style={{ height: `${rowVirtualizer.getTotalSize()}px`, position: "relative" }}>
            {virtualItems.map((virtualItem) => {
              const option = displayOptions[virtualItem.index]
              if (!option) return null
              return (
                <div
                  key={option.value}
                  style={{
                    position: "absolute",
                    top: 0,
                    left: 0,
                    width: "100%",
                    transform: `translateY(${virtualItem.start}px)`,
                  }}
                >
                  {renderOption(option, virtualItem.index)}
                </div>
              )
            })}
          </div>
        )
      }

      if (groups && groups.length > 0) {
        const grouped = groups
          .map((group) => ({
            group,
            options: filteredOptions.filter((option) => option.group === group.key),
          }))
          .filter((entry) => entry.options.length > 0)
        const declaredGroupKeys = new Set(groups.map((group) => group.key))
        const ungroupedOptions = filteredOptions.filter(
          (option) => !option.group || !declaredGroupKeys.has(option.group)
        )

        return (
          <>
            {grouped.map(({ group, options: groupOptions }) => (
              <div key={group.key}>
                <div className="px-3 pb-1 pt-2 text-xs font-semibold text_tertiary">
                  {group.label}
                </div>
                {groupOptions.map((option) => {
                  return renderOption(option, displayOptionIndexes.get(option.value) ?? -1)
                })}
              </div>
            ))}
            {ungroupedOptions.length > 0 ? (
              <div>
                {ungroupedOptions.map((option) => {
                  return renderOption(option, displayOptionIndexes.get(option.value) ?? -1)
                })}
              </div>
            ) : null}
          </>
        )
      }

      return displayOptions.map((option, index) => renderOption(option, index))
    }

    const activeDescendant =
      focusedIndex >= 0 && displayOptions[focusedIndex]
        ? `${optionIdPrefix}-${displayOptions[focusedIndex]?.value}`
        : undefined
    const resolvedValidation =
      validation === "error" || isAriaInvalid(ariaInvalid) ? "error" : undefined

    return (
      <>
        {name ? (
          <input
            type="hidden"
            name={name}
            required={required}
            value={multiple ? normalizedMultiValue.join(",") : normalizedSingleValue}
          />
        ) : null}
        <Popover.Root open={open} onOpenChange={(nextOpen) => !disabled && setOpen(nextOpen)}>
          <Popover.Trigger asChild>
            <div
              ref={mergedRef}
              id={id}
              role="combobox"
              tabIndex={disabled ? -1 : 0}
              aria-expanded={open}
              aria-haspopup="listbox"
              aria-controls={`${optionIdPrefix}-listbox`}
              aria-activedescendant={!isSearchEnabled ? activeDescendant : undefined}
              aria-describedby={ariaDescribedBy}
              aria-invalid={validation === "error" ? true : ariaInvalid || undefined}
              aria-disabled={disabled || undefined}
              data-slot="select-trigger"
              data-size={size}
              data-variant={variant}
              data-open={open}
              onKeyDown={onTriggerKeyDown}
              className={cn(
                inputVariants({ variant, size, validation: resolvedValidation }),
                selectTriggerVariants(),
                multiple && [sizeMinHeightMap[size ?? "m"], "h-auto"],
                hasValue ? "text_primary" : "text_tertiary",
                className
              )}
            >
              <span className="flex flex-1 flex-wrap items-center gap-1 py-1">
                {multiple ? (
                  selectedOptions.length > 0 ? (
                    <>
                      {tagsToShow.map((option) => (
                        <span key={option.value} className={cn(selectTagVariants())}>
                          {option.icon && <span className="flex-shrink-0">{option.icon}</span>}
                          <span>{option.label}</span>
                          {!disabled ? (
                            <span
                              role="button"
                              tabIndex={0}
                              aria-label={`Remove ${option.label}`}
                              onMouseDown={(event) => {
                                event.preventDefault()
                                event.stopPropagation()
                                removeOption(option.value)
                              }}
                              onKeyDown={(event) => {
                                if (event.key === "Enter" || event.key === " ") {
                                  event.preventDefault()
                                  event.stopPropagation()
                                  removeOption(option.value)
                                }
                              }}
                              className="inline-flex cursor-pointer items-center justify-center text_tertiary hover:text_primary"
                            >
                              &times;
                            </span>
                          ) : null}
                        </span>
                      ))}
                      {hiddenCount > 0 ? (
                        <span className="text-xs text_secondary">{overflowLabel(hiddenCount)}</span>
                      ) : null}
                    </>
                  ) : (
                    <span className="truncate">{placeholder}</span>
                  )
                ) : selectedOption ? (
                  <span className="truncate">{selectedOption.label}</span>
                ) : (
                  <span className="truncate">{placeholder}</span>
                )}
              </span>
              {clearable && hasValue && !disabled ? (
                <span
                  role="button"
                  tabIndex={0}
                  aria-label="Clear selection"
                  onMouseDown={(event) => {
                    event.preventDefault()
                    event.stopPropagation()
                    clearValue()
                  }}
                  onKeyDown={(event) => {
                    if (event.key === "Enter" || event.key === " ") {
                      event.preventDefault()
                      event.stopPropagation()
                      clearValue()
                    }
                  }}
                  className="inline-flex h-4 w-4 items-center justify-center text_secondary hover:text_primary"
                >
                  ×
                </span>
              ) : null}
              <ChevronDownIcon open={open} />
            </div>
          </Popover.Trigger>
          <Popover.Portal container={portalContainer ?? undefined}>
            <Popover.Content
              align="start"
              sideOffset={8}
              onOpenAutoFocus={(event) => event.preventDefault()}
              onCloseAutoFocus={(event) => {
                event.preventDefault()
                triggerRef.current?.focus()
              }}
              style={{ width: contentWidth }}
              className={cn(selectContentVariants())}
            >
              {isSearchEnabled ? (
                <div className="p-1">
                  <input
                    ref={searchInputRef}
                    aria-label={searchPlaceholder}
                    role="combobox"
                    aria-expanded={open}
                    aria-controls={`${optionIdPrefix}-listbox`}
                    aria-activedescendant={activeDescendant}
                    value={searchQuery}
                    onChange={(event) => setSearchQuery(event.target.value)}
                    onKeyDown={(event) => {
                      if (event.key === "ArrowDown" || event.key === "ArrowUp") {
                        event.preventDefault()
                        moveFocusedIndex(event.key === "ArrowDown" ? 1 : -1)
                        return
                      }
                      if (event.key === "Home") {
                        event.preventDefault()
                        focusFirstOption()
                        return
                      }
                      if (event.key === "End") {
                        event.preventDefault()
                        focusLastOption()
                        return
                      }
                      if (event.key === "Enter" && focusedIndex >= 0) {
                        event.preventDefault()
                        const option = displayOptions[focusedIndex]
                        if (option) {
                          selectOption(option)
                        }
                        return
                      }
                      if (event.key === "Escape") {
                        event.preventDefault()
                        setOpen(false)
                        return
                      }
                      if (event.key === "Backspace" && searchQuery.length === 0) {
                        removeLastSelected()
                      }
                    }}
                    placeholder={searchPlaceholder}
                    className={cn(inputVariants({ variant, size: "s" }))}
                  />
                </div>
              ) : null}
              <div
                id={`${optionIdPrefix}-listbox`}
                ref={listRef}
                role="listbox"
                aria-multiselectable={multiple || undefined}
                tabIndex={-1}
                onKeyDown={onListKeyDown}
                className="max-h-60 overflow-auto p-1"
              >
                {renderOptionList()}
              </div>
            </Popover.Content>
          </Popover.Portal>
        </Popover.Root>
      </>
    )
  }
)

Select.displayName = "Select"

export { Select }
