import * as React from "react"
import { ChevronLeft, ChevronRight } from "lucide-react"

import { cn } from "@/lib/internal"
import { calendarDayVariants } from "./calendar-variants"

export interface DateRange {
  from?: Date
  to?: Date
}

export type DayDecoratorRule =
  | {
      type: "range"
      from: Date
      to: Date
      icon?: React.ReactNode
      backgroundClass?: string
      display?: "below" | "background"
    }
  | {
      type: "weekly"
      weekdays: number[]
      icon?: React.ReactNode
      backgroundClass?: string
      display?: "below" | "background"
    }
  | {
      type: "yearly"
      month: number
      day: number
      icon?: React.ReactNode
      backgroundClass?: string
      display?: "below" | "background"
    }

interface CalendarBaseProps {
  minDate?: Date
  maxDate?: Date
  disabledDates?: Date[] | ((date: Date) => boolean)
  dayDecorators?: DayDecoratorRule[]
  weekDayLabels?: [string, string, string, string, string, string, string]
  className?: string
}

interface CalendarSingleProps extends CalendarBaseProps {
  mode?: "single"
  value?: Date
  defaultValue?: Date
  onValueChange?: (date: Date) => void
}

interface CalendarRangeProps extends CalendarBaseProps {
  mode: "range"
  value?: DateRange
  defaultValue?: DateRange
  onValueChange?: (range: DateRange) => void
}

export type CalendarProps = CalendarSingleProps | CalendarRangeProps

type CalendarDayStatus =
  | "default"
  | "selected"
  | "today"
  | "outside"
  | "disabled"
  | "range-middle"
  | "range-hover"

const weekDays: [string, string, string, string, string, string, string] = [
  "Mon",
  "Tue",
  "Wed",
  "Thu",
  "Fri",
  "Sat",
  "Sun",
]

const normalizeDate = (date: Date) => new Date(date.getFullYear(), date.getMonth(), date.getDate())

const getDaysInMonth = (year: number, month: number) => new Date(year, month + 1, 0).getDate()

const getFirstDayOfMonth = (year: number, month: number) => {
  const day = new Date(year, month, 1).getDay()
  return day === 0 ? 6 : day - 1
}

const isSameDay = (a: Date, b: Date) =>
  a.getFullYear() === b.getFullYear() &&
  a.getMonth() === b.getMonth() &&
  a.getDate() === b.getDate()

const getDecoratorDisplay = (rule: DayDecoratorRule) => rule.display ?? "below"

const matchesRule = (rule: DayDecoratorRule, date: Date): boolean => {
  const normalizedDate = normalizeDate(date)

  switch (rule.type) {
    case "range": {
      const fromTime = normalizeDate(rule.from).getTime()
      const toTime = normalizeDate(rule.to).getTime()
      const minTime = Math.min(fromTime, toTime)
      const maxTime = Math.max(fromTime, toTime)
      const dateTime = normalizedDate.getTime()
      return dateTime >= minTime && dateTime <= maxTime
    }
    case "weekly":
      return rule.weekdays.includes(normalizedDate.getDay())
    case "yearly":
      return normalizedDate.getMonth() === rule.month && normalizedDate.getDate() === rule.day
  }
}

const isBackgroundDecoratableStatus = (status: CalendarDayStatus) =>
  status === "default" || status === "outside" || status === "today"

const startOfMonth = (date: Date) => new Date(date.getFullYear(), date.getMonth(), 1)

const getMonthDays = (year: number, month: number) => {
  const daysInMonth = getDaysInMonth(year, month)
  const firstDayOffset = getFirstDayOfMonth(year, month)
  const daysInPrevMonth = getDaysInMonth(year, month - 1)

  return Array.from({ length: 42 }, (_, index) => {
    if (index < firstDayOffset) {
      const day = daysInPrevMonth - firstDayOffset + index + 1
      return { date: new Date(year, month - 1, day), outside: true }
    }

    if (index >= firstDayOffset + daysInMonth) {
      const day = index - (firstDayOffset + daysInMonth) + 1
      return { date: new Date(year, month + 1, day), outside: true }
    }

    const day = index - firstDayOffset + 1
    return { date: new Date(year, month, day), outside: false }
  })
}

interface CalendarMonthGridProps {
  year: number
  month: number
  showPrevButton: boolean
  showNextButton: boolean
  onPrev: () => void
  onNext: () => void
  dayDecorators?: DayDecoratorRule[]
  weekDayLabels: [string, string, string, string, string, string, string]
  renderDay: (date: Date, outside: boolean, hasAnyBelowDecorator: boolean) => React.ReactNode
}

const CalendarMonthGrid = ({
  year,
  month,
  showPrevButton,
  showNextButton,
  onPrev,
  onNext,
  dayDecorators,
  weekDayLabels,
  renderDay,
}: CalendarMonthGridProps) => {
  const monthLabel = `${String(month + 1).padStart(2, "0")}/${year}`
  const monthDays = React.useMemo(() => getMonthDays(year, month), [month, year])
  const hasAnyBelowDecorator = React.useMemo(() => {
    if (!dayDecorators?.length) {
      return false
    }

    return monthDays.some(({ date }) =>
      dayDecorators.some((rule) => getDecoratorDisplay(rule) === "below" && matchesRule(rule, date))
    )
  }, [dayDecorators, monthDays])

  return (
    <div className="flex flex-col gap-3">
      <div className="flex items-center justify-between gap-2">
        {showPrevButton ? (
          <button
            type="button"
            data-slot="calendar-prev"
            onClick={onPrev}
            className="inline-flex items-center justify-center h-8 w-8 radius_6 hover:state_bg_button_tertiary_soft text_secondary cursor-pointer"
            aria-label="Previous month"
          >
            <ChevronLeft className="h-4 w-4" />
          </button>
        ) : (
          <span className="h-8 w-8" aria-hidden="true" />
        )}

        <p className="text-sm font-semibold text_primary capitalize">{monthLabel}</p>

        {showNextButton ? (
          <button
            type="button"
            data-slot="calendar-next"
            onClick={onNext}
            className="inline-flex items-center justify-center h-8 w-8 radius_6 hover:state_bg_button_tertiary_soft text_secondary cursor-pointer"
            aria-label="Next month"
          >
            <ChevronRight className="h-4 w-4" />
          </button>
        ) : (
          <span className="h-8 w-8" aria-hidden="true" />
        )}
      </div>

      <div className="grid grid-cols-7 gap-1">
        {weekDayLabels.map((day) => (
          <div
            key={day}
            className="h-8 w-8 inline-flex items-center justify-center text-xs text_tertiary"
          >
            {day}
          </div>
        ))}
      </div>

      <div className="grid grid-cols-7 gap-1">
        {monthDays.map(({ date, outside }) => renderDay(date, outside, hasAnyBelowDecorator))}
      </div>
    </div>
  )
}

const Calendar = React.forwardRef<HTMLDivElement, CalendarProps>((props, ref) => {
  const { minDate, maxDate, disabledDates, dayDecorators, weekDayLabels, className } = props
  const resolvedWeekDayLabels = weekDayLabels ?? weekDays
  const singleProps = props.mode === "range" ? undefined : props
  const rangeProps = props.mode === "range" ? props : undefined
  const isRangeMode = !!rangeProps

  const [internalValue, setInternalValue] = React.useState<Date | undefined>(
    singleProps?.defaultValue
  )
  const [internalRange, setInternalRange] = React.useState<DateRange>(
    rangeProps?.defaultValue ?? {}
  )

  const isSingleControlled = !isRangeMode && singleProps?.value !== undefined
  const isRangeControlled = isRangeMode && rangeProps?.value !== undefined

  const selectedDate = !isRangeMode
    ? isSingleControlled
      ? singleProps?.value
      : internalValue
    : undefined

  const selectedRange = React.useMemo(
    () =>
      isRangeMode ? (isRangeControlled ? (rangeProps?.value ?? {}) : internalRange) : undefined,
    [internalRange, isRangeControlled, isRangeMode, rangeProps?.value]
  )

  const [viewMonth, setViewMonth] = React.useState<Date>(() => {
    if (isRangeMode) {
      const anchorDate =
        rangeProps?.value?.from ??
        rangeProps?.defaultValue?.from ??
        rangeProps?.value?.to ??
        rangeProps?.defaultValue?.to ??
        new Date()

      return startOfMonth(anchorDate)
    }

    return startOfMonth(singleProps?.value ?? singleProps?.defaultValue ?? new Date())
  })

  React.useEffect(() => {
    if (isRangeMode) {
      const anchorDate = rangeProps?.value?.from ?? rangeProps?.value?.to
      if (anchorDate) {
        setViewMonth(startOfMonth(anchorDate))
      }
      return
    }

    if (singleProps?.value) {
      setViewMonth(startOfMonth(singleProps.value))
    }
  }, [isRangeMode, rangeProps?.value, singleProps?.value])

  const [rangePhase, setRangePhase] = React.useState<"idle" | "selecting">(() => {
    const initialRange = rangeProps?.value ?? rangeProps?.defaultValue
    return initialRange?.from && !initialRange?.to ? "selecting" : "idle"
  })
  const [hoverDate, setHoverDate] = React.useState<Date | null>(null)

  React.useEffect(() => {
    if (!isRangeMode) {
      setRangePhase("idle")
      setHoverDate(null)
      return
    }

    const current = isRangeControlled ? (rangeProps?.value ?? {}) : internalRange
    setRangePhase(current.from && !current.to ? "selecting" : "idle")
  }, [internalRange, isRangeControlled, isRangeMode, rangeProps?.value])

  const normalizedMinDate = React.useMemo(
    () => (minDate ? normalizeDate(minDate) : undefined),
    [minDate]
  )
  const normalizedMaxDate = React.useMemo(
    () => (maxDate ? normalizeDate(maxDate) : undefined),
    [maxDate]
  )

  const isDisabled = React.useCallback(
    (date: Date) => {
      const normalizedDate = normalizeDate(date)

      if (normalizedMinDate && normalizedDate.getTime() < normalizedMinDate.getTime()) {
        return true
      }

      if (normalizedMaxDate && normalizedDate.getTime() > normalizedMaxDate.getTime()) {
        return true
      }

      if (Array.isArray(disabledDates)) {
        return disabledDates.some((disabledDate) =>
          isSameDay(normalizeDate(disabledDate), normalizedDate)
        )
      }

      if (typeof disabledDates === "function") {
        return disabledDates(normalizedDate)
      }

      return false
    },
    [disabledDates, normalizedMaxDate, normalizedMinDate]
  )

  const today = React.useMemo(() => normalizeDate(new Date()), [])

  const handleSingleSelect = React.useCallback(
    (date: Date) => {
      if (isDisabled(date)) {
        return
      }

      if (!isSingleControlled) {
        setInternalValue(date)
      }

      singleProps?.onValueChange?.(date)
      setViewMonth(startOfMonth(date))
    },
    [isDisabled, isSingleControlled, singleProps]
  )

  const handleRangeClick = React.useCallback(
    (date: Date) => {
      if (isDisabled(date)) return

      const current = isRangeControlled ? (rangeProps?.value ?? {}) : internalRange

      if (rangePhase === "idle" || (current.from && current.to)) {
        setRangePhase("selecting")
        setHoverDate(null)
        const next: DateRange = { from: date, to: undefined }
        if (!isRangeControlled) setInternalRange(next)
        else rangeProps?.onValueChange?.(next)
        return
      }

      setRangePhase("idle")
      const from = normalizeDate(current.from!)
      const next: DateRange = date < from ? { from: date, to: from } : { from, to: date }
      if (!isRangeControlled) setInternalRange(next)
      rangeProps?.onValueChange?.(next)
    },
    [internalRange, isDisabled, isRangeControlled, rangePhase, rangeProps]
  )

  const getRangeDayStatus = React.useCallback(
    (
      date: Date,
      from: Date | undefined,
      to: Date | undefined,
      hover: Date | null,
      outside: boolean
    ): CalendarDayStatus => {
      if (isDisabled(date)) return "disabled"

      const effectiveTo = to ?? (from && hover && hover >= from ? hover : undefined)

      if (from && isSameDay(date, from)) return "selected"
      if (effectiveTo && isSameDay(date, effectiveTo)) return "selected"
      if (from && effectiveTo && date > from && date < effectiveTo) return "range-middle"
      if (!to && from && hover && date > from && date < hover) return "range-hover"
      if (outside) return "outside"
      if (isSameDay(date, today)) return "today"
      return "default"
    },
    [isDisabled, today]
  )

  const renderSingleDay = React.useCallback(
    (date: Date, outside: boolean, hasAnyBelowDecorator: boolean) => {
      const normalizedDate = normalizeDate(date)
      const dayKey = normalizedDate.toISOString()
      const disabled = isDisabled(normalizedDate)
      const selected = !!selectedDate && isSameDay(normalizeDate(selectedDate), normalizedDate)
      const isToday = isSameDay(today, normalizedDate)
      const matchingDecorators =
        dayDecorators?.filter((rule) => matchesRule(rule, normalizedDate)) ?? []
      const belowDecorators = matchingDecorators.filter(
        (decorator) => getDecoratorDisplay(decorator) === "below" && decorator.icon
      )

      let backgroundClass: string | undefined
      for (const decorator of matchingDecorators) {
        if (getDecoratorDisplay(decorator) === "background" && decorator.backgroundClass) {
          backgroundClass = decorator.backgroundClass
        }
      }

      let status: CalendarDayStatus = "default"
      if (disabled) {
        status = "disabled"
      } else if (selected) {
        status = "selected"
      } else if (isToday) {
        status = "today"
      } else if (outside) {
        status = "outside"
      }

      return (
        <button
          key={dayKey}
          type="button"
          data-slot="calendar-day"
          disabled={disabled}
          onClick={() => handleSingleSelect(normalizedDate)}
          className={cn(
            calendarDayVariants({ status }),
            hasAnyBelowDecorator && "h-10",
            belowDecorators.length > 0 && "flex-col gap-0",
            isBackgroundDecoratableStatus(status) && backgroundClass
          )}
        >
          <span>{normalizedDate.getDate()}</span>
          {belowDecorators.length > 0 ? (
            <span className="mt-0.5 flex h-3 items-center justify-center gap-0.5">
              {belowDecorators.map((decorator, index) => (
                <span
                  key={`${dayKey}-decorator-${index}`}
                  className="inline-flex h-3 w-3 items-center justify-center"
                >
                  {decorator.icon}
                </span>
              ))}
            </span>
          ) : null}
        </button>
      )
    },
    [dayDecorators, handleSingleSelect, isDisabled, selectedDate, today]
  )

  const normalizedHoverDate = hoverDate ? normalizeDate(hoverDate) : null

  const renderRangeDay = React.useCallback(
    (date: Date, outside: boolean, hasAnyBelowDecorator: boolean) => {
      const normalizedDate = normalizeDate(date)
      const dayKey = normalizedDate.toISOString()
      const from = selectedRange?.from ? normalizeDate(selectedRange.from) : undefined
      const to = selectedRange?.to ? normalizeDate(selectedRange.to) : undefined
      const status = getRangeDayStatus(normalizedDate, from, to, normalizedHoverDate, outside)
      const effectiveTo =
        to ??
        (from && normalizedHoverDate && normalizedHoverDate >= from
          ? normalizedHoverDate
          : undefined)
      const matchingDecorators =
        dayDecorators?.filter((rule) => matchesRule(rule, normalizedDate)) ?? []
      const belowDecorators = matchingDecorators.filter(
        (decorator) => getDecoratorDisplay(decorator) === "below" && decorator.icon
      )

      let backgroundClass: string | undefined
      for (const decorator of matchingDecorators) {
        if (getDecoratorDisplay(decorator) === "background" && decorator.backgroundClass) {
          backgroundClass = decorator.backgroundClass
        }
      }

      const isStart = !!from && isSameDay(normalizedDate, from)
      const isEnd = !!effectiveTo && isSameDay(normalizedDate, effectiveTo)
      const isInRange = status === "range-middle" || status === "range-hover"
      const isSolo = isStart && (!from || !effectiveTo || isSameDay(from, effectiveTo))

      return (
        <div key={dayKey} className="relative flex items-center justify-center">
          {isInRange ? (
            <div className="absolute inset-y-0.5 left-[-2px] right-[-2px] bg_accent_secondary_subtle" />
          ) : null}
          {isStart && !isSolo ? (
            <div className="absolute inset-y-0.5 left-1/2 right-[-2px] bg_accent_secondary_subtle" />
          ) : null}
          {isEnd && !isSolo ? (
            <div className="absolute inset-y-0.5 left-[-2px] right-1/2 bg_accent_secondary_subtle" />
          ) : null}
          <button
            type="button"
            data-slot="calendar-day"
            disabled={status === "disabled"}
            onClick={() => handleRangeClick(normalizedDate)}
            onMouseEnter={() => setHoverDate(normalizedDate)}
            onMouseLeave={() => setHoverDate(null)}
            className={cn(
              "relative z-10",
              calendarDayVariants({ status }),
              hasAnyBelowDecorator && "h-10",
              belowDecorators.length > 0 && "flex-col gap-0",
              isBackgroundDecoratableStatus(status) && backgroundClass
            )}
          >
            <span>{normalizedDate.getDate()}</span>
            {belowDecorators.length > 0 ? (
              <span className="mt-0.5 flex h-3 items-center justify-center gap-0.5">
                {belowDecorators.map((decorator, index) => (
                  <span
                    key={`${dayKey}-decorator-${index}`}
                    className="inline-flex h-3 w-3 items-center justify-center"
                  >
                    {decorator.icon}
                  </span>
                ))}
              </span>
            ) : null}
          </button>
        </div>
      )
    },
    [dayDecorators, getRangeDayStatus, handleRangeClick, normalizedHoverDate, selectedRange]
  )

  const year = viewMonth.getFullYear()
  const month = viewMonth.getMonth()

  if (isRangeMode) {
    const secondYear = month === 11 ? year + 1 : year
    const secondMonth = month === 11 ? 0 : month + 1

    return (
      <div
        ref={ref}
        data-slot="calendar"
        className={cn(
          "inline-flex gap-6 p-3 bg_primary border border_secondary radius_8 shadow_xs",
          className
        )}
      >
        <CalendarMonthGrid
          year={year}
          month={month}
          showPrevButton
          showNextButton={false}
          onPrev={() => setViewMonth(new Date(year, month - 1, 1))}
          onNext={() => {}}
          dayDecorators={dayDecorators}
          weekDayLabels={resolvedWeekDayLabels}
          renderDay={renderRangeDay}
        />
        <CalendarMonthGrid
          year={secondYear}
          month={secondMonth}
          showPrevButton={false}
          showNextButton
          onPrev={() => {}}
          onNext={() => setViewMonth(new Date(year, month + 1, 1))}
          dayDecorators={dayDecorators}
          weekDayLabels={resolvedWeekDayLabels}
          renderDay={renderRangeDay}
        />
      </div>
    )
  }

  return (
    <div
      ref={ref}
      data-slot="calendar"
      className={cn(
        "inline-flex p-3 bg_primary border border_secondary radius_8 shadow_xs",
        className
      )}
    >
      <CalendarMonthGrid
        year={year}
        month={month}
        showPrevButton
        showNextButton
        onPrev={() => setViewMonth(new Date(year, month - 1, 1))}
        onNext={() => setViewMonth(new Date(year, month + 1, 1))}
        dayDecorators={dayDecorators}
        weekDayLabels={resolvedWeekDayLabels}
        renderDay={renderSingleDay}
      />
    </div>
  )
})

Calendar.displayName = "Calendar"

export { Calendar }
