import * as React from "react"

import { cn } from "@/lib/internal"
import { Calendar, type DateRange } from "./calendar"

export interface DateRangePreset {
  label: string
  range: DateRange
}

export interface DateRangePickerProps {
  value?: DateRange
  defaultValue?: DateRange
  onValueChange?: (range: DateRange) => void
  presets?: DateRangePreset[]
  showPresets?: boolean
  minDate?: Date
  maxDate?: Date
  disabledDates?: Date[] | ((date: Date) => boolean)
  className?: string
}

const normalizeToMidnight = (d: Date) => new Date(d.getFullYear(), d.getMonth(), d.getDate())

const subDays = (d: Date, n: number) => new Date(d.getFullYear(), d.getMonth(), d.getDate() - n)

const startOfMonth = (d: Date) => new Date(d.getFullYear(), d.getMonth(), 1)

const endOfMonth = (d: Date) => new Date(d.getFullYear(), d.getMonth() + 1, 0)

const isSameDay = (a: Date, b: Date) =>
  a.getFullYear() === b.getFullYear() &&
  a.getMonth() === b.getMonth() &&
  a.getDate() === b.getDate()

const DateRangePicker = React.forwardRef<HTMLDivElement, DateRangePickerProps>(
  (
    {
      value,
      defaultValue,
      onValueChange,
      presets,
      showPresets = true,
      minDate,
      maxDate,
      disabledDates,
      className,
    },
    ref
  ) => {
    const [internalRange, setInternalRange] = React.useState<DateRange>(defaultValue ?? {})
    const isControlled = value !== undefined
    const currentRange = isControlled ? (value ?? {}) : internalRange

    const handleValueChange = React.useCallback(
      (range: DateRange) => {
        if (!isControlled) setInternalRange(range)
        onValueChange?.(range)
      },
      [isControlled, onValueChange]
    )

    const defaultPresets = React.useMemo((): DateRangePreset[] => {
      const today = normalizeToMidnight(new Date())
      const prevMonthDate = new Date(today.getFullYear(), today.getMonth() - 1, 1)

      return [
        { label: "Today", range: { from: today, to: today } },
        { label: "Yesterday", range: { from: subDays(today, 1), to: subDays(today, 1) } },
        { label: "Last 7 days", range: { from: subDays(today, 6), to: today } },
        { label: "Last 14 days", range: { from: subDays(today, 13), to: today } },
        { label: "Last 30 days", range: { from: subDays(today, 29), to: today } },
        { label: "This month", range: { from: startOfMonth(today), to: endOfMonth(today) } },
        {
          label: "Last month",
          range: { from: startOfMonth(prevMonthDate), to: endOfMonth(prevMonthDate) },
        },
        { label: "Last 90 days", range: { from: subDays(today, 89), to: today } },
      ]
    }, [])

    const isPresetActive = React.useCallback(
      (preset: DateRangePreset) =>
        !!(
          currentRange.from &&
          currentRange.to &&
          preset.range.from &&
          preset.range.to &&
          isSameDay(currentRange.from, preset.range.from) &&
          isSameDay(currentRange.to, preset.range.to)
        ),
      [currentRange.from, currentRange.to]
    )

    return (
      <div
        ref={ref}
        role="group"
        aria-label="Date range picker"
        data-slot="date-range-picker"
        className={cn(
          "inline-flex bg_primary border border_secondary radius_8 shadow_xs overflow-hidden",
          className
        )}
      >
        {showPresets && (
          <div className="w-40 shrink-0 border-r border_secondary py-2 flex flex-col gap-0.5 px-1">
            {(presets ?? defaultPresets).map((preset) => (
              <button
                key={preset.label}
                type="button"
                onClick={() => handleValueChange(preset.range)}
                className={cn(
                  "w-full text-left text-sm px-3 py-1.5 radius_6 transition-colors cursor-pointer whitespace-nowrap",
                  isPresetActive(preset)
                    ? "text_primary state_bg_button_tertiary_soft font-medium"
                    : "text_secondary hover:text_primary hover:state_bg_button_tertiary_soft"
                )}
              >
                {preset.label}
              </button>
            ))}
          </div>
        )}

        <div className="p-4">
          <Calendar
            mode="range"
            value={currentRange}
            onValueChange={handleValueChange}
            minDate={minDate}
            maxDate={maxDate}
            disabledDates={disabledDates}
            className="border-none shadow-none"
          />
        </div>
      </div>
    )
  }
)

DateRangePicker.displayName = "DateRangePicker"

export { DateRangePicker }
