import * as React from "react"
import { type VariantProps } from "class-variance-authority"

import { cn } from "@/lib/internal"
import { textareaVariants } from "./textarea-variants"

export interface TextareaProps
  extends
    Omit<React.ComponentPropsWithoutRef<"textarea">, "size">,
    VariantProps<typeof textareaVariants> {
  /** Auto-grow height with content */
  autosize?: boolean
  /** Minimum number of visible rows (default: 3) */
  minRows?: number
  /** Maximum number of rows before scrolling */
  maxRows?: number
}

const Textarea = React.forwardRef<HTMLTextAreaElement, TextareaProps>(
  (
    {
      className,
      variant = "light",
      size = "m",
      autosize = false,
      minRows = 3,
      maxRows,
      defaultValue,
      value,
      onChange,
      ...props
    },
    ref
  ) => {
    const innerRef = React.useRef<HTMLTextAreaElement | null>(null)

    const mergedRef = React.useCallback(
      (node: HTMLTextAreaElement | null) => {
        innerRef.current = node
        if (typeof ref === "function") {
          ref(node)
        } else if (ref) {
          ref.current = node
        }
      },
      [ref]
    )

    const adjustHeight = React.useCallback(() => {
      const el = innerRef.current
      if (!el || !autosize) return
      el.style.height = "auto"
      let nextHeight = el.scrollHeight
      if (maxRows) {
        const style = getComputedStyle(el)
        const lineHeight = parseFloat(style.lineHeight) || 20
        const paddingTop = parseFloat(style.paddingTop) || 0
        const paddingBottom = parseFloat(style.paddingBottom) || 0
        const maxHeight = lineHeight * maxRows + paddingTop + paddingBottom
        nextHeight = Math.min(nextHeight, maxHeight)
      }
      el.style.height = `${nextHeight}px`
    }, [autosize, maxRows])

    // Adjust on mount and whenever value changes (controlled)
    React.useLayoutEffect(() => {
      adjustHeight()
    }, [adjustHeight, defaultValue, value])

    const handleChange = React.useCallback(
      (e: React.ChangeEvent<HTMLTextAreaElement>) => {
        adjustHeight()
        onChange?.(e)
      },
      [adjustHeight, onChange]
    )

    return (
      <textarea
        ref={mergedRef}
        data-slot="textarea"
        rows={minRows}
        className={cn(textareaVariants({ variant, size }), className)}
        defaultValue={defaultValue}
        value={value}
        onChange={handleChange}
        {...props}
      />
    )
  }
)

Textarea.displayName = "Textarea"

export { Textarea }
