import * as React from "react"
import { Popover as PopoverPrimitive } from "radix-ui"

import { cn } from "@/lib/internal"

export interface PopoverProps {
  trigger: React.ReactNode
  children: React.ReactNode
  open?: boolean
  onOpenChange?: (open: boolean) => void
  side?: "top" | "right" | "bottom" | "left"
  align?: "start" | "center" | "end"
  sideOffset?: number
  portal?: boolean
  className?: string
}

export interface PopoverContentProps extends React.ComponentPropsWithoutRef<
  typeof PopoverPrimitive.Content
> {
  portal?: boolean
}

const PopoverContent = React.forwardRef<
  React.ElementRef<typeof PopoverPrimitive.Content>,
  PopoverContentProps
>(
  (
    { className, side = "bottom", align = "start", sideOffset = 8, portal = true, ...props },
    ref
  ) => {
    const content = (
      <PopoverPrimitive.Content
        ref={ref}
        side={side}
        align={align}
        sideOffset={sideOffset}
        data-slot="popover-content"
        className={cn("z-50 border border_secondary bg_primary p-2 radius_8 shadow_l", className)}
        {...props}
      />
    )

    return portal ? <PopoverPrimitive.Portal>{content}</PopoverPrimitive.Portal> : content
  }
)

const Popover = ({
  trigger,
  children,
  open,
  onOpenChange,
  side = "bottom",
  align = "start",
  sideOffset = 8,
  portal = true,
  className,
}: PopoverProps) => (
  <PopoverPrimitive.Root data-slot="popover" open={open} onOpenChange={onOpenChange}>
    <PopoverPrimitive.Trigger asChild>{trigger}</PopoverPrimitive.Trigger>
    <PopoverContent
      side={side}
      align={align}
      sideOffset={sideOffset}
      portal={portal}
      className={className}
    >
      {children}
    </PopoverContent>
  </PopoverPrimitive.Root>
)

Popover.displayName = "Popover"
PopoverContent.displayName = "PopoverContent"

const PopoverTrigger = PopoverPrimitive.Trigger
PopoverTrigger.displayName = "PopoverTrigger"
const PopoverClose = PopoverPrimitive.Close
PopoverClose.displayName = "PopoverClose"

export { Popover, PopoverTrigger, PopoverContent, PopoverClose }
