import * as React from "react"
import { type VariantProps } from "class-variance-authority"

import { cn } from "@/lib/internal"
import { inputPinCodeContainerVariants, inputPinCodeSlotVariants } from "./input-pin-code-variants"

const DEFAULT_LENGTH = 6
const DEFAULT_PLACEHOLDER = "-"
const MASK_CHARACTER = "•"

const normalizeValue = (value: string, length: number, numericOnly: boolean) => {
  const nextValue = numericOnly ? value.replace(/\D+/g, "") : value
  return nextValue.slice(0, length)
}

const getSeparatorTextSize = (size: InputPinCodeProps["size"]) => {
  if (size === "s") return "text-xs"
  if (size === "l") return "text-base"
  return "text-sm"
}

export interface InputPinCodeProps
  extends
    Omit<
      React.ComponentPropsWithoutRef<"input">,
      | "autoComplete"
      | "defaultValue"
      | "inputMode"
      | "maxLength"
      | "onChange"
      | "pattern"
      | "placeholder"
      | "size"
      | "type"
      | "value"
    >,
    VariantProps<typeof inputPinCodeSlotVariants>,
    VariantProps<typeof inputPinCodeContainerVariants> {
  length?: number
  value?: string
  onChange?: (value: string) => void
  onComplete?: (value: string) => void
  numericOnly?: boolean
  mask?: boolean
  placeholder?: string
  separatorAfter?: number[]
}

const InputPinCode = React.forwardRef<HTMLInputElement, InputPinCodeProps>(
  (
    {
      className,
      length = DEFAULT_LENGTH,
      value,
      onChange,
      onComplete,
      numericOnly = true,
      mask = false,
      disabled = false,
      placeholder = DEFAULT_PLACEHOLDER,
      variant = "light",
      size = "m",
      separatorAfter,
      autoFocus = false,
      onBlur,
      onFocus,
      "aria-invalid": ariaInvalid,
      "aria-label": ariaLabel,
      "aria-labelledby": ariaLabelledBy,
      ...props
    },
    ref
  ) => {
    const inputRef = React.useRef<HTMLInputElement | null>(null)
    const caretStyleRef = React.useRef(false)
    const [internalValue, setInternalValue] = React.useState("")
    const [isFocused, setIsFocused] = React.useState(false)
    const isControlled = value !== undefined
    const currentValue = normalizeValue(
      isControlled ? (value ?? "") : internalValue,
      length,
      numericOnly
    )
    const activeIndex = currentValue.length >= length ? length - 1 : currentValue.length
    const separatorPositions = separatorAfter ?? []
    const showCaret = isFocused && !disabled && currentValue.length < length

    React.useEffect(() => {
      if (caretStyleRef.current || typeof document === "undefined") return
      caretStyleRef.current = true
      const style = document.createElement("style")
      style.textContent = `
@keyframes pin-caret-blink {
  0%, 100% { opacity: 1; }
  50% { opacity: 0; }
}`
      document.head.appendChild(style)
      return () => {
        document.head.removeChild(style)
        caretStyleRef.current = false
      }
    }, [])

    React.useEffect(() => {
      if (isControlled) return

      const normalizedInternalValue = normalizeValue(internalValue, length, numericOnly)
      if (normalizedInternalValue !== internalValue) {
        setInternalValue(normalizedInternalValue)
      }
    }, [internalValue, isControlled, length, numericOnly])

    const mergedRef = React.useCallback(
      (node: HTMLInputElement | null) => {
        inputRef.current = node

        if (typeof ref === "function") {
          ref(node)
        } else if (ref) {
          ref.current = node
        }
      },
      [ref]
    )

    const focusInput = () => {
      if (disabled) return
      inputRef.current?.focus()
    }

    const commitValue = (nextValue: string) => {
      if (nextValue === currentValue) return

      if (!isControlled) {
        setInternalValue(nextValue)
      }

      onChange?.(nextValue)

      if (nextValue.length === length) {
        onComplete?.(nextValue)
      }
    }

    const handleChange = (event: React.ChangeEvent<HTMLInputElement>) => {
      const nextValue = normalizeValue(event.target.value, length, numericOnly)
      commitValue(nextValue)
    }

    const handleFocus = (event: React.FocusEvent<HTMLInputElement>) => {
      setIsFocused(true)
      onFocus?.(event)
    }

    const handleBlur = (event: React.FocusEvent<HTMLInputElement>) => {
      setIsFocused(false)
      onBlur?.(event)
    }

    return (
      <div
        data-slot="input-pin-code"
        data-variant={variant}
        data-size={size}
        data-disabled={disabled ? "true" : undefined}
        data-invalid={ariaInvalid ? "true" : undefined}
        className={cn(inputPinCodeContainerVariants({ size }), className)}
        onClick={focusInput}
      >
        <input
          {...props}
          ref={mergedRef}
          data-slot="input-pin-code-input"
          type="text"
          value={currentValue}
          disabled={disabled}
          autoFocus={autoFocus}
          maxLength={length}
          autoComplete="one-time-code"
          inputMode={numericOnly ? "numeric" : undefined}
          pattern={numericOnly ? "[0-9]*" : undefined}
          aria-invalid={ariaInvalid}
          aria-label={ariaLabel ?? (ariaLabelledBy ? undefined : "Pin code input")}
          aria-labelledby={ariaLabelledBy}
          spellCheck={false}
          className="pointer-events-none absolute inset-0 h-full w-full opacity-0 outline-none"
          onChange={handleChange}
          onFocus={handleFocus}
          onBlur={handleBlur}
        />

        {Array.from({ length }, (_, index) => {
          const character = currentValue[index]
          const isFilled = character !== undefined
          const isActive = isFocused && activeIndex === index
          const showSeparator = index < length - 1 && separatorPositions.includes(index + 1)
          const renderedCharacter = isFilled ? (mask ? MASK_CHARACTER : character) : placeholder
          const shouldShowPlaceholder =
            Boolean(renderedCharacter) && !(showCaret && isActive && !isFilled)

          return (
            <React.Fragment key={index}>
              <div
                data-slot="input-pin-code-slot"
                data-active={isActive ? "true" : undefined}
                data-filled={isFilled ? "true" : undefined}
                data-disabled={disabled ? "true" : undefined}
                data-invalid={ariaInvalid ? "true" : undefined}
                className={cn(
                  inputPinCodeSlotVariants({ variant, size }),
                  isFilled ? "text_primary font-medium" : "text_tertiary",
                  disabled && "pointer-events-none opacity-60",
                  ariaInvalid && "border_error",
                  isActive &&
                    !ariaInvalid &&
                    "border-[var(--ds-bg-accent-secondary)] shadow-[var(--ds-outline-blue-focus)]"
                )}
              >
                {shouldShowPlaceholder ? <span aria-hidden="true">{renderedCharacter}</span> : null}
                {showCaret && isActive && !isFilled ? (
                  <span
                    aria-hidden="true"
                    className="absolute top-1/2 h-5 w-px -translate-y-1/2 bg-[var(--ds-bg-accent-secondary)] animate-[pin-caret-blink_1s_infinite]"
                  />
                ) : null}
              </div>

              {showSeparator ? (
                <span
                  aria-hidden="true"
                  className={cn("select-none text_tertiary", getSeparatorTextSize(size))}
                >
                  -
                </span>
              ) : null}
            </React.Fragment>
          )
        })}
      </div>
    )
  }
)

InputPinCode.displayName = "InputPinCode"

export { InputPinCode }
