import * as React from "react"
import { Filter } from "lucide-react"

import { Button } from "./button"
import { Checkbox } from "./checkbox"
import { Input } from "./input"
import { Popover } from "./popover"

interface DataTableFilterOption {
  label: string
  value: string
}

interface DataTableFilterDropdownProps {
  columnId: string
  filterType?: "text" | "select"
  options?: DataTableFilterOption[]
  value: unknown
  onApply: (value: string | string[]) => void
  onReset: () => void
}

function toTextValue(value: unknown): string {
  if (typeof value === "string") {
    return value
  }

  return ""
}

function toSelectValue(value: unknown): string[] {
  if (!Array.isArray(value)) {
    return []
  }

  return value.filter((item): item is string => typeof item === "string")
}

function DataTableFilterDropdown({
  columnId,
  filterType = "text",
  options,
  value,
  onApply,
  onReset,
}: DataTableFilterDropdownProps) {
  const [open, setOpen] = React.useState(false)
  const [draftText, setDraftText] = React.useState(() => toTextValue(value))
  const [draftOptions, setDraftOptions] = React.useState<string[]>(() => toSelectValue(value))

  React.useEffect(() => {
    if (filterType === "text") {
      setDraftText(toTextValue(value))
      return
    }

    setDraftOptions(toSelectValue(value))
  }, [filterType, value])

  const activeCount = React.useMemo(() => {
    if (filterType === "text") {
      return draftText.trim().length > 0 ? 1 : 0
    }

    return draftOptions.length
  }, [draftOptions.length, draftText, filterType])

  const handleApply = React.useCallback(() => {
    if (filterType === "text") {
      const trimmed = draftText.trim()
      setDraftText(trimmed)
      onApply(trimmed)
    } else {
      onApply(draftOptions)
    }
    setOpen(false)
  }, [draftOptions, draftText, filterType, onApply])

  const handleOptionToggle = React.useCallback((nextChecked: boolean, optionValue: string) => {
    setDraftOptions((previous) => {
      if (nextChecked) {
        if (previous.includes(optionValue)) {
          return previous
        }

        return [...previous, optionValue]
      }

      return previous.filter((valueItem) => valueItem !== optionValue)
    })
  }, [])

  return (
    <Popover
      open={open}
      onOpenChange={setOpen}
      trigger={
        <button
          type="button"
          aria-label={`Filter ${columnId}`}
          className="relative inline-flex cursor-pointer items-center justify-center rounded-sm p-1 text_secondary hover:bg_secondary hover:text_primary"
        >
          <Filter className="h-3.5 w-3.5" />
          {activeCount > 0 ? (
            <span className="absolute -right-1 -top-1 inline-flex min-w-4 items-center justify-center rounded-full bg_accent_primary px-1 text-[10px] font-semibold leading-none text_primary">
              {activeCount}
            </span>
          ) : null}
        </button>
      }
      align="start"
      sideOffset={10}
      className="w-64 p-3"
    >
      <div data-slot="data-table-filter-dropdown" className="flex flex-col gap-3">
        {filterType === "text" ? (
          <Input
            size="s"
            value={draftText}
            placeholder={`Filter ${columnId}`}
            onChange={(event) => {
              setDraftText(event.target.value)
            }}
          />
        ) : (
          <div className="max-h-48 space-y-2 overflow-auto pr-1">
            {options?.map((option) => (
              <Checkbox
                key={option.value}
                size="sm"
                label={option.label}
                checked={draftOptions.includes(option.value)}
                onCheckedChange={(checked) => {
                  handleOptionToggle(checked === true, option.value)
                }}
              />
            ))}

            {!options?.length ? <p className="text-xs text_secondary">No filters</p> : null}
          </div>
        )}

        <div className="flex items-center justify-end gap-2">
          <Button
            size="s"
            variant="subtle"
            onClick={() => {
              if (filterType === "text") {
                setDraftText("")
              } else {
                setDraftOptions([])
              }
              onReset()
              setOpen(false)
            }}
          >
            Reset
          </Button>

          <Button size="s" variant="primary" onClick={handleApply}>
            Apply
          </Button>
        </div>
      </div>
    </Popover>
  )
}

export { DataTableFilterDropdown }
