import * as React from "react"
import { Slot as SlotPrimitive } from "radix-ui"
import { type VariantProps } from "class-variance-authority"

import { cn } from "@/lib/internal"
import { avatarVariants } from "./avatar-variants"

export type AvatarType = "image" | "icon" | "text"
export type AvatarSize = "xxs" | "xs" | "s" | "m" | "l" | "xl"

export interface AvatarProps
  extends Omit<React.ComponentProps<"span">, "children">, VariantProps<typeof avatarVariants> {
  asChild?: boolean
  src?: string
  alt?: string
  fallback?: string
  icon?: React.ReactNode
  imageProps?: React.ComponentProps<"img">
}

const Avatar = React.forwardRef<HTMLSpanElement, AvatarProps>(
  (
    {
      className,
      size = "m",
      type = "image",
      asChild = false,
      src,
      alt,
      fallback,
      icon,
      imageProps,
      onClick,
      onKeyDown,
      ...props
    },
    ref
  ) => {
    const [hasError, setHasError] = React.useState(false)

    const fallbackLabel = alt ?? fallback ?? "Avatar"
    const canShowImage = type === "image" && !!src && !hasError
    const resolvedType: AvatarType = canShowImage ? "image" : icon ? "icon" : "text"
    const isInteractive = !!onClick
    const Comp = asChild ? SlotPrimitive.Root : "span"

    const handleImageError: React.ReactEventHandler<HTMLImageElement> = (event) => {
      setHasError(true)
      imageProps?.onError?.(event)
    }

    const handleKeyDown: React.KeyboardEventHandler<HTMLSpanElement> = (event) => {
      if (event.key === "Enter" || event.key === " ") {
        if (onClick) {
          event.preventDefault()
          onClick(event as unknown as React.MouseEvent<HTMLSpanElement, MouseEvent>)
        }
      }
      onKeyDown?.(event)
    }

    const renderContent = () => {
      if (resolvedType === "image" && src) {
        return (
          <img
            src={src}
            alt={alt ?? "Avatar image"}
            className="h-full w-full object-cover"
            onError={handleImageError}
            {...imageProps}
          />
        )
      }

      if (resolvedType === "icon") {
        return (
          <span className="flex items-center justify-center" aria-hidden="true">
            {icon}
          </span>
        )
      }

      return <span aria-hidden="true">{fallback ?? alt?.slice(0, 2) ?? "?"}</span>
    }

    return (
      <Comp
        ref={ref}
        data-slot="avatar"
        data-size={size}
        data-type={resolvedType}
        className={cn(avatarVariants({ size, type: resolvedType }), className)}
        role={isInteractive ? "button" : "img"}
        aria-label={fallbackLabel}
        tabIndex={isInteractive ? 0 : undefined}
        onClick={onClick}
        onKeyDown={handleKeyDown}
        {...props}
      >
        {renderContent()}
      </Comp>
    )
  }
)

Avatar.displayName = "Avatar"

export { Avatar }
