import * as React from "react"

import { cn } from "@/lib/internal"
import { stepsConnectorVariants, stepsIndicatorVariants } from "./steps-variants"

export interface Step {
  /** Primary content: displayed below the indicator (horizontal) or to the right (vertical) */
  content?: React.ReactNode
  /** Secondary content: displayed above the indicator (horizontal) or to the left (vertical) */
  secondaryContent?: React.ReactNode
  /** Custom icon node — used only when Steps variant="icon" */
  icon?: React.ReactNode
}

export interface StepsProps {
  steps: Step[]
  currentStep: number
  orientation?: "horizontal" | "vertical"
  /** "number" = numbered circles (default), "dot" = small dots, "icon" = custom icon per step */
  variant?: "number" | "dot" | "icon"
  className?: string
}

type StepStatus = "completed" | "current" | "upcoming"

const CheckIcon = () => (
  <svg
    viewBox="0 0 16 16"
    fill="none"
    xmlns="http://www.w3.org/2000/svg"
    aria-hidden="true"
    className="h-4 w-4"
  >
    <path
      d="M12.5 4.5L6.5 10.5L3.5 7.5"
      stroke="currentColor"
      strokeWidth="1.5"
      strokeLinecap="round"
      strokeLinejoin="round"
    />
  </svg>
)

function renderIndicatorContent(
  step: Step,
  status: StepStatus,
  index: number,
  variant: "number" | "dot" | "icon"
): React.ReactNode {
  if (variant === "dot") return null
  if (variant === "icon") {
    if (status === "completed") return <CheckIcon />
    return step.icon ?? <span>{index + 1}</span>
  }
  // number variant
  if (status === "completed") return <CheckIcon />
  return <span>{index + 1}</span>
}

function getStepKey(step: Step, index: number) {
  if (typeof step.content === "string" || typeof step.content === "number") return step.content
  if (typeof step.secondaryContent === "string" || typeof step.secondaryContent === "number") {
    return step.secondaryContent
  }
  return index
}

const Steps = React.forwardRef<HTMLDivElement, StepsProps>(
  ({ steps, currentStep, orientation = "horizontal", variant = "number", className }, ref) => {
    const getStatus = (index: number): StepStatus =>
      index < currentStep ? "completed" : index === currentStep ? "current" : "upcoming"

    if (orientation === "vertical") {
      const hasSecondary = steps.some((s) => s.secondaryContent !== undefined)

      return (
        <div ref={ref} data-slot="steps" className={cn("flex flex-col", className)}>
          {steps.map((step, index) => {
            const status = getStatus(index)
            const isLast = index === steps.length - 1

            return (
              <React.Fragment key={getStepKey(step, index)}>
                <div data-slot="steps-item" className="flex items-start gap-0">
                  {/* Secondary content — left column (optional) */}
                  {hasSecondary ? (
                    <div className="flex-shrink-0 w-20 pr-3 flex flex-col justify-center text-right">
                      {step.secondaryContent}
                    </div>
                  ) : null}

                  {/* Connector column */}
                  <div className="flex flex-col items-center flex-shrink-0 self-stretch">
                    <div
                      data-slot="steps-indicator"
                      className={stepsIndicatorVariants({ status, variant })}
                    >
                      {renderIndicatorContent(step, status, index, variant)}
                    </div>
                    {!isLast ? (
                      <div
                        data-slot="steps-connector"
                        className={stepsConnectorVariants({
                          status: index < currentStep ? "completed" : "upcoming",
                          orientation: "vertical",
                          variant,
                        })}
                      />
                    ) : null}
                  </div>

                  {/* Primary content — right column */}
                  <div
                    className={cn(
                      "flex flex-col justify-center pl-3",
                      !isLast && (variant === "dot" ? "pb-4" : "pb-6")
                    )}
                  >
                    {step.content}
                  </div>
                </div>
              </React.Fragment>
            )
          })}
        </div>
      )
    }

    // Horizontal orientation
    const hasSecondary = steps.some((s) => s.secondaryContent !== undefined)

    return (
      <div ref={ref} data-slot="steps" className={cn("flex items-start w-full", className)}>
        {steps.map((step, index) => {
          const status = getStatus(index)
          const isLast = index === steps.length - 1

          return (
            <React.Fragment key={getStepKey(step, index)}>
              <div data-slot="steps-item" className="flex flex-col items-center min-w-0">
                {/* Secondary content — above the indicator */}
                {hasSecondary ? (
                  <div className="mb-2 text-center min-h-[1.25rem]">{step.secondaryContent}</div>
                ) : null}

                {/* Indicator */}
                <div
                  data-slot="steps-indicator"
                  className={stepsIndicatorVariants({ status, variant })}
                >
                  {renderIndicatorContent(step, status, index, variant)}
                </div>

                {/* Primary content — below indicator */}
                {step.content ? <div className="mt-2 text-center">{step.content}</div> : null}
              </div>

              {/* Connector between steps */}
              {!isLast ? (
                <div
                  data-slot="steps-connector"
                  className={stepsConnectorVariants({
                    status: index < currentStep ? "completed" : "upcoming",
                    orientation: "horizontal",
                    variant,
                  })}
                />
              ) : null}
            </React.Fragment>
          )
        })}
      </div>
    )
  }
)

Steps.displayName = "Steps"

export { Steps }
