import * as React from "react"
import { useVirtualizer } from "@tanstack/react-virtual"

import { cn } from "@/lib/internal"

export interface VirtualListProps<T> {
  items: T[]
  estimateSize: number | ((index: number) => number)
  renderItem: (item: T, index: number) => React.ReactNode
  overscan?: number
  className?: string
  getItemKey?: (item: T, index: number) => string | number
}

function VirtualList<T>({
  items,
  estimateSize,
  renderItem,
  overscan = 5,
  className,
  getItemKey,
}: VirtualListProps<T>) {
  const parentRef = React.useRef<HTMLDivElement>(null)

  const estimateSizeFn = React.useCallback(
    (index: number) => (typeof estimateSize === "number" ? estimateSize : estimateSize(index)),
    [estimateSize]
  )

  const virtualizer = useVirtualizer({
    count: items.length,
    getScrollElement: () => parentRef.current,
    estimateSize: estimateSizeFn,
    overscan,
    getItemKey: getItemKey ? (index) => getItemKey(items[index], index) : undefined,
  })

  return (
    <div
      ref={parentRef}
      data-slot="virtual-list"
      role="list"
      className={cn("overflow-auto", className)}
    >
      <div style={{ height: virtualizer.getTotalSize(), position: "relative" }}>
        {virtualizer.getVirtualItems().map((virtualItem) => (
          <div
            key={virtualItem.key}
            role="listitem"
            data-index={virtualItem.index}
            ref={virtualizer.measureElement}
            style={{
              position: "absolute",
              top: 0,
              left: 0,
              width: "100%",
              transform: `translateY(${virtualItem.start}px)`,
            }}
          >
            {renderItem(items[virtualItem.index], virtualItem.index)}
          </div>
        ))}
      </div>
    </div>
  )
}

VirtualList.displayName = "VirtualList"

export { VirtualList }
