import * as React from "react"

import { ChevronsLeft, ChevronsRight } from "lucide-react"

import { cn } from "@/lib/internal"
import { Avatar } from "./avatar"
import { ScrollArea } from "./scroll-area"
import { sidebarItemVariants, sidebarSubItemVariants } from "./sidebar-variants"

const SIDEBAR_WIDTH = "232px"
const SIDEBAR_COLLAPSED_WIDTH = "56px"

// ─── Context ──────────────────────────────────────────────────────────────────

interface SidebarContextValue {
  collapsed: boolean
  toggle: () => void
  collapseMode: "collapse" | "hide"
}

const SidebarContext = React.createContext<SidebarContextValue>({
  collapsed: false,
  toggle: () => {},
  collapseMode: "collapse",
})

export interface SidebarNavItem {
  id: string
  label: string
  icon?: React.ReactNode
  href?: string
  children?: SidebarNavItem[]
  badge?: React.ReactNode
  dot?: boolean
  disabled?: boolean
  /** Only applies when item has children. Open by default (user can still close). */
  defaultOpen?: boolean
  /** Only applies when item has children. Always open, cannot be collapsed. */
  alwaysOpen?: boolean
}

export interface SidebarNavGroup {
  id: string
  label?: string
  items: SidebarNavItem[]
}

interface SidebarTriggerProps {
  isHideWhenSidebarOpen?: boolean
  className?: string
  icon?: React.ReactNode
}

const SidebarTrigger = React.forwardRef<HTMLButtonElement, SidebarTriggerProps>(
  ({ isHideWhenSidebarOpen = false, className, icon }, ref) => {
    const { collapsed, toggle } = React.useContext(SidebarContext)

    if (isHideWhenSidebarOpen && !collapsed) return null

    return (
      <button
        ref={ref}
        type="button"
        data-slot="sidebar-trigger"
        onClick={toggle}
        aria-label={collapsed ? "Expand sidebar" : "Collapse sidebar"}
        aria-expanded={!collapsed}
        className={cn(
          "inline-flex items-center justify-center w-6 h-6 radius_6 flex-shrink-0",
          "text_tertiary hover:text_primary hover:state_bg_button_tertiary_soft",
          "transition-colors duration-150 cursor-pointer",
          className
        )}
      >
        {icon ??
          (collapsed ? (
            <ChevronsRight className="w-4 h-4" />
          ) : (
            <ChevronsLeft className="w-4 h-4" />
          ))}
      </button>
    )
  }
)

// ─── Sidebar (root) ───────────────────────────────────────────────────────────

interface SidebarProps extends React.ComponentProps<"aside"> {
  defaultCollapsed?: boolean
  collapsed?: boolean
  onCollapsedChange?: (collapsed: boolean) => void
  collapseMode?: "collapse" | "hide"
}

const Sidebar = React.forwardRef<HTMLElement, SidebarProps>(
  (
    {
      defaultCollapsed = false,
      collapsed: collapsedProp,
      onCollapsedChange,
      collapseMode = "collapse",
      className,
      style,
      children,
      ...props
    },
    ref
  ) => {
    const [internalCollapsed, setInternalCollapsed] = React.useState(defaultCollapsed)
    const isControlled = collapsedProp !== undefined
    const collapsed = isControlled ? collapsedProp : internalCollapsed

    const toggle = React.useCallback(() => {
      const next = !collapsed
      if (!isControlled) setInternalCollapsed(next)
      onCollapsedChange?.(next)
    }, [collapsed, isControlled, onCollapsedChange])

    return (
      <SidebarContext.Provider value={{ collapsed, toggle, collapseMode }}>
        <aside
          ref={ref}
          data-slot="sidebar"
          data-collapsed={collapsed}
          style={
            {
              "--sidebar-width": SIDEBAR_WIDTH,
              "--sidebar-collapsed-width": SIDEBAR_COLLAPSED_WIDTH,
              width:
                collapsed && collapseMode === "hide"
                  ? 0
                  : collapsed
                    ? "var(--sidebar-collapsed-width)"
                    : "var(--sidebar-width)",
              ...style,
            } as React.CSSProperties
          }
          className={cn(
            "shrink-0 flex flex-col h-screen sticky top-0",
            "bg_sidebar_primary border-r border_primary",
            "transition-all duration-200 overflow-hidden",
            collapsed && collapseMode === "hide" ? "border-r-0" : "",
            className
          )}
          {...props}
        >
          {children}
        </aside>
      </SidebarContext.Provider>
    )
  }
)

// ─── SidebarHeader ────────────────────────────────────────────────────────────

interface SidebarHeaderProps extends Omit<React.ComponentProps<"div">, "title"> {
  logo?: React.ReactNode
  title?: React.ReactNode
}

const SidebarHeader = React.forwardRef<HTMLDivElement, SidebarHeaderProps>(
  ({ logo, title, className, children, ...props }, ref) => {
    const { collapsed } = React.useContext(SidebarContext)

    return (
      <div
        ref={ref}
        data-slot="sidebar-header"
        className={cn(
          "shrink-0 flex h-11 items-center py-0",
          "hover:state_bg_sidebar_primary_subtle radius_6 cursor-pointer transition-colors",
          collapsed ? "justify-center px-0 gap-0" : "gap-2 pl-5 pr-3",
          className
        )}
        {...props}
      >
        {children ?? (
          <>
            {logo && !collapsed && (
              <span className="shrink-0 flex items-center justify-center">{logo}</span>
            )}

            <div
              className={cn(
                "overflow-hidden transition-all duration-200",
                collapsed ? "w-0 opacity-0" : "flex-1 opacity-100"
              )}
            >
              {title && <p className="text_primary body_s font_semibold truncate">{title}</p>}
            </div>

            <SidebarTrigger />
          </>
        )}
      </div>
    )
  }
)

// ─── SidebarContent ───────────────────────────────────────────────────────────

const SidebarContent = React.forwardRef<HTMLDivElement, React.ComponentProps<"div">>(
  ({ className, children, dir, ...props }, ref) => {
    const { collapsed } = React.useContext(SidebarContext)
    const scrollDir = dir as "ltr" | "rtl" | undefined

    if (collapsed) {
      return (
        <ScrollArea
          ref={ref}
          data-slot="sidebar-content"
          className={cn("flex-1", className)}
          dir={scrollDir}
          {...props}
        >
          <nav aria-label="Sidebar navigation" className="p-2 space-y-3">
            {children}
          </nav>
        </ScrollArea>
      )
    }

    return (
      <ScrollArea
        ref={ref}
        data-slot="sidebar-content"
        className={cn("flex-1", className)}
        dir={scrollDir}
        {...props}
      >
        <nav aria-label="Sidebar navigation" className="p-3 space-y-6">
          {children}
        </nav>
      </ScrollArea>
    )
  }
)

// ─── SidebarSection ───────────────────────────────────────────────────────────

interface SidebarSectionProps extends React.ComponentProps<"div"> {
  label?: string
  panel?: boolean
}

const SidebarSection = React.forwardRef<HTMLDivElement, SidebarSectionProps>(
  ({ label, panel = false, className, children, ...props }, ref) => {
    const { collapsed } = React.useContext(SidebarContext)

    return (
      <div
        ref={ref}
        data-slot="sidebar-section"
        className={cn("space-y-0.5", panel && "bg_sidebar_secondary radius_8", className)}
        {...props}
      >
        {label &&
          (collapsed ? (
            <hr className="border_secondary my-1" />
          ) : (
            <p className="fg_sidebar_secondary text-[10px] font-semibold uppercase tracking-wider px-2 mb-1">
              {label}
            </p>
          ))}
        {children}
      </div>
    )
  }
)

// ─── SidebarItem ──────────────────────────────────────────────────────────────

interface SidebarItemProps extends Omit<React.ComponentProps<"button">, "children" | "onClick"> {
  icon?: React.ReactNode
  label?: string
  href?: string
  badge?: React.ReactNode
  dot?: boolean
  active?: boolean
  defaultOpen?: boolean
  open?: boolean
  onOpenChange?: (open: boolean) => void
  alwaysOpen?: boolean
  children?: React.ReactNode
  onClick?: React.MouseEventHandler<HTMLElement>
}

const SidebarItem = React.forwardRef<HTMLElement, SidebarItemProps>(
  (
    {
      icon,
      label,
      href,
      badge,
      dot = false,
      active = false,
      defaultOpen = false,
      open: openProp,
      onOpenChange,
      alwaysOpen = false,
      className,
      onClick,
      disabled,
      children,
      ...props
    },
    ref
  ) => {
    const { collapsed } = React.useContext(SidebarContext)
    const hasChildren = React.Children.count(children) > 0

    const [internalOpen, setInternalOpen] = React.useState(alwaysOpen || defaultOpen)
    const isControlled = openProp !== undefined
    const isOpen = alwaysOpen ? true : isControlled ? openProp : internalOpen
    const collapsedFallbackIcon =
      !icon && collapsed ? (
        <span className="inline-flex h-4 w-4 items-center justify-center radius_4 border border_secondary bg_primary text-[10px] font-semibold leading-none text_secondary">
          {(label ?? "?").slice(0, 1).toUpperCase()}
        </span>
      ) : null
    const resolvedIcon = icon ?? collapsedFallbackIcon
    const ItemElement = href ? "a" : "button"

    const handleClick = (e: React.MouseEvent<HTMLElement>) => {
      if (disabled) {
        e.preventDefault()
        e.stopPropagation()
        return
      }

      if (hasChildren && !collapsed && !alwaysOpen) {
        const next = !isOpen
        if (!isControlled) setInternalOpen(next)
        onOpenChange?.(next)
      }
      onClick?.(e)
    }

    const itemProps: React.HTMLAttributes<HTMLElement> & {
      ref: React.Ref<HTMLElement>
      href?: string
      type?: React.ButtonHTMLAttributes<HTMLButtonElement>["type"]
      disabled?: boolean
      "data-slot"?: string
      "data-active"?: boolean
    } = {
      ref,
      ...(href
        ? {
            href: disabled ? undefined : href,
            "aria-disabled": disabled || undefined,
            tabIndex: disabled ? -1 : undefined,
          }
        : { type: "button", disabled }),
      "data-slot": "sidebar-item",
      "data-active": active,
      title: collapsed ? label : undefined,
      "aria-current": active ? "page" : undefined,
      "aria-expanded": hasChildren && !collapsed ? isOpen : undefined,
      onClick: handleClick,
      className: cn(
        sidebarItemVariants({ active }),
        collapsed ? "justify-center px-0 w-10 h-10 mx-auto" : "pl-3 pr-1.5 gap-2",
        className
      ),
      ...props,
    }

    return (
      <div data-slot="sidebar-item-wrapper">
        {React.createElement(
          ItemElement,
          itemProps,
          <>
            {resolvedIcon && (
              <span
                className={cn(
                  "shrink-0 flex items-center justify-center w-4 h-4",
                  collapsed && dot ? "relative" : "",
                  icon ? (active ? "fg_sidebar_primary" : "fg_sidebar_secondary") : ""
                )}
                aria-hidden="true"
              >
                {resolvedIcon}
                {collapsed && dot && (
                  <span className="absolute -top-0.5 -right-0.5 w-1.5 h-1.5 radius_round bg_error flex-shrink-0" />
                )}
              </span>
            )}

            {!collapsed && (
              <>
                <span className="flex-1 text-left truncate">{label}</span>
                {badge ? <span className="flex-shrink-0">{badge}</span> : null}
                {dot ? <span className="w-1.5 h-1.5 radius_round bg_error flex-shrink-0" /> : null}
                {hasChildren && !alwaysOpen && (
                  <svg
                    viewBox="0 0 16 16"
                    fill="none"
                    xmlns="http://www.w3.org/2000/svg"
                    aria-hidden="true"
                    className={cn(
                      "w-3.5 h-3.5 shrink-0 transition-transform duration-200",
                      isOpen ? "rotate-180" : ""
                    )}
                  >
                    <path
                      d="M4 6L8 10L12 6"
                      stroke="currentColor"
                      strokeWidth="1.5"
                      strokeLinecap="round"
                      strokeLinejoin="round"
                    />
                  </svg>
                )}
              </>
            )}
          </>
        )}

        {/* Children panel — CSS grid animation */}
        {hasChildren && (
          <div
            className={cn(
              "grid transition-all duration-200",
              isOpen && !collapsed ? "grid-rows-[1fr]" : "grid-rows-[0fr]"
            )}
            aria-label={label ? `${label} submenu` : undefined}
          >
            <div className="min-h-0 overflow-hidden pt-0.5 space-y-0.5">{children}</div>
          </div>
        )}
      </div>
    )
  }
)

// ─── SidebarSubItem ───────────────────────────────────────────────────────────

interface SidebarSubItemProps extends Omit<React.ComponentProps<"button">, "onClick"> {
  icon?: React.ReactNode
  label: string
  href?: string
  active?: boolean
  onClick?: React.MouseEventHandler<HTMLElement>
}

const SidebarSubItem = React.forwardRef<HTMLElement, SidebarSubItemProps>(
  ({ icon, label, href, active = false, disabled, className, onClick, ...props }, ref) => {
    const { collapsed } = React.useContext(SidebarContext)

    if (collapsed) return null

    const handleClick = (event: React.MouseEvent<HTMLElement>) => {
      if (disabled) {
        event.preventDefault()
        event.stopPropagation()
        return
      }

      onClick?.(event)
    }

    if (href) {
      return (
        <a
          ref={ref as React.Ref<HTMLAnchorElement>}
          href={disabled ? undefined : href}
          data-slot="sidebar-subitem"
          data-active={active}
          aria-current={active ? "page" : undefined}
          aria-disabled={disabled || undefined}
          tabIndex={disabled ? -1 : undefined}
          onClick={handleClick}
          className={cn(sidebarSubItemVariants({ active }), className)}
        >
          {icon && (
            <span
              className={cn(
                "shrink-0 flex items-center justify-center w-4 h-4",
                active ? "fg_sidebar_primary" : "fg_sidebar_secondary"
              )}
              aria-hidden="true"
            >
              {icon}
            </span>
          )}
          <span className="flex-1 text-left truncate">{label}</span>
        </a>
      )
    }

    return (
      <button
        ref={ref as React.Ref<HTMLButtonElement>}
        type="button"
        disabled={disabled}
        data-slot="sidebar-subitem"
        data-active={active}
        aria-current={active ? "page" : undefined}
        onClick={handleClick}
        className={cn(sidebarSubItemVariants({ active }), className)}
        {...props}
      >
        {icon && (
          <span
            className={cn(
              "shrink-0 flex items-center justify-center w-4 h-4",
              active ? "fg_sidebar_primary" : "fg_sidebar_secondary"
            )}
            aria-hidden="true"
          >
            {icon}
          </span>
        )}
        <span className="flex-1 text-left truncate">{label}</span>
      </button>
    )
  }
)

// ─── SidebarFooter ────────────────────────────────────────────────────────────

interface SidebarFooterProps extends React.ComponentProps<"div"> {
  avatarSrc?: string
  avatarFallback?: string
  name?: string
  role?: string
}

const SidebarFooter = React.forwardRef<HTMLDivElement, SidebarFooterProps>(
  ({ avatarSrc, avatarFallback, name, role, className, children, ...props }, ref) => {
    const { collapsed } = React.useContext(SidebarContext)

    return (
      <div
        ref={ref}
        data-slot="sidebar-footer"
        className={cn(
          "shrink-0 h-16",
          collapsed
            ? "flex items-center justify-center p-3"
            : "flex items-center gap-1.5 px-4 pt-5 pb-3",
          className
        )}
        {...props}
      >
        {children ?? (
          <>
            <Avatar
              src={avatarSrc}
              fallback={avatarFallback}
              size="s"
              type={avatarSrc ? "image" : "text"}
              className="shrink-0"
            />
            {!collapsed && (name || role) && (
              <div className="flex-1 overflow-hidden">
                {name && <p className="text_primary body_s font_semibold truncate">{name}</p>}
                {role && <p className="text_tertiary body_xs truncate">{role}</p>}
              </div>
            )}
          </>
        )}
      </div>
    )
  }
)

const BlockSidebarHeader = ({ header }: { header?: React.ReactNode }) => {
  const { collapsed } = React.useContext(SidebarContext)

  return (
    <div
      data-slot="sidebar-header"
      className={cn(
        "shrink-0 flex h-11 items-center gap-2 py-0",
        "hover:state_bg_sidebar_primary_subtle radius_6 cursor-pointer transition-colors",
        collapsed ? "justify-center px-0" : "pl-5 pr-3"
      )}
    >
      {header && !collapsed ? <div className="flex-1 overflow-hidden">{header}</div> : null}
      <SidebarTrigger className={collapsed ? "" : "ml-auto"} />
    </div>
  )
}

const BlockSidebarNav = ({ children }: { children: React.ReactNode }) => {
  const { collapsed } = React.useContext(SidebarContext)

  return (
    <ScrollArea data-slot="sidebar-content" className="flex-1">
      <nav
        aria-label="Sidebar navigation"
        className={cn(collapsed ? "p-2 space-y-3" : "p-3 space-y-6")}
      >
        {children}
      </nav>
    </ScrollArea>
  )
}

const BlockSidebarFooterGroups = ({ children }: { children: React.ReactNode }) => (
  <nav
    data-slot="sidebar-footer-groups"
    aria-label="Sidebar footer navigation"
    className="shrink-0 bg_sidebar_secondary px-3 pb-2 space-y-4 pt-3"
  >
    {children}
  </nav>
)

export interface BlockSidebarLayoutProps {
  groups: SidebarNavGroup[]
  footerGroups?: SidebarNavGroup[]
  onNavigate?: (id: string, href?: string) => void
  activeId?: string
  header?: React.ReactNode
  footer?: React.ReactNode
  defaultCollapsed?: boolean
  collapsed?: boolean
  onCollapsedChange?: (collapsed: boolean) => void
  collapseMode?: "collapse" | "hide"
  children?: React.ReactNode
  className?: string
  contentClassName?: string
}

const BlockSidebarLayout = React.forwardRef<HTMLDivElement, BlockSidebarLayoutProps>(
  (
    {
      groups,
      footerGroups,
      onNavigate,
      activeId,
      header,
      footer,
      defaultCollapsed = false,
      collapsed: collapsedProp,
      onCollapsedChange,
      collapseMode = "collapse",
      children,
      className,
      contentClassName,
    },
    ref
  ) => {
    const handleNavigate = React.useCallback(
      (event: React.MouseEvent<HTMLElement>, id: string, href?: string) => {
        if (!onNavigate) return
        event.preventDefault()
        onNavigate(id, href)
      },
      [onNavigate]
    )

    const renderGroup = React.useCallback(
      (group: SidebarNavGroup, hideLabel = false) => (
        <SidebarSection key={group.id} label={hideLabel ? undefined : group.label}>
          {group.items.map((item) =>
            item.children?.length ? (
              <SidebarItem
                key={item.id}
                icon={item.icon}
                label={item.label}
                href={item.href}
                active={activeId === item.id}
                badge={item.badge}
                dot={item.dot}
                disabled={item.disabled}
                defaultOpen={
                  item.defaultOpen ?? item.children.some((child) => child.id === activeId)
                }
                alwaysOpen={item.alwaysOpen}
                onClick={(event) => handleNavigate(event, item.id, item.href)}
              >
                {item.children.map((child) => (
                  <SidebarSubItem
                    key={child.id}
                    icon={child.icon}
                    label={child.label}
                    href={child.href}
                    active={activeId === child.id}
                    disabled={child.disabled}
                    onClick={(event) => handleNavigate(event, child.id, child.href)}
                  />
                ))}
              </SidebarItem>
            ) : (
              <SidebarItem
                key={item.id}
                icon={item.icon}
                label={item.label}
                href={item.href}
                active={activeId === item.id}
                badge={item.badge}
                dot={item.dot}
                disabled={item.disabled}
                onClick={(event) => handleNavigate(event, item.id, item.href)}
              />
            )
          )}
        </SidebarSection>
      ),
      [activeId, handleNavigate]
    )

    return (
      <div
        ref={ref}
        data-slot="block-sidebar-layout"
        className={cn("flex h-screen overflow-hidden", className)}
      >
        <Sidebar
          defaultCollapsed={defaultCollapsed}
          collapsed={collapsedProp}
          onCollapsedChange={onCollapsedChange}
          collapseMode={collapseMode}
          className="h-full"
        >
          <BlockSidebarHeader header={header} />

          <BlockSidebarNav>{groups.map((group) => renderGroup(group))}</BlockSidebarNav>

          {footerGroups && footerGroups.length > 0 ? (
            <BlockSidebarFooterGroups>
              {footerGroups.map((group) => renderGroup(group, true))}
            </BlockSidebarFooterGroups>
          ) : null}

          {footer ? (
            <div data-slot="sidebar-footer" className="shrink-0 h-16 px-4 pt-5 pb-3">
              {footer}
            </div>
          ) : null}
        </Sidebar>

        <div className={cn("flex-1 overflow-auto", contentClassName)}>{children}</div>
      </div>
    )
  }
)

// ─── displayNames ─────────────────────────────────────────────────────────────

Sidebar.displayName = "Sidebar"
SidebarTrigger.displayName = "SidebarTrigger"
SidebarHeader.displayName = "SidebarHeader"
SidebarContent.displayName = "SidebarContent"
SidebarSection.displayName = "SidebarSection"
SidebarItem.displayName = "SidebarItem"
SidebarSubItem.displayName = "SidebarSubItem"
SidebarFooter.displayName = "SidebarFooter"
BlockSidebarLayout.displayName = "BlockSidebarLayout"

export {
  Sidebar,
  SidebarHeader,
  SidebarContent,
  SidebarSection,
  SidebarItem,
  SidebarSubItem,
  SidebarFooter,
  SidebarTrigger,
  BlockSidebarLayout,
}
