import { cva, type VariantProps } from "class-variance-authority"

export const tabsListVariants = cva("inline-flex items-center", {
  variants: {
    variant: {
      default: "bg_tertiary p-1 radius_8",
      underline: "border-b border_secondary gap-1 w-full",
      borderless: "border-b border-transparent gap-1 w-full",
    },
  },
  defaultVariants: { variant: "default" },
})

export const tabsTriggerVariants = cva(
  "inline-flex h-[var(--ui-tabs-trigger-height,2rem)] items-center justify-center whitespace-nowrap px-3 text-sm font-medium transition-colors duration-0",
  {
    variants: {
      variant: {
        default: [
          "bg-transparent py-1.5 text_secondary radius_6",
          "hover:state_bg_button_tertiary_soft",
          "data-[state=active]:bg-[var(--ds-bg-primary)] data-[state=active]:text-[var(--ds-text-primary)] data-[state=active]:shadow-[var(--ds-shadow-s)]",
        ].join(" "),
        underline: [
          "border-b-2 border-transparent py-2 text_tertiary -mb-[2px]",
          "hover:text_primary",
        ].join(" "),
        borderless: [
          "border-b-2 border-transparent py-2 text_tertiary -mb-[2px]",
          "hover:text_primary",
        ].join(" "),
      },
      color: {
        orange: "",
        primary: "",
      },
    },
    compoundVariants: [
      {
        variant: "underline",
        color: "orange",
        class: "data-[state=active]:border-[var(--ds-border-accent-primary)] data-[state=active]:text-[var(--ds-fg-accent-primary)]",
      },
      {
        variant: "borderless",
        color: "orange",
        class: "data-[state=active]:border-[var(--ds-border-accent-primary)] data-[state=active]:text-[var(--ds-fg-accent-primary)]",
      },
      {
        variant: "underline",
        color: "primary",
        class:
          "data-[state=active]:border-[var(--ds-text-primary)] data-[state=active]:text-[var(--ds-text-primary)]",
      },
      {
        variant: "borderless",
        color: "primary",
        class:
          "data-[state=active]:border-[var(--ds-text-primary)] data-[state=active]:text-[var(--ds-text-primary)]",
      },
    ],
    defaultVariants: {
      variant: "default",
      color: "orange",
    },
  }
)

export type TabsVariant = NonNullable<VariantProps<typeof tabsListVariants>["variant"]>
export type TabsColor = NonNullable<VariantProps<typeof tabsTriggerVariants>["color"]>

export const tabsContentVariants = cva("mt-4")
