import * as React from "react"

export const themes = [
  "light",
  "high-contrast-light",
  "olive",
  "dark",
  "deep-forest",
  "sunset",
] as const

export type ThemeName = (typeof themes)[number]
const extraThemeClassNames = themes
  .filter((theme) => theme !== "light" && theme !== "dark")
  .map((theme) => `theme-${theme}`)

type ThemeOptions = {
  defaultValue?: ThemeName
  storageKey?: string
}

const isThemeName = (value: string | null): value is ThemeName =>
  themes.includes(value as ThemeName)

const getSystemTheme = () =>
  typeof window !== "undefined" && window.matchMedia("(prefers-color-scheme: dark)").matches
    ? "dark"
    : "light"

export function useTheme(options: ThemeOptions = {}) {
  const { storageKey = "ui-kit-theme", defaultValue } = options

  const [theme, setTheme] = React.useState<ThemeName>(() => {
    if (typeof window === "undefined") return defaultValue ?? "light"
    const stored = localStorage.getItem(storageKey)
    if (isThemeName(stored)) return stored
    return defaultValue ?? getSystemTheme()
  })

  React.useEffect(() => {
    const root = document.documentElement
    root.classList.remove("dark", ...extraThemeClassNames)
    if (theme === "dark") root.classList.add("dark")
    if (theme !== "light" && theme !== "dark") root.classList.add(`theme-${theme}`)
    root.dataset.theme = theme
    localStorage.setItem(storageKey, theme)
  }, [theme, storageKey])

  React.useEffect(() => {
    const mq = window.matchMedia("(prefers-color-scheme: dark)")
    const handler = (event: MediaQueryListEvent) => {
      const stored = localStorage.getItem(storageKey)
      if (!isThemeName(stored)) setTheme(event.matches ? "dark" : "light")
    }
    mq.addEventListener("change", handler)
    return () => mq.removeEventListener("change", handler)
  }, [storageKey])

  return { theme, setTheme, themes }
}
