import * as React from "react"
import { Dialog } from "radix-ui"
import { type VariantProps } from "class-variance-authority"

import { cn } from "@/lib/internal"
import { drawerContentVariants, drawerOverlayVariants } from "./drawer-variants"

const Drawer = Dialog.Root

const DrawerPortal = Dialog.Portal

const DrawerTrigger = React.forwardRef<
  React.ElementRef<typeof Dialog.Trigger>,
  React.ComponentPropsWithoutRef<typeof Dialog.Trigger>
>(({ children, asChild = true, ...props }, ref) => (
  <Dialog.Trigger ref={ref} data-slot="drawer-trigger" asChild={asChild} {...props}>
    {children}
  </Dialog.Trigger>
))

const DrawerClose = React.forwardRef<
  React.ElementRef<typeof Dialog.Close>,
  React.ComponentPropsWithoutRef<typeof Dialog.Close>
>(({ className, ...props }, ref) => (
  <Dialog.Close ref={ref} data-slot="drawer-close" className={cn(className)} {...props} />
))

const DrawerOverlay = React.forwardRef<
  React.ElementRef<typeof Dialog.Overlay>,
  React.ComponentPropsWithoutRef<typeof Dialog.Overlay>
>(({ className, ...props }, ref) => (
  <Dialog.Overlay
    ref={ref}
    data-slot="drawer-overlay"
    className={cn(drawerOverlayVariants(), className)}
    {...props}
  />
))

interface DrawerContentProps
  extends
    React.ComponentPropsWithoutRef<typeof Dialog.Content>,
    VariantProps<typeof drawerContentVariants> {}

const DrawerContent = React.forwardRef<React.ElementRef<typeof Dialog.Content>, DrawerContentProps>(
  ({ className, children, side = "left", size = "m", ...props }, ref) => (
    <DrawerPortal>
      <DrawerOverlay />
      <Dialog.Content
        ref={ref}
        data-slot="drawer-content"
        data-side={side}
        className={cn(drawerContentVariants({ side, size }), className)}
        {...props}
      >
        {children}
      </Dialog.Content>
    </DrawerPortal>
  )
)

const DrawerHeader = React.forwardRef<HTMLDivElement, React.ComponentPropsWithoutRef<"div">>(
  ({ className, ...props }, ref) => (
    <div
      ref={ref}
      data-slot="drawer-header"
      className={cn(
        "flex items-center justify-between px-6 py-4 border-b border_secondary",
        className
      )}
      {...props}
    />
  )
)

const DrawerTitle = React.forwardRef<
  React.ElementRef<typeof Dialog.Title>,
  React.ComponentPropsWithoutRef<typeof Dialog.Title>
>(({ className, ...props }, ref) => (
  <Dialog.Title
    ref={ref}
    data-slot="drawer-title"
    className={cn("text-lg font-semibold text_primary", className)}
    {...props}
  />
))

const DrawerDescription = React.forwardRef<
  React.ElementRef<typeof Dialog.Description>,
  React.ComponentPropsWithoutRef<typeof Dialog.Description>
>(({ className, ...props }, ref) => (
  <Dialog.Description
    ref={ref}
    data-slot="drawer-description"
    className={cn("text-sm text_tertiary mt-1", className)}
    {...props}
  />
))

const DrawerBody = React.forwardRef<HTMLDivElement, React.ComponentPropsWithoutRef<"div">>(
  ({ className, ...props }, ref) => (
    <div
      ref={ref}
      data-slot="drawer-body"
      className={cn("flex-1 overflow-y-auto px-6 py-4", className)}
      {...props}
    />
  )
)

const DrawerFooter = React.forwardRef<HTMLDivElement, React.ComponentPropsWithoutRef<"div">>(
  ({ className, ...props }, ref) => (
    <div
      ref={ref}
      data-slot="drawer-footer"
      className={cn(
        "flex items-center justify-end gap-2 px-6 py-4 border-t border_secondary mt-auto",
        className
      )}
      {...props}
    />
  )
)

DrawerTrigger.displayName = Dialog.Trigger.displayName
DrawerClose.displayName = Dialog.Close.displayName
DrawerOverlay.displayName = Dialog.Overlay.displayName
DrawerContent.displayName = Dialog.Content.displayName
DrawerHeader.displayName = "DrawerHeader"
DrawerTitle.displayName = Dialog.Title.displayName
DrawerDescription.displayName = Dialog.Description.displayName
DrawerBody.displayName = "DrawerBody"
DrawerFooter.displayName = "DrawerFooter"

export {
  Drawer,
  DrawerTrigger,
  DrawerClose,
  DrawerPortal,
  DrawerOverlay,
  DrawerContent,
  DrawerHeader,
  DrawerTitle,
  DrawerDescription,
  DrawerBody,
  DrawerFooter,
}
