import * as React from "react"
import {
  type ColumnDef,
  type ColumnFiltersState,
  type ExpandedState,
  type PaginationState,
  type Row,
  type RowSelectionState,
  type SortingState,
  type Updater,
  type VisibilityState,
  flexRender,
  functionalUpdate,
  getCoreRowModel,
  getExpandedRowModel,
  getFilteredRowModel,
  getPaginationRowModel,
  getSortedRowModel,
  useReactTable,
} from "@tanstack/react-table"
import { useVirtualizer } from "@tanstack/react-virtual"
import { ChevronRight } from "lucide-react"

import { cn } from "@/lib/internal"
import { Checkbox } from "./checkbox"
import { Pagination } from "./pagination"
import { radioGroupItemVariants } from "./radio-group-variants"
import { Skeleton } from "./skeleton"
import {
  dataTableCellVariants,
  dataTableHeadVariants,
  dataTableHeaderCellVariants,
  dataTablePaginationWrapperVariants,
  dataTableRowVariants,
  dataTableScrollContainerVariants,
  dataTableSummaryCellVariants,
  dataTableVariants,
  dataTableWrapperVariants,
} from "./data-table-variants"
import type { DataTableColumnMeta, DataTableProps } from "./data-table-types"
import {
  buildRowLookup,
  collectColumnPinning,
  getPinnedState,
  hasResizableColumn,
  resolveRowId,
  toCssSize,
  toExpandedKeys,
  toExpandedState,
  toRowSelectionState,
  toSortValue,
  toTanStackColumns,
} from "./data-table-utils"

function DataTable<T extends object>(props: DataTableProps<T>) {
  const {
    data,
    columns,
    getRowKey,
    loading = false,
    emptyMessage = "No data",
    bordered = false,
    striped = false,
    size = "default",
    stickyHeader = false,
    scroll,
    className,
    defaultSort,
    sort,
    onSortChange,
    multiSort = false,
    onMultiSortChange,
    onFilterChange,
    rowSelection,
    expandable,
    getSubRows,
    defaultExpanded = false,
    defaultExpandedRowIds,
    pagination,
    columnVisibility,
    onColumnVisibilityChange,
    summary,
    onRow,
    virtual = false,
  } = props

  const selectionType = rowSelection?.type ?? "checkbox"
  const hasTreeData = !!getSubRows
  const hasCustomExpandedRows = !!expandable?.expandedRowRender && !hasTreeData
  const hasPagination = pagination !== false && pagination !== undefined
  const paginationPosition = hasPagination ? (pagination.position ?? "bottom") : "bottom"
  const scrollContainerRef = React.useRef<HTMLDivElement>(null)

  const [internalSorting, setInternalSorting] = React.useState<SortingState>(() => {
    if (!defaultSort) {
      return []
    }

    return [
      {
        id: defaultSort.key,
        desc: defaultSort.direction === "desc",
      },
    ]
  })
  const [columnFilters, setColumnFilters] = React.useState<ColumnFiltersState>([])
  const [internalRowSelection, setInternalRowSelection] = React.useState<RowSelectionState>(() =>
    toRowSelectionState(rowSelection?.defaultSelectedRowKeys)
  )
  const [internalExpanded, setInternalExpanded] = React.useState<ExpandedState>(() => {
    if (defaultExpanded) {
      return true
    }

    const expandedKeys = new Set<string>()

    if (defaultExpandedRowIds?.length) {
      for (const rowId of defaultExpandedRowIds) {
        expandedKeys.add(rowId)
      }
    }

    if (expandable?.defaultExpandedRowKeys?.length) {
      for (const rowId of expandable.defaultExpandedRowKeys) {
        expandedKeys.add(rowId)
      }
    }

    if (expandedKeys.size > 0) {
      return Object.fromEntries(Array.from(expandedKeys).map((rowId) => [rowId, true]))
    }

    return {}
  })
  const [internalColumnVisibility, setInternalColumnVisibility] = React.useState<VisibilityState>(
    () => columnVisibility ?? {}
  )

  const isSortControlled = sort !== undefined
  const isRowSelectionControlled = rowSelection?.selectedRowKeys !== undefined
  const isExpandedControlled = expandable?.expandedRowKeys !== undefined
  const isColumnVisibilityControlled = columnVisibility !== undefined

  const sorting = React.useMemo<SortingState>(() => {
    if (!isSortControlled) {
      return internalSorting
    }

    if (!sort) {
      return []
    }

    return [
      {
        id: sort.key,
        desc: sort.direction === "desc",
      },
    ]
  }, [internalSorting, isSortControlled, sort])

  const rowSelectionState = React.useMemo<RowSelectionState>(() => {
    if (!isRowSelectionControlled) {
      return internalRowSelection
    }

    return toRowSelectionState(rowSelection?.selectedRowKeys)
  }, [internalRowSelection, isRowSelectionControlled, rowSelection?.selectedRowKeys])

  const expandedState = React.useMemo<ExpandedState>(() => {
    if (!isExpandedControlled) {
      return internalExpanded
    }

    return toExpandedState(expandable?.expandedRowKeys)
  }, [expandable?.expandedRowKeys, internalExpanded, isExpandedControlled])

  const columnVisibilityState = React.useMemo<VisibilityState>(() => {
    if (!isColumnVisibilityControlled) {
      return internalColumnVisibility
    }

    return columnVisibility ?? {}
  }, [columnVisibility, internalColumnVisibility, isColumnVisibilityControlled])

  const rowLookup = React.useMemo(
    () => buildRowLookup(data, getRowKey, getSubRows),
    [data, getRowKey, getSubRows]
  )
  const allRowIds = React.useMemo(() => Array.from(rowLookup.keys()), [rowLookup])

  const baseColumns = React.useMemo(() => toTanStackColumns(columns), [columns])
  const columnPinning = React.useMemo(() => collectColumnPinning(columns), [columns])
  const selectionColumn = React.useMemo<ColumnDef<T> | null>(() => {
    if (!rowSelection) {
      return null
    }

    const selectionWidth = rowSelection.columnWidth ?? 48

    if (selectionType === "radio") {
      return {
        id: "__select",
        header: () => null,
        cell: ({ row }) => (
          <div className="flex items-center justify-center">
            <button
              type="button"
              role="radio"
              aria-checked={row.getIsSelected()}
              aria-label={`Select row ${row.id}`}
              disabled={!row.getCanSelect()}
              data-state={row.getIsSelected() ? "checked" : "unchecked"}
              className={cn(radioGroupItemVariants({ size: "sm" }), "cursor-pointer")}
              onClick={row.getCanSelect() ? () => row.toggleSelected(true) : undefined}
            />
          </div>
        ),
        size: selectionWidth,
        minSize: selectionWidth,
        maxSize: selectionWidth,
        enableSorting: false,
        enableColumnFilter: false,
        enableResizing: false,
        meta: {
          align: "center",
          width: selectionWidth,
          minWidth: selectionWidth,
          maxWidth: selectionWidth,
        } satisfies DataTableColumnMeta,
      }
    }

    return {
      id: "__select",
      header: ({ table }) => (
        <div className="flex items-center justify-center">
          <Checkbox
            size="sm"
            aria-label="Select all rows"
            checked={
              table.getIsAllRowsSelected()
                ? true
                : table.getIsSomeRowsSelected()
                  ? "indeterminate"
                  : false
            }
            onCheckedChange={(checked) => {
              table.toggleAllRowsSelected(checked === true)
            }}
          />
        </div>
      ),
      cell: ({ row }) => (
        <div className="flex items-center justify-center">
          <Checkbox
            size="sm"
            aria-label={`Select row ${row.id}`}
            checked={row.getIsSelected()}
            disabled={!row.getCanSelect()}
            onCheckedChange={(checked) => {
              row.toggleSelected(checked === true)
            }}
          />
        </div>
      ),
      size: selectionWidth,
      minSize: selectionWidth,
      maxSize: selectionWidth,
      enableSorting: false,
      enableColumnFilter: false,
      enableResizing: false,
      meta: {
        align: "center",
        width: selectionWidth,
        minWidth: selectionWidth,
        maxWidth: selectionWidth,
      } satisfies DataTableColumnMeta,
    }
  }, [rowSelection, selectionType])

  const expandColumn = React.useMemo<ColumnDef<T> | null>(() => {
    if (!hasCustomExpandedRows) {
      return null
    }

    const expandWidth = expandable?.expandColumnWidth ?? 48

    return {
      id: "__expand",
      header: () => null,
      cell: ({ row }) => {
        if (!row.getCanExpand()) {
          return null
        }

        return (
          <div className="flex items-center justify-center">
            <button
              type="button"
              className="inline-flex h-6 w-6 cursor-pointer items-center justify-center rounded-sm hover:bg_secondary"
              aria-label={row.getIsExpanded() ? "Collapse row" : "Expand row"}
              onClick={row.getToggleExpandedHandler()}
            >
              <ChevronRight
                className={cn(
                  "h-3.5 w-3.5 icon_tertiary transition-transform duration-150",
                  row.getIsExpanded() && "rotate-90"
                )}
              />
            </button>
          </div>
        )
      },
      size: expandWidth,
      minSize: expandWidth,
      maxSize: expandWidth,
      enableSorting: false,
      enableColumnFilter: false,
      enableResizing: false,
      meta: {
        align: "center",
        width: expandWidth,
        minWidth: expandWidth,
        maxWidth: expandWidth,
      } satisfies DataTableColumnMeta,
    }
  }, [expandable?.expandColumnWidth, hasCustomExpandedRows])

  const tableColumns = React.useMemo(() => {
    const nextColumns = [...baseColumns]

    if (expandColumn) {
      nextColumns.unshift(expandColumn)
    }

    if (selectionColumn) {
      nextColumns.unshift(selectionColumn)
    }

    return nextColumns
  }, [baseColumns, expandColumn, selectionColumn])

  const filterMap = React.useMemo<Record<string, unknown>>(
    () => Object.fromEntries(columnFilters.map((filterItem) => [filterItem.id, filterItem.value])),
    [columnFilters]
  )

  const onFilterChangeRef = React.useRef(onFilterChange)
  React.useLayoutEffect(() => {
    onFilterChangeRef.current = onFilterChange
  })
  const didMountFilterEffectRef = React.useRef(false)

  const paginationState = React.useMemo<PaginationState | undefined>(() => {
    if (!hasPagination || !pagination) {
      return undefined
    }

    return {
      pageIndex: pagination.pageIndex,
      pageSize: pagination.pageSize,
    }
  }, [hasPagination, pagination])

  const useManualPagination = hasPagination && !!pagination && pagination.manual === true
  const canResize = React.useMemo(() => hasResizableColumn(columns), [columns])

  React.useEffect(() => {
    if (!didMountFilterEffectRef.current) {
      didMountFilterEffectRef.current = true
      return
    }

    onFilterChangeRef.current?.(filterMap)
  }, [filterMap])

  const handleSortingChange = React.useCallback(
    (updater: Updater<SortingState>) => {
      const nextSorting = functionalUpdate(updater, sorting)
      const normalizedSorting = multiSort
        ? nextSorting
        : nextSorting.length > 0
          ? [nextSorting[0]!]
          : []

      if (!isSortControlled) {
        setInternalSorting(normalizedSorting)
      }

      onSortChange?.(toSortValue(normalizedSorting))
      onMultiSortChange?.(
        normalizedSorting.map((sortingItem) => ({
          key: sortingItem.id,
          direction: sortingItem.desc ? "desc" : "asc",
        }))
      )
    },
    [isSortControlled, multiSort, onMultiSortChange, onSortChange, sorting]
  )

  const handleRowSelectionChange = React.useCallback(
    (updater: Updater<RowSelectionState>) => {
      const nextRowSelection = functionalUpdate(updater, rowSelectionState)

      if (!isRowSelectionControlled) {
        setInternalRowSelection(nextRowSelection)
      }

      if (!rowSelection?.onChange) {
        return
      }

      const selectedKeys = Object.keys(nextRowSelection).filter((rowId) => nextRowSelection[rowId])
      const selectedRows = selectedKeys
        .map((rowId) => rowLookup.get(rowId))
        .filter((rowItem): rowItem is T => rowItem !== undefined)

      rowSelection.onChange(selectedKeys, selectedRows)
    },
    [isRowSelectionControlled, rowLookup, rowSelection, rowSelectionState]
  )
  const handleExpandedChange = React.useCallback(
    (updater: Updater<ExpandedState>) => {
      const nextExpanded = functionalUpdate(updater, expandedState)

      if (!isExpandedControlled) {
        setInternalExpanded(nextExpanded)
      }

      expandable?.onExpandedRowsChange?.(toExpandedKeys(nextExpanded, allRowIds))
    },
    [allRowIds, expandable, expandedState, isExpandedControlled]
  )

  const handlePaginationChange = React.useCallback(
    (updater: Updater<PaginationState>) => {
      if (!pagination || !paginationState) {
        return
      }

      const nextPagination = functionalUpdate(updater, paginationState)
      pagination.onChange(nextPagination.pageIndex, nextPagination.pageSize)
    },
    [pagination, paginationState]
  )

  const handleColumnVisibilityChange = React.useCallback(
    (updater: Updater<VisibilityState>) => {
      const nextVisibility = functionalUpdate(updater, columnVisibilityState)

      if (!isColumnVisibilityControlled) {
        setInternalColumnVisibility(nextVisibility)
      }

      onColumnVisibilityChange?.(nextVisibility)
    },
    [columnVisibilityState, isColumnVisibilityControlled, onColumnVisibilityChange]
  )

  const table = useReactTable({
    data,
    columns: tableColumns,
    state: {
      sorting,
      columnFilters,
      rowSelection: rowSelectionState,
      expanded: expandedState,
      columnPinning,
      pagination: paginationState,
      columnVisibility: columnVisibilityState,
    },
    onSortingChange: handleSortingChange,
    onColumnFiltersChange: setColumnFilters,
    onRowSelectionChange: rowSelection ? handleRowSelectionChange : undefined,
    onExpandedChange: hasCustomExpandedRows || hasTreeData ? handleExpandedChange : undefined,
    onPaginationChange: hasPagination ? handlePaginationChange : undefined,
    onColumnVisibilityChange: handleColumnVisibilityChange,
    enableSortingRemoval: true,
    enableMultiSort: multiSort,
    isMultiSortEvent: (event) => {
      if (!multiSort) {
        return false
      }

      if (!event || typeof event !== "object") {
        return false
      }

      return "shiftKey" in event && Boolean((event as { shiftKey?: boolean }).shiftKey)
    },
    enableColumnResizing: canResize,
    columnResizeMode: "onChange",
    enableRowSelection: rowSelection
      ? (row) => {
          const checkboxProps = rowSelection.getCheckboxProps?.(row.original)
          return checkboxProps?.disabled !== true
        }
      : false,
    enableMultiRowSelection: selectionType !== "radio",
    getRowCanExpand:
      hasCustomExpandedRows || hasTreeData
        ? (row: Row<T>) => {
            if (hasTreeData) {
              const subRows = getSubRows?.(row.original)
              return (subRows?.length ?? 0) > 0
            }

            if (expandable?.rowExpandable) {
              return expandable.rowExpandable(row.original)
            }

            return hasCustomExpandedRows
          }
        : undefined,
    getCoreRowModel: getCoreRowModel(),
    getFilteredRowModel: getFilteredRowModel(),
    getSortedRowModel: getSortedRowModel(),
    getExpandedRowModel: getExpandedRowModel(),
    getPaginationRowModel: hasPagination ? getPaginationRowModel() : undefined,
    getSubRows: getSubRows ? (row) => getSubRows(row) : undefined,
    getRowId: (row, index, parent) => resolveRowId(row, index, parent?.id, getRowKey),
    manualPagination: useManualPagination,
    pageCount:
      hasPagination && pagination
        ? Math.max(1, Math.ceil(pagination.total / pagination.pageSize))
        : undefined,
  })

  const rows = table.getRowModel().rows
  const headerGroups = table.getHeaderGroups()
  const totalHeaderRows = headerGroups.length
  const visibleLeafCount = table.getVisibleLeafColumns().length
  const useVirtualRows = virtual && scroll?.y !== undefined && !hasCustomExpandedRows
  const rowVirtualizer = useVirtualizer({
    count: rows.length,
    getScrollElement: () => scrollContainerRef.current,
    estimateSize: () => (size === "compact" ? 36 : 48),
    overscan: 5,
    enabled: useVirtualRows,
  })
  const virtualItems = useVirtualRows ? rowVirtualizer.getVirtualItems() : []
  const paddingTop = useVirtualRows && virtualItems.length > 0 ? virtualItems[0]!.start : 0
  const paddingBottom =
    useVirtualRows && virtualItems.length > 0
      ? rowVirtualizer.getTotalSize() - virtualItems[virtualItems.length - 1]!.end
      : 0

  let summaryContent: React.ReactNode = null
  try {
    summaryContent = summary?.(data)
  } catch (error) {
    if (import.meta.env.DEV) {
      console.warn("[ui-kit/DataTable] Summary rendering failed.", error)
    }
    // Prevent summary errors from crashing the entire table
  }

  const scrollContainerStyle: React.CSSProperties = {}
  const tableStyle: React.CSSProperties = {}

  if (scroll?.x !== undefined) {
    tableStyle.minWidth = toCssSize(scroll.x)
  }

  if (scroll?.y !== undefined) {
    scrollContainerStyle.maxHeight = toCssSize(scroll.y)
    scrollContainerStyle.overflowY = "auto"
  }

  const renderPagination = (position: "top" | "bottom") => {
    if (!hasPagination || !pagination) {
      return null
    }

    if (!(paginationPosition === position || paginationPosition === "both")) {
      return null
    }

    return (
      <div
        data-slot="data-table-pagination"
        className={cn(dataTablePaginationWrapperVariants({ position }))}
      >
        <Pagination
          total={pagination.total}
          pageSize={pagination.pageSize}
          pageIndex={pagination.pageIndex}
          onPageChange={(nextPage) => {
            pagination.onChange(nextPage, pagination.pageSize)
          }}
          onPageSizeChange={(nextPageSize) => {
            pagination.onChange(0, nextPageSize)
          }}
          pageSizeOptions={pagination.pageSizeOptions}
          showSizeSelector={pagination.showSizeSelector}
          showTotal={pagination.showTotal}
        />
      </div>
    )
  }

  const renderDataRow = (row: Row<T>, index: number) => {
    const rowProps = onRow?.(row.original)
    const rowIsStriped = striped && index % 2 === 1

    return (
      <React.Fragment key={row.id}>
        <tr
          data-slot="data-table-row"
          className={cn(
            dataTableRowVariants({
              striped: rowIsStriped,
              selected: row.getIsSelected(),
            }),
            rowProps?.onClick && "cursor-pointer"
          )}
          {...rowProps}
        >
          {row.getVisibleCells().map((cell) => {
            const pinned = getPinnedState(cell.column.getIsPinned())
            const meta = (cell.column.columnDef.meta as DataTableColumnMeta | undefined) ?? {}
            const cellSize = cell.column.getSize()

            const cellStyle: React.CSSProperties = {
              width: cellSize,
              minWidth: cellSize,
            }

            if (pinned === "left") {
              cellStyle.position = "sticky"
              cellStyle.left = cell.column.getStart("left")
              cellStyle.zIndex = 2
            }

            if (pinned === "right") {
              cellStyle.position = "sticky"
              cellStyle.right = cell.column.getAfter("right")
              cellStyle.zIndex = 2
            }

            const pinnedBackground = pinned
              ? row.getIsSelected()
                ? "bg_accent_primary/10"
                : rowIsStriped
                  ? "bg_canvas_primary"
                  : "bg_primary"
              : ""

            return (
              <td
                key={cell.id}
                data-slot="data-table-cell"
                className={cn(
                  dataTableCellVariants({
                    size,
                    bordered,
                    align: meta.align ?? "left",
                    pinned,
                  }),
                  pinnedBackground,
                  meta.groupBorder && "border-r border_secondary"
                )}
                style={cellStyle}
              >
                {flexRender(cell.column.columnDef.cell, cell.getContext())}
              </td>
            )
          })}
        </tr>

        {hasCustomExpandedRows && row.getIsExpanded() && expandable?.expandedRowRender ? (
          <tr data-slot="data-table-row" className={cn(dataTableRowVariants())}>
            <td
              data-slot="data-table-cell"
              colSpan={visibleLeafCount || 1}
              className={cn(dataTableCellVariants({ size, bordered }))}
            >
              {expandable.expandedRowRender(row.original, row.depth)}
            </td>
          </tr>
        ) : null}
      </React.Fragment>
    )
  }

  return (
    <div data-slot="data-table" className={cn(dataTableWrapperVariants({ bordered }), className)}>
      {renderPagination("top")}

      <div
        ref={scrollContainerRef}
        data-slot="data-table-scroll-container"
        className={cn(dataTableScrollContainerVariants())}
        style={scrollContainerStyle}
      >
        <table className={cn(dataTableVariants())} style={tableStyle}>
          <thead className={cn(dataTableHeadVariants({ sticky: stickyHeader }))}>
            {headerGroups.map((headerGroup) => (
              <tr key={headerGroup.id}>
                {headerGroup.headers.map((header) => {
                  if (header.isPlaceholder) {
                    return null
                  }

                  const isGroupHeader = header.subHeaders.length > 0
                  const rowSpan = isGroupHeader
                    ? undefined
                    : Math.max(totalHeaderRows - header.depth, 1)
                  const pinned = getPinnedState(header.column.getIsPinned())
                  const meta =
                    (header.column.columnDef.meta as DataTableColumnMeta | undefined) ?? {}
                  const headerSize = header.getSize()

                  const headerStyle: React.CSSProperties = {
                    width: headerSize,
                    minWidth: headerSize,
                  }

                  if (pinned === "left") {
                    headerStyle.position = "sticky"
                    headerStyle.left = header.column.getStart("left")
                    headerStyle.zIndex = stickyHeader ? 5 : 3
                  }

                  if (pinned === "right") {
                    headerStyle.position = "sticky"
                    headerStyle.right = header.column.getAfter("right")
                    headerStyle.zIndex = stickyHeader ? 5 : 3
                  }

                  return (
                    <th
                      key={header.id}
                      data-slot="data-table-header-cell"
                      colSpan={header.colSpan > 1 ? header.colSpan : undefined}
                      rowSpan={rowSpan && rowSpan > 1 ? rowSpan : undefined}
                      className={cn(
                        dataTableHeaderCellVariants({
                          size,
                          bordered,
                          align: isGroupHeader ? "center" : (meta.align ?? "left"),
                          pinned,
                          resizable: header.column.getCanResize() && !isGroupHeader,
                        }),
                        isGroupHeader && "border-x border_secondary",
                        meta.groupBorder && "border-r border_secondary"
                      )}
                      style={headerStyle}
                    >
                      {flexRender(header.column.columnDef.header, header.getContext())}
                      {header.column.getCanResize() && !isGroupHeader ? (
                        <div
                          onMouseDown={header.getResizeHandler()}
                          onTouchStart={header.getResizeHandler()}
                          className={cn(
                            "absolute right-0 top-0 h-full w-1 cursor-col-resize select-none touch-none bg_accent_primary opacity-0 hover:opacity-100",
                            header.column.getIsResizing() && "opacity-100"
                          )}
                        />
                      ) : null}
                    </th>
                  )
                })}
              </tr>
            ))}
          </thead>

          <tbody>
            {loading ? (
              Array.from(
                { length: hasPagination && pagination ? pagination.pageSize : 5 },
                (_, i) => (
                  <tr
                    key={`skeleton-${i}`}
                    data-slot="data-table-row"
                    className={cn(dataTableRowVariants())}
                  >
                    {table.getVisibleLeafColumns().map((col) => {
                      const meta = (col.columnDef.meta as DataTableColumnMeta | undefined) ?? {}
                      return (
                        <td
                          key={col.id}
                          data-slot="data-table-cell"
                          className={cn(
                            dataTableCellVariants({ size, bordered, align: meta.align ?? "left" })
                          )}
                        >
                          <Skeleton className="h-4 w-full" />
                        </td>
                      )
                    })}
                  </tr>
                )
              )
            ) : rows.length === 0 ? (
              <tr data-slot="data-table-row" className={cn(dataTableRowVariants())}>
                <td
                  data-slot="data-table-empty"
                  colSpan={visibleLeafCount || 1}
                  className={cn(
                    dataTableCellVariants({ size, bordered }),
                    "text-center text_secondary"
                  )}
                >
                  {emptyMessage}
                </td>
              </tr>
            ) : useVirtualRows ? (
              <>
                {paddingTop > 0 ? (
                  <tr data-slot="data-table-row">
                    <td
                      data-slot="data-table-cell"
                      colSpan={visibleLeafCount || 1}
                      style={{ height: paddingTop }}
                      className="border-0 p-0"
                    />
                  </tr>
                ) : null}

                {virtualItems.map((virtualItem) =>
                  renderDataRow(rows[virtualItem.index]!, virtualItem.index)
                )}

                {paddingBottom > 0 ? (
                  <tr data-slot="data-table-row">
                    <td
                      data-slot="data-table-cell"
                      colSpan={visibleLeafCount || 1}
                      style={{ height: paddingBottom }}
                      className="border-0 p-0"
                    />
                  </tr>
                ) : null}
              </>
            ) : (
              rows.map((row, index) => renderDataRow(row, index))
            )}
          </tbody>

          {summaryContent ? (
            <tfoot data-slot="data-table-summary">
              {Array.isArray(summaryContent) ? (
                <tr data-slot="data-table-row">
                  {summaryContent.map((summaryCell, index) => (
                    <td
                      key={`summary-${index}`}
                      data-slot="data-table-cell"
                      className={cn(dataTableSummaryCellVariants({ size, bordered }))}
                    >
                      {summaryCell}
                    </td>
                  ))}
                </tr>
              ) : React.isValidElement(summaryContent) ? (
                summaryContent
              ) : (
                <tr data-slot="data-table-row">
                  <td
                    data-slot="data-table-cell"
                    colSpan={visibleLeafCount || 1}
                    className={cn(dataTableSummaryCellVariants({ size, bordered }))}
                  >
                    {summaryContent}
                  </td>
                </tr>
              )}
            </tfoot>
          ) : null}
        </table>
      </div>

      {renderPagination("bottom")}
    </div>
  )
}

export { DataTable }

export type {
  DataTableProps,
  DataTableColumnDef,
  DataTableCellMeta,
  DataTableRowSelectionConfig,
  DataTableExpandableConfig,
  DataTablePaginationConfig,
} from "./data-table-types"
