import * as React from "react"
import { type VariantProps } from "class-variance-authority"

import { cn } from "@/lib/internal"
import { notiBadgeVariants } from "./noti-badge-variants"

type NotiBadgeVariantProps = VariantProps<typeof notiBadgeVariants>

export interface NotiBadgeProps
  extends
    Omit<React.HTMLAttributes<HTMLSpanElement>, "color" | "children">,
    NotiBadgeVariantProps {
  count?: number
  max?: number
  overflowLabel?: React.ReactNode
  children?: React.ReactNode
}

const formatCount = (
  count: number | undefined,
  max: number,
  overflowLabel: React.ReactNode | undefined
) => {
  if (count === undefined) return undefined
  if (count > max) return overflowLabel ?? `${max}+`
  return count
}

const NotiBadge = React.forwardRef<HTMLSpanElement, NotiBadgeProps>(
  (
    {
      className,
      size = "l",
      color = "red",
      count,
      max = 99,
      overflowLabel,
      children,
      ...props
    },
    ref
  ) => {
    const content = size === "s" ? null : children ?? formatCount(count, max, overflowLabel)

    return (
      <span
        ref={ref}
        data-slot="noti-badge"
        data-size={size}
        data-color={color}
        className={cn(notiBadgeVariants({ size, color }), className)}
        {...props}
      >
        {content}
      </span>
    )
  }
)

NotiBadge.displayName = "NotiBadge"

export { NotiBadge }
