import * as React from "react"
import { ChevronRight } from "lucide-react"
import { Popover as PopoverPrimitive } from "radix-ui"

import { cn } from "@/lib/internal"

interface BreadcrumbItem {
  label: string
  href?: string
  icon?: React.ReactNode
}

interface BreadcrumbProps {
  items: BreadcrumbItem[]
  separator?: React.ReactNode
  className?: string
  maxItems?: number
}

type RenderBreadcrumbItem = BreadcrumbItem & { _ellipsis?: boolean }

const defaultSeparator = <ChevronRight className="h-3.5 w-3.5" aria-hidden="true" />

const Breadcrumb = React.forwardRef<HTMLElement, BreadcrumbProps>(
  ({ items, separator = defaultSeparator, className, maxItems }, ref) => {
    const hiddenItems: BreadcrumbItem[] =
      maxItems !== undefined && items.length > maxItems ? items.slice(1, items.length - 1) : []

    const visibleItems: RenderBreadcrumbItem[] =
      maxItems !== undefined && items.length > maxItems
        ? [items[0], { label: "...", _ellipsis: true }, items[items.length - 1]]
        : items

    return (
      <nav ref={ref} data-slot="breadcrumb" aria-label="Breadcrumb" className={className}>
        <ol className={cn("flex flex-wrap items-center gap-1")}>
          {visibleItems.map((item, index) => {
            const isLast = index === visibleItems.length - 1
            const key = `${item.label}-${index}`
            const isEllipsis = !!item._ellipsis

            return (
              <li key={key} className="inline-flex items-center">
                {isEllipsis ? (
                  <PopoverPrimitive.Root>
                    <PopoverPrimitive.Trigger asChild>
                      <button
                        type="button"
                        className="inline-flex items-center px-1 py-0.5 text-sm icon_tertiary hover:state_fg_tertiary_neutral_max radius_4 transition-colors cursor-pointer"
                        aria-label="Show hidden items"
                      >
                        ...
                      </button>
                    </PopoverPrimitive.Trigger>
                    <PopoverPrimitive.Portal>
                      <PopoverPrimitive.Content
                        side="bottom"
                        align="start"
                        sideOffset={6}
                        className="z-50 min-w-36 bg_primary border border_secondary radius_8 shadow_l p-1"
                      >
                        {hiddenItems.map((hiddenItem, hiddenIndex) =>
                          hiddenItem.href ? (
                            <a
                              key={`${hiddenItem.label}-${hiddenIndex}`}
                              href={hiddenItem.href}
                              className="flex items-center gap-2 px-3 py-1.5 text-sm text_tertiary hover:state_fg_tertiary_neutral_max radius_6 transition-colors cursor-pointer"
                            >
                              {hiddenItem.icon}
                              {hiddenItem.label}
                            </a>
                          ) : (
                            <span
                              key={`${hiddenItem.label}-${hiddenIndex}`}
                              className="flex items-center gap-2 px-3 py-1.5 text-sm text_tertiary radius_6"
                            >
                              {hiddenItem.icon}
                              {hiddenItem.label}
                            </span>
                          )
                        )}
                      </PopoverPrimitive.Content>
                    </PopoverPrimitive.Portal>
                  </PopoverPrimitive.Root>
                ) : isLast || !item.href ? (
                  <span
                    aria-current={isLast ? "page" : undefined}
                    className={cn(
                      "inline-flex items-center gap-1",
                      isLast ? "font-normal text_primary" : "text_tertiary"
                    )}
                  >
                    {item.icon}
                    {item.label}
                  </span>
                ) : (
                  <a
                    href={item.href}
                    className="inline-flex items-center gap-1 px-1 py-0.5 text_tertiary transition-colors hover:state_fg_tertiary_neutral_max radius_4"
                  >
                    {item.icon}
                    {item.label}
                  </a>
                )}
                {!isLast ? (
                  <span className="mx-1 inline-flex items-center icon_tertiary" aria-hidden="true">
                    {separator}
                  </span>
                ) : null}
              </li>
            )
          })}
        </ol>
      </nav>
    )
  }
)

Breadcrumb.displayName = "Breadcrumb"

export { Breadcrumb }
export type { BreadcrumbItem, BreadcrumbProps }
