import { Toaster as SonnerToaster } from "sonner"

import { cn } from "@/lib/internal"

export interface ToasterProps {
  position?:
    | "top-left"
    | "top-center"
    | "top-right"
    | "bottom-left"
    | "bottom-center"
    | "bottom-right"
  expand?: boolean
  richColors?: boolean
  closeButton?: boolean
  duration?: number
  className?: string
}

/**
 * Toast provider for applications using ui-kit.
 *
 * Usage:
 * 1) In app root: `<Toaster />`
 * 2) Anywhere: `toast.success("Saved!")`, `toast.error("Failed!")`, `toast("Hello")`
 */
export function Toaster({
  position = "top-right",
  expand,
  richColors = true,
  closeButton = true,
  duration = 4000,
  className,
}: ToasterProps) {
  return (
    <SonnerToaster
      position={position}
      expand={expand}
      richColors={richColors}
      closeButton={closeButton}
      duration={duration}
      className={className}
      toastOptions={{
        classNames: {
          toast: cn("bg_primary border_secondary shadow_m radius_8"),
          title: "text_primary",
          description: "text_secondary",
          closeButton: "bg_secondary border_secondary",
        },
      }}
    />
  )
}
