import { clsx, type ClassValue } from "clsx"
import { extendTailwindMerge } from "tailwind-merge"

const isTokenBackgroundColor = (className: string) => className.startsWith("bg_")
const isTokenBorderColor = (className: string) => className.startsWith("border_")
const isTokenTextColor = (className: string) =>
  className.startsWith("text_") || className.startsWith("fg_") || className.startsWith("icon_")

const twMerge = extendTailwindMerge({
  extend: {
    classGroups: {
      "bg-color": [isTokenBackgroundColor],
      "border-color": [isTokenBorderColor],
      "text-color": [isTokenTextColor],
    },
  },
})

export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs))
}
