import * as React from "react"
import { Switch as SwitchPrimitive } from "radix-ui"

import { cn } from "@/lib/internal"
import { switchThumbVariants, switchVariants } from "./switch-variants"

export interface SwitchProps extends Omit<
  React.ComponentPropsWithoutRef<typeof SwitchPrimitive.Root>,
  "asChild"
> {
  label?: string
  description?: string
  size?: "sm" | "md" | "lg"
  labelPosition?: "left" | "right"
}

const Switch = React.forwardRef<React.ElementRef<typeof SwitchPrimitive.Root>, SwitchProps>(
  ({ label, description, size = "md", labelPosition = "right", className, id, ...props }, ref) => {
    const generatedId = React.useId()
    const innerId = id ?? generatedId

    return (
      <div
        data-slot="switch-wrapper"
        data-label-position={labelPosition}
        className={cn(
          "flex items-center gap-2",
          labelPosition === "left" && "flex-row-reverse justify-end",
          className
        )}
      >
        <SwitchPrimitive.Root
          ref={ref}
          id={innerId}
          data-slot="switch"
          data-size={size}
          className={cn(switchVariants({ size }))}
          {...props}
        >
          <SwitchPrimitive.Thumb
            data-slot="switch-thumb"
            className={cn(switchThumbVariants({ size }))}
          />
        </SwitchPrimitive.Root>
        {(label || description) && (
          <div className="flex flex-col">
            {label && (
              <label htmlFor={innerId} className="cursor-pointer text_primary text-sm">
                {label}
              </label>
            )}
            {description && <span className="text_tertiary text-sm">{description}</span>}
          </div>
        )}
      </div>
    )
  }
)

Switch.displayName = "Switch"

export { Switch }
