import * as React from "react"

import { cn } from "@/lib/internal"
import {
  segmentedControlItemVariants,
  segmentedControlVariants,
} from "./segmented-control-variants"

export interface SegmentedControlOption {
  value: string
  label: React.ReactNode
  icon?: React.ReactNode
  disabled?: boolean
}

export interface SegmentedControlProps {
  options: readonly SegmentedControlOption[]
  value?: string
  defaultValue?: string
  onValueChange?: (value: string) => void
  size?: "xs" | "s" | "m" | "l"
  disabled?: boolean
  className?: string
}

const getInitialValue = (options: readonly SegmentedControlOption[], defaultValue?: string) => {
  if (defaultValue !== undefined) return defaultValue
  return options.find((option) => !option.disabled)?.value
}

const SegmentedControl = React.forwardRef<HTMLDivElement, SegmentedControlProps>(
  (
    { options, value, defaultValue, onValueChange, size = "m", disabled = false, className },
    ref
  ) => {
    const isControlled = value !== undefined
    const [internalValue, setInternalValue] = React.useState<string | undefined>(() =>
      getInitialValue(options, defaultValue)
    )

    const selectedValue = isControlled ? value : internalValue

    const handleChange = React.useCallback(
      (nextValue: string) => {
        if (!isControlled) {
          setInternalValue(nextValue)
        }
        onValueChange?.(nextValue)
      },
      [isControlled, onValueChange]
    )

    return (
      <div
        ref={ref}
        data-slot="segmented-control"
        role="radiogroup"
        aria-disabled={disabled || undefined}
        className={cn(segmentedControlVariants(), className)}
      >
        {options.map((option) => {
          const isActive = option.value === selectedValue
          const isOptionDisabled = disabled || !!option.disabled

          return (
            <button
              key={option.value}
              type="button"
              data-slot="segmented-control-item"
              role="radio"
              aria-checked={isActive}
              aria-disabled={isOptionDisabled || undefined}
              disabled={isOptionDisabled}
              onClick={() => {
                if (isOptionDisabled || isActive) return
                handleChange(option.value)
              }}
              className={cn(
                segmentedControlItemVariants({
                  size,
                  active: isActive,
                  disabled: isOptionDisabled,
                })
              )}
            >
              {option.icon}
              {option.label}
            </button>
          )
        })}
      </div>
    )
  }
)

SegmentedControl.displayName = "SegmentedControl"

export { SegmentedControl }
