import * as React from "react"
import { type VariantProps } from "class-variance-authority"

import { cn } from "@/lib/internal"
import { badgeVariants } from "./badge-variants"

type BadgeVariantProps = VariantProps<typeof badgeVariants>
type BadgeSize = NonNullable<BadgeVariantProps["size"]>
type BadgeColor = NonNullable<BadgeVariantProps["color"]>
type LegacyBadgeSize = "sm" | "md" | "lg"

const normalizeBadgeSize = (size?: BadgeSize | LegacyBadgeSize): BadgeSize | undefined => {
  if (!size) return undefined
  if (size === "sm") return "s"
  if (size === "md") return "m"
  if (size === "lg") return "l"
  return size
}

const normalizeBadgeColor = (color?: BadgeColor | null): BadgeColor | undefined => {
  if (!color) return undefined
  return color === "white" ? "light" : color
}

export interface BadgeProps
  extends
    Omit<React.HTMLAttributes<HTMLSpanElement>, "color">,
    Omit<BadgeVariantProps, "size" | "rounded"> {
  size?: BadgeSize | LegacyBadgeSize
  rounded?: boolean
  dot?: boolean
  iconLeft?: React.ReactNode
  iconRight?: React.ReactNode
}

const Badge = React.forwardRef<HTMLSpanElement, BadgeProps>(
  (
    {
      className,
      variant,
      size,
      color,
      bordered,
      rounded,
      dot,
      iconLeft,
      iconRight,
      children,
      ...props
    },
    ref
  ) => {
    const normalizedSize = normalizeBadgeSize(size)
    const normalizedColor = normalizeBadgeColor(color)
    const iconClassName =
      "inline-flex h-3 w-3 shrink-0 items-center justify-center text-current [&_svg:not([class*='size-'])]:h-3 [&_svg:not([class*='size-'])]:w-3"

    React.useEffect(() => {
      if (import.meta.env.DEV && color === "white") {
        console.warn('[ui-kit/Badge] color="white" is deprecated. Use color="light" instead.')
      }
    }, [color])

    return (
      <span
        ref={ref}
        data-slot="badge"
        data-variant={variant}
        data-size={normalizedSize}
        className={cn(
          badgeVariants({ variant, size: normalizedSize, color: normalizedColor, bordered, rounded }),
          className
        )}
        {...props}
      >
        {dot && <span className="h-1.5 w-1.5 radius_round bg-current flex-shrink-0" aria-hidden />}
        {iconLeft ? <span className={iconClassName}>{iconLeft}</span> : null}
        {children}
        {iconRight ? <span className={iconClassName}>{iconRight}</span> : null}
      </span>
    )
  }
)

Badge.displayName = "Badge"

export { Badge }
