import * as React from "react"
import { type VariantProps } from "class-variance-authority"

import { cn } from "@/lib/internal"
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuTrigger,
} from "./dropdown-menu"
import { iconToggleVariants } from "./icon-toggle-variants"

type IconDropdownVariantProps = VariantProps<typeof iconToggleVariants>

export interface IconDropdownProps
  extends Omit<React.ComponentPropsWithoutRef<typeof DropdownMenu>, "children">,
    Omit<IconDropdownVariantProps, "active"> {
  icon: React.ReactNode
  children: React.ReactNode
  active?: boolean
  disabled?: boolean
  className?: string
  contentClassName?: string
  side?: "top" | "right" | "bottom" | "left"
  align?: "start" | "center" | "end"
  sideOffset?: number
  "aria-label": string
}

const IconDropdown = React.forwardRef<HTMLButtonElement, IconDropdownProps>(
  (
    {
      icon,
      children,
      variant = "dim",
      size = "m",
      active: activeProp,
      disabled,
      className,
      contentClassName,
      side,
      align,
      sideOffset,
      open: openProp,
      onOpenChange,
      "aria-label": ariaLabel,
      ...props
    },
    ref
  ) => {
    const [uncontrolledOpen, setUncontrolledOpen] = React.useState(false)
    const open = openProp ?? uncontrolledOpen
    const active = activeProp ?? open

    const handleOpenChange = React.useCallback(
      (nextOpen: boolean) => {
        setUncontrolledOpen(nextOpen)
        onOpenChange?.(nextOpen)
      },
      [onOpenChange]
    )

    return (
      <DropdownMenu open={open} onOpenChange={handleOpenChange} {...props}>
        <DropdownMenuTrigger asChild disabled={disabled}>
          <button
            ref={ref}
            type="button"
            data-slot="icon-dropdown"
            data-variant={variant}
            data-size={size}
            data-active={active || undefined}
            disabled={disabled}
            aria-label={ariaLabel}
            className={cn(
              iconToggleVariants({ variant, size, active }),
              disabled && variant === "dim" && "bg_button_tertiary",
              className
            )}
          >
            {icon}
          </button>
        </DropdownMenuTrigger>
        <DropdownMenuContent
          side={side}
          align={align}
          sideOffset={sideOffset}
          className={contentClassName}
        >
          {children}
        </DropdownMenuContent>
      </DropdownMenu>
    )
  }
)

IconDropdown.displayName = "IconDropdown"

export { IconDropdown }
